import { Logger } from "../../logger";
import { LoadTestUserInput, TestType } from "./model";
import * as vscode from "vscode";
import { LoadTestInputType, LoadTestInputArtifacts } from "./model";
import { HTTPLoadTestInputHandler } from "../LoadTestUserInput/http";
import { PostmanLoadTestInputHandler } from "../LoadTestUserInput/postman";
import { URLEndpointLoadTestInputHandler } from "../LoadTestUserInput/url";
import { HTTPInputArtifacts, InsomniaInputArtifacts, PostmanInputArtifacts, URLEndpointInputArtifacts } from "./model";
import { InsomniaLoadTestInputHandler } from "../LoadTestUserInput/insomnia";
import { SampleHTTPLoadTestInputHandler } from "../LoadTestUserInput/httpSample";
import { ErrorMessages, Messages } from "../../strings";
import { ErrorUtil } from "../../Utils/errorUtil";
import { formatString } from "../../util";
import { validateInputFile } from "../../ChatParticipant/AzureLoadTesting/util";
import { ALTContext } from "../../ChatParticipant/AzureLoadTesting/Context";
import { TestScriptHelper } from "./testScript";
import { getRootPath } from "../VsCodeAPI";
import { EditorUtil } from "../../Utils/editorUtil";
import { updateEnvFile, updateRequirementsFile } from "../../Utils/fileUtil";
import { AzureLoadTesting, ChatParticipant, VSCodeCommand } from "../../constants";
import * as path from "path";

export class GenerateLoadTestService {
    
    private _logger: Logger;

    constructor() {
        this._logger = new Logger("GenerateLoadTestService");
    }

    async selectLoadTestInputType(copilotEnabled:boolean=true) : Promise<LoadTestUserInput | null> {

        let testType: TestType = TestType.Locust;
        
        // ask user for test type if not selected
        let testTypeSelection = await vscode.window.showQuickPick(
            [
                { label: vscode.l10n.t(Messages.Locust), value: TestType.Locust},
                { label: vscode.l10n.t(Messages.JMeter), value: TestType.JMeter}
            ],
            {
                placeHolder: vscode.l10n.t(Messages.SelectLoadTestType),
                ignoreFocusOut : true
            }
        );

        if(testTypeSelection){
            testType = testTypeSelection.value;
        }else{
            this._logger.debug(`User did not select test type, defaulting to Locust`);
        }

        // Default selection for input type as URI or Sample HTTP file in case of copilot not enabled or JMeter test type
        let options = [
            { label: vscode.l10n.t(Messages.URLEndpoint), value: LoadTestInputType.URLEndpoint , iconPath: new vscode.ThemeIcon('ports-open-browser-icon') },
            { label: vscode.l10n.t(Messages.PetStoreSample), value: LoadTestInputType.SampleHTTPFile, iconPath: new vscode.ThemeIcon('repo') },
        ]

        if(copilotEnabled && testType == TestType.Locust){
            options = [
                { label: vscode.l10n.t(Messages.URLEndpoint), value: LoadTestInputType.URLEndpoint , iconPath: new vscode.ThemeIcon('ports-open-browser-icon') },
                { label: vscode.l10n.t(Messages.PostmanCollection), value: LoadTestInputType.Postman, iconPath: new vscode.ThemeIcon('file') },
                { label: vscode.l10n.t(Messages.InsomniaCollection), value: LoadTestInputType.Insomnia, iconPath: new vscode.ThemeIcon('file') },
                { label: vscode.l10n.t(Messages.HTTPFile), value: LoadTestInputType.HTTP, iconPath: new vscode.ThemeIcon('file') },
                { label: vscode.l10n.t(Messages.PetStoreSample), value: LoadTestInputType.SampleHTTPFile, iconPath: new vscode.ThemeIcon('repo') },
            ]
        }
        
        const inputType = await vscode.window.showQuickPick(
            options,
            {
                placeHolder: vscode.l10n.t(Messages.SelectInputFile),
                ignoreFocusOut : true
            }
        );

        if (inputType) {
            this._logger.debug(`User selected input type is ${inputType.value}`);
            let artifacts : LoadTestInputArtifacts | null = await this.getArtifacts(inputType.value, testType);
            if (artifacts) {
                return {
                    type: inputType.value,
                    artifacts: artifacts,
                    testType:testType,
                    virtualUsers: AzureLoadTesting.DefaultVUs,
                    testDurationSeconds: AzureLoadTesting.DefaultDuration
                };
            }
        }else{
            ErrorUtil.showRequiredInputFileError();
            return null;
        }

        return null;
    }

    async getArtifacts<T extends LoadTestInputArtifacts>(inputType: LoadTestInputType, testType:TestType) : Promise<T | null> {
        let handler: { selectArtifact: <T extends LoadTestInputArtifacts>() => Promise<T | null> } | undefined;
        let artifacts: any = null;
        
        
        switch(inputType){
            case LoadTestInputType.Postman:
                handler = new PostmanLoadTestInputHandler(testType);
                artifacts = await handler.selectArtifact<PostmanInputArtifacts>();
                break;
            case LoadTestInputType.HTTP:
                handler = new HTTPLoadTestInputHandler(testType);
                artifacts = await handler.selectArtifact<HTTPInputArtifacts>();
                break;
            case LoadTestInputType.Insomnia:
                handler = new InsomniaLoadTestInputHandler(testType);
                artifacts = await handler.selectArtifact<InsomniaInputArtifacts>();
                break;
            case LoadTestInputType.URLEndpoint:
                handler = new URLEndpointLoadTestInputHandler(testType);
                artifacts = await handler.selectArtifact<URLEndpointInputArtifacts>();
                break;
            case LoadTestInputType.SampleHTTPFile:
                handler = new SampleHTTPLoadTestInputHandler(testType);
                artifacts = await handler.selectArtifact<HTTPInputArtifacts>();
                break;
        }

        if(handler == null){
            this._logger.error(`Invalid input type ${inputType}`, false);
            throw new Error(`Invalid input type ${inputType}`);
        }

        return artifacts as T | null;
    }
  

    async generateLoadTestScriptFromUserInput(userInput: LoadTestUserInput, request: vscode.ChatRequest, context: vscode.ChatContext, stream: vscode.ChatResponseStream, token: vscode.CancellationToken) {
        let inputFilePath = userInput.artifacts!.inputFilePath;

        let isVaildInputFile = validateInputFile(inputFilePath);

        if(!isVaildInputFile){
            stream.markdown(vscode.l10n.t(ErrorMessages.INVALID_INPUT_FILE));
            return false;
        }

        ALTContext.setLatestLoadTestInputFilePath(inputFilePath);

        stream.markdown(`${vscode.l10n.t(Messages.GeneratingLoadTestScript)} **${path.basename(inputFilePath)}**.\n\n`);
        
        const rootPath = getRootPath();
        
        let {script, envContent, packages} = await new TestScriptHelper().createScript(userInput, request.model);
        
        if (!script) {
            stream.markdown(vscode.l10n.t(ErrorMessages.UnableToGenerateLoadTestScript));
            return false;
        }

        stream.filetree([{
            name : path.basename(rootPath),
            children : [
                {
                    name : path.basename(script),
                    children : [],
                }
            ]
        }], vscode.workspace.workspaceFolders![0].uri)
        
        
        stream.markdown(`## ${vscode.l10n.t(Messages.AdditionalSteps)}\n\n`);

        if(envContent != ""){
            stream.markdown(`\n\nThe `);
            stream.anchor(vscode.Uri.joinPath(vscode.workspace.workspaceFolders![0].uri, '.env'), '.env');
            stream.markdown(` file has been updated with the following variables:\n`);
            stream.markdown(`\`\`\`bash\n${envContent}\n\`\`\`\n`);    
        }
        
        if(packages.length > 0){
            stream.markdown(`\n### ${formatString(Messages.RequirementTxtFileMarkdown, packages.join('\n'))}\n`);
            stream.markdown(`You can find the `);
            stream.anchor(vscode.Uri.joinPath(vscode.workspace.workspaceFolders![0].uri, 'requirements.txt'), 'requirements.txt');
            stream.markdown(` in the current workspace\n`);
        }

        stream.markdown(`## ${vscode.l10n.t(Messages.NextSteps)}\n\n`);

        stream.markdown(`\n\n### ${vscode.l10n.t(Messages.WantToTestLocally)}\n`);
        stream.button({
            title: vscode.l10n.t(Messages.RunTestLocally),
            command : VSCodeCommand.OPEN_CHAT,
            arguments : [
                `@${ChatParticipant.CHART_PARTICIPANT_ID} /${ChatParticipant.RUN_LOAD_TEST_LOCALLY}`
            ]
        });

        stream.markdown(`\n\n### **OR** \n`);

        stream.markdown(`\n\n### ${vscode.l10n.t(Messages.WantToRunAtScale)}\n`);
        stream.button({
            title: vscode.l10n.t(Messages.RunInAzure),
            command : VSCodeCommand.OPEN_CHAT,
            arguments : [
                `@${ChatParticipant.CHART_PARTICIPANT_ID} /${ChatParticipant.RUN_LOAD_TEST_IN_AZURE}`
            ]
        });

        return true;
    }

    async proceedLoadTestGenerationWithoutCopilot (userInput:LoadTestUserInput | null)  {
        if (userInput && userInput.artifacts) {
                        
            let inputFilePath = userInput.artifacts.inputFilePath;

            let isVaildInputFile = validateInputFile(inputFilePath);

            if(!isVaildInputFile){
                this._logger.error(ErrorMessages.INVALID_INPUT_FILE);
            }
    
            ALTContext.setLatestLoadTestInputFilePath(inputFilePath); 
            
            let scriptContent = userInput.artifacts.scriptContent;
            let requirements = userInput.artifacts.requirements;
            let envVars = userInput.artifacts.requiredEnvs;

            await vscode.window.withProgress({
                location: vscode.ProgressLocation.Notification,
                title: vscode.l10n.t(Messages.GeneratingTheLoadTestScript),
                cancellable: false,
            }, async (progress, token) => {
                
                // delay for few second 
                await new Promise(resolve => setTimeout(resolve, 1000));

                if(scriptContent){
                    let contents = scriptContent.split("\n");
                    // add \n for each line 
                    contents = contents.map(l => l + "\n");
                    let scriptFile = await EditorUtil.streamContentToEditorWithOverlay(contents, userInput.testType);

                    try{
                        if(scriptFile){
                            updateRequirementsFile(requirements!, vscode.Uri.joinPath(vscode.workspace.workspaceFolders![0].uri, 'requirements.txt').fsPath);
                            updateEnvFile(envVars, vscode.Uri.joinPath(vscode.workspace.workspaceFolders![0].uri, '.env').fsPath);

                            // show success message along with action for run in local and azure
                            vscode.window.showInformationMessage(
                                vscode.l10n.t(Messages.LoadTestScriptCreated, path.basename(scriptFile!)),
                                vscode.l10n.t(Messages.RunInAzure),
                                vscode.l10n.t(Messages.RunTestLocally)
                            ).then(async (command) => {
                                this._logger.debug(`User selected action : ${command}`);
                                if (command === vscode.l10n.t(Messages.RunTestLocally)) {
                                    vscode.commands.executeCommand(VSCodeCommand.RUN_LOAD_TEST_LOCALLY);
                                } else if (command === vscode.l10n.t(Messages.RunInAzure)) {
                                    vscode.commands.executeCommand(VSCodeCommand.RUN_LOAD_TEST_IN_AZURE);
                                } else {
                                    this._logger.debug("User cancelled the action");
                                }
                            });
                        }else{
                            this._logger.debug(`Unable to create script content`);
                        }
                    }catch(e){
                        this._logger.debug(`Error occurred while creating test script ${e}`);
                    }
                }else{
                    this._logger.error(ErrorMessages.UnableToGenerateLoadTestScript);
                    
                }
            });
            
        } else {
            this._logger.error(vscode.l10n.t(ErrorMessages.REQUIRED_INPUT_FILE_MARKDOWN));
        }
    }
}