import * as fs from 'fs';
import * as vscode from 'vscode';
import { ChatCommandHandler } from '../../handler';
import {  DefaultSystemPrompt, IncludeFileContentPrompt } from '../Prompts';
import { Links } from '../../../constants';

export class DefaultALTChatHandler extends ChatCommandHandler {

    async handle(request: vscode.ChatRequest, context: vscode.ChatContext, stream: vscode.ChatResponseStream, token: vscode.CancellationToken) {
        
        const activeEditor = vscode.window.activeTextEditor;
        let inputFile: string | undefined;
        if (activeEditor) {
            inputFile = activeEditor.document.fileName;
        }

        let prompt = request.prompt;
        if(!prompt ){
            let response = `**@testing** integrates with [Azure Load Testing](${Links.MALT}) to generate and run load tests using Copilot.\n\nTry these commands:\n\n
\`\`\`shell
# Generate a load test script
@testing /generateLoadTest

# Run a load test in Azure
@testing /runLoadTestInAzure

# Run a load test locally
@testing /runLoadTestLocally

# Validate your load test configuration
@testing /validateLoadTestConfig
\`\`\`\n\n
Need help getting started? Check out the [Quickstart Guide](${Links.QuickStartGuide}) for more information.
`;      
            stream.markdown(response);
            return true;
        }
        const messages = [
            vscode.LanguageModelChatMessage.Assistant(DefaultSystemPrompt),
            vscode.LanguageModelChatMessage.User(prompt)
        ];
        
        if (inputFile && fs.existsSync(inputFile)) {
            let fileContent = fs.readFileSync(inputFile, 'utf8');
            messages.push(vscode.LanguageModelChatMessage.User(IncludeFileContentPrompt(fileContent)))
        }  

        const chatResponse = await request.model.sendRequest(messages, {}, token);
        for await (const fragment of chatResponse.text) {
            stream.markdown(fragment);
        }

        return true;
    }
}