import { ViewLoadTestRuns } from '../Commands/viewtestruns';
import * as vscode from 'vscode';
import { RestAPI } from '../Services/AzureLoadTesting/api';
import { ISelectAzureLoadTestRunOptions } from './models';
import { Logger } from '../logger';
import { ErrorMessages, Messages } from '../strings';

export class SelectAzureLoadTestRun implements vscode.LanguageModelTool<ISelectAzureLoadTestRunOptions> {
    private logger: Logger;

    constructor() {
        this.logger = new Logger('SelectAzureLoadTestRun');
    }

    async invoke(
        options: vscode.LanguageModelToolInvocationOptions<ISelectAzureLoadTestRunOptions>,
        _token: vscode.CancellationToken
    ) {
        this.logger.debug(`SelectAzureLoadTestRun.invoke called`);
        let apiClient = new RestAPI();
        const resourceId = options.input.azure_load_testing_resourceId;
        if (!resourceId) {
            this.logger.debug('No azure_load_testing_resourceId provided');
            return new vscode.LanguageModelToolResult([
                new vscode.LanguageModelTextPart(ErrorMessages.AzureLoadTestingResourceIdRequired)
            ]);
        }
        if (!resourceId || !resourceId.startsWith('/subscriptions/')) {
            this.logger.debug('Invalid azure_load_testing_resourceId: ' + resourceId);
            return new vscode.LanguageModelToolResult([new vscode.LanguageModelTextPart(ErrorMessages.InvalidAzureLoadTestingResourceId)]);
        }
        let resource = await apiClient.getAzureResourceDetails(resourceId);
        if (!resource || !resource.id) {
            this.logger.debug('Invalid azure_load_testing_resourceId: ' + resourceId);
            return new vscode.LanguageModelToolResult([
                new vscode.LanguageModelTextPart(ErrorMessages.InvalidAzureLoadTestingResourceId)
            ]);
        }
        let viewTestRun = new ViewLoadTestRuns();
        let testRun = await viewTestRun.selectAzureLoadTestRun(`https://${resource.properties.dataPlaneURI}`);
        if (!testRun) {
            this.logger.debug(`No test run found for resource: ${resourceId}`);
            return new vscode.LanguageModelToolResult([new vscode.LanguageModelTextPart(ErrorMessages.NoTestRunFoundForResource)]);
        }else{
            this.logger.debug(`Found test run: ${testRun}`);
        }
        return new vscode.LanguageModelToolResult([
            new vscode.LanguageModelTextPart(`${Messages.SelectedTestRunName}: ${testRun.label}\n\n${Messages.SelectedTestRunId}: ${testRun.id}\n\n`),
        ]);
    }

    async prepareInvocation(
        options: vscode.LanguageModelToolInvocationPrepareOptions<ISelectAzureLoadTestRunOptions>,
        _token: vscode.CancellationToken
    ) {
        this.logger.debug(`SelectAzureLoadTestRun.prepareInvocation called`);
        const confirmationMessages = {
            title: Messages.SelectAzureLoadTestRunTitle,
            message: new vscode.MarkdownString(Messages.SelectAzureLoadTestRunMessage),
        };
        return {
            invocationMessage: Messages.SelectingAzureLoadTestRun,
            confirmationMessages,
        };
    }
}