import * as vscode from 'vscode';
import { Copilot } from '../../constants';
import { Logger } from '../../logger';
import { UserState } from '../AzureLoadTesting/model';

export class GitHubService {

    private _logger = new Logger("GitHubService");
    constructor() {
    }

    async getUserState(): Promise<UserState> {
        
        let userState = UserState.NoGitHubAccount;

        let githubAccounts = await vscode.authentication.getAccounts('github');
                
        if(!githubAccounts || githubAccounts.length == 0){
            this._logger.debug("No github account found");
            userState = UserState.NoGitHubAccount;
        }else{
            userState = UserState.SignedInWithGitHub;
            let access = await this.checkIfUserHasCopilotAccess();
            if(!access){
                this._logger.debug("User does not have copilot access");
                userState = UserState.CopilotNotEnabled;
            }else{
                this._logger.debug("User has copilot access");
                userState = UserState.CopilotEnabled;
            }
        }
        
        return userState;
    }

    async getGitHubAccountName(): Promise<string | undefined> {
        let githubAccounts = await vscode.authentication.getAccounts('github');
        
        if(!githubAccounts || githubAccounts.length == 0){
            this._logger.debug("No github account found");
            return undefined;
        }

        let accountName = githubAccounts[0].label;

        return accountName;
    }

    async signInToGitHubAccount(): Promise<void> {
        await vscode.authentication.getSession('github', ['user:email'], { createIfNone : true });
        let githubAccounts = await vscode.authentication.getAccounts('github');

        if(!githubAccounts || githubAccounts.length == 0){
            this._logger.debug("No github account found");
            return;
        }
    }
        
    async checkIfUserHasCopilotAccess () {

        // checking first if user has access to copilot using vscode llm api
        let models = await vscode.lm.selectChatModels({
            family : Copilot.DefaultModel
        });

        if(models && models.length > 0){
            this._logger.debug(`User has copilot access`);
            return true;
        }

        // if not, checking with github api
        this._logger.debug("User does not have copilot access, checking with github api");
        try{
            let url = "https://api.github.com/copilot_internal/v2/token";

            let token = await vscode.authentication.getSession('github', ['user:email'], { createIfNone : true });

            if(token == null){
                return false;
            }

            let headers = {
                'Authorization': `Bearer ${token.accessToken}`,
            };

            let response = await fetch(url, {
                method: 'GET',
                headers: headers
            });

            if (response.ok) {
                let data = await response.json();
                this._logger.debug(`User has copilot access with github api`);
                return true;
            } else {
                this._logger.debug(`User does not have copilot access: ${response.status}`);
                return false;
            }
        }catch(e){
            this._logger.debug(`Error while checking copilot access: ${e}`);
            return false;
        }

    }

}