import * as vscode from 'vscode';
import { CreateLoadTestTool } from './createLoadTest';
import { RunLoadTestInAzure } from './runLoadTestInAzure';
import { SelectAzureLoadTestResource } from './selectAzureLoadTestResource';
import { GetAzureLoadTestRunInsights } from './getLoadTestInsightsAzure';
import { SelectAzureLoadTestRun } from './selectAzureLoadTestRun';

export function registerChatTools(context: vscode.ExtensionContext) {
    context.subscriptions.push(vscode.lm.registerTool('create_load_test_script', new CreateLoadTestTool()));
    context.subscriptions.push(vscode.lm.registerTool('select_azure_load_testing_resource', new SelectAzureLoadTestResource()));
    context.subscriptions.push(vscode.lm.registerTool('run_load_test_in_azure', new RunLoadTestInAzure()));
    context.subscriptions.push(vscode.lm.registerTool('select_azure_load_test_run', new SelectAzureLoadTestRun()));
    context.subscriptions.push(vscode.lm.registerTool('get_azure_load_test_run_insights', new GetAzureLoadTestRunInsights()));
}