import { TestType } from "../AzureLoadTesting/model";

export const FindEnvsAndSecretsSystemPrompt = 'You are an expert in Load testing tool like JMeter and Locust. You are helping a developer to set up a load test by identifying secrets and environment variables that need to be configured.';

export const FindEnvsAndSecretsUserPrompt = (script:string, loadTestType:TestType) => {


    return `You are given a ${loadTestType} load test script which may use environment variables or secrets (credentials like api key or bearer token etc., sensitive data information). Please help the developer find the environment variables and secrets used in the script. Please provide the list of environment variables and secrets used in the script in the Required JSON Output format defined below. Don't add any comments or explanations in the response. If there are no environment variables or secrets used in the script, return an empty list array.
    Please include value for environment variables only in the output. If the value is not available, then return empty string as value for that variable.
    ## Input Python script
    ${script}
        
    ## Required Output
    \`\`\`json
    {
        "envVariables": [
            {
                "name": "<env_variable_name1>",
                "value": "<value_of_env_variable1>",
            },
            {
                "name": "<env_variable_name2>",
                "value": "<value_of_env_variable2>",
            }
        ],
        "secrets": [
            "<secret_name1>",
            "<secret_name2>"
            ...
        ]
    }
    \`\`\``;
}

export const FindAdditionalFilesSystemPrompt = 'You are an AI assistant that helps developers identify additional files that a Python script may depend on. Your task is to analyze the provided Python script and list any external files or local Python scripts that are referenced in the code, excluding comments.';

export const FindAdditionalFilesUserPrompt = (script:string) => {
    return `Given below python script can you help in finding the additional files which is used in this script code. File shouldn't be referred as a comment section in python code. There could also be some local python script which is referanced by this script, include those files as well. Please provide the list of file paths used in the script in the below format. If this script doesn't use any file then return empty list array. Don't return any python script code in the response.
    ##[Input Python script]
    ${script}
    
    ##[Required Output]
    
    \`\`\`files
    [
        <file1_path>,
        <file2_path>
        ...
    ]
    \`\`\``;
}