import * as path from 'path';
import * as vscode from 'vscode';
import { ChatParticipant, VSCodeCommand } from '../../../constants';
import { GenerateLoadTestService } from '../../../Services/AzureLoadTesting/generateLoadTestService';
import { LoadTestInputType, LoadTestUserInput, TestType } from '../../../Services/AzureLoadTesting/model';
import { TestScriptHelper } from '../../../Services/AzureLoadTesting/testScript';
import { getRootPath } from '../../../Services/VsCodeAPI';
import { ErrorMessages, Messages } from "../../../strings";
import { formatString } from '../../../util';
import { ChatCommandHandler } from "../../handler";
import { ALTContext } from '../Context';
import { validateInputFile } from "../util";
import { EditorUtil } from '../../../Utils/editorUtil';
import { updateEnvFile, updateRequirementsFile } from '../../../Utils/fileUtil';

export class GenerateLoadTestHandler extends ChatCommandHandler {
    
    private _selectedUserInput : LoadTestUserInput | null = null;
    
    async handle(request: vscode.ChatRequest, context: vscode.ChatContext, stream: vscode.ChatResponseStream, token: vscode.CancellationToken) {
        
        if (!this.isWorkspaceOpen(stream)) {
            return false;
        }

        let service = new GenerateLoadTestService();

        let userInput : LoadTestUserInput | null = await service.selectLoadTestInputType();
        
        this._selectedUserInput = userInput;

        if (userInput && userInput.artifacts) {
            
            let inputFilePath = userInput.artifacts.inputFilePath;

            let isVaildInputFile = validateInputFile(inputFilePath);

            ALTContext.setLatestLoadTestInputFilePath(inputFilePath);

            if(!isVaildInputFile){
                stream.markdown(vscode.l10n.t(ErrorMessages.INVALID_INPUT_FILE));
                return false;
            }

            stream.markdown(`${vscode.l10n.t(Messages.GeneratingLoadTestScript)} **${path.basename(inputFilePath)}**.\n\n`);
            
            let scriptFilePath : string | null = null;
            let envContent = userInput.artifacts.requiredEnvs ? Object.entries(userInput.artifacts.requiredEnvs).map(([key, value]) => `${key}=${value}`).join('\n') : "";
            let packages = userInput.artifacts.requirements || [];
            let additionalFiles = [];

            if(userInput.type != LoadTestInputType.URLEndpoint && userInput.type != LoadTestInputType.SampleHTTPFile){
                let resp = await new TestScriptHelper().createScript(userInput, request.model);
                scriptFilePath = resp.script;
                envContent = resp.envContent;
                packages = resp.packages;
                additionalFiles = resp.additionalFiles || [];
            }else{
                // For URL Endpoint and Sample HTTP File, we don't generate a script through llm, but we need to stream it
                let scriptContent = userInput.artifacts.scriptContent;
                
                if (!scriptContent) {
                    stream?.markdown(vscode.l10n.t(ErrorMessages.UnableToGenerateLoadTestScript));
                    return false;
                }

                let content = scriptContent.trim().split('\n').map(line => line+"\n");
                scriptFilePath = await EditorUtil.streamContentToEditorWithOverlay(content, userInput.testType);

                if (!scriptFilePath) {
                    stream?.markdown(vscode.l10n.t(ErrorMessages.UnableToGenerateLoadTestScript));
                    return false;
                }
                
                let envs = userInput.artifacts.requiredEnvs;
                packages = userInput.artifacts.requirements || [];
                envContent =envs ? Object.entries(envs || {}).map(([key, value]) => `${key}=${value}`).join('\n') : "";

                updateEnvFile(envs || {}, vscode.Uri.joinPath(vscode.workspace.workspaceFolders![0].uri, '.env').fsPath);

                if(userInput.testType == TestType.Locust){
                    updateRequirementsFile(packages, vscode.Uri.joinPath(vscode.workspace.workspaceFolders![0].uri, 'requirements.txt').fsPath);
                }

            }

            if (!scriptFilePath) {
                stream?.markdown(vscode.l10n.t(ErrorMessages.UnableToGenerateLoadTestScript));
                return false;
            }
            
            const rootPath = getRootPath();

            stream?.filetree([{
                name : path.basename(rootPath),
                children : [
                    {
                        name : path.basename(scriptFilePath),
                        children : [],
                    }
                ]
            }], vscode.workspace.workspaceFolders![0].uri)
            
            
            stream?.markdown(`## ${vscode.l10n.t(Messages.AdditionalSteps)}\n\n`);
    
            if(envContent != "" && stream){
                stream.markdown(`\n\nThe `);
                stream.anchor(vscode.Uri.joinPath(vscode.workspace.workspaceFolders![0].uri, '.env'), '.env');
                stream.markdown(` file has been updated with the following variables:\n`);
                stream.markdown(`\`\`\`bash\n${envContent}\n\`\`\`\n`);    
            }
            
            if(packages.length > 0 && stream && userInput.testType == TestType.Locust){
                stream.markdown(`\n### ${formatString(Messages.RequirementTxtFileMarkdown, packages.join('\n'))}\n`);
                stream.markdown(`You can find the `);
                stream.anchor(vscode.Uri.joinPath(vscode.workspace.workspaceFolders![0].uri, 'requirements.txt'), 'requirements.txt');
                stream.markdown(` in the current workspace\n`);
            }
    
            stream?.markdown(`## ${vscode.l10n.t(Messages.NextSteps)}\n\n`);
    
            stream?.markdown(`\n\n### ${vscode.l10n.t(Messages.WantToTestLocally)}\n`);
            stream?.button({
                title: vscode.l10n.t(Messages.RunTestLocally),
                command : VSCodeCommand.OPEN_CHAT,
                arguments : [
                    `@${ChatParticipant.CHART_PARTICIPANT_ID} /${ChatParticipant.RUN_LOAD_TEST_LOCALLY}`
                ]
            });
    
            stream?.markdown(`\n\n### **OR** \n`);
    
            stream?.markdown(`\n\n### ${vscode.l10n.t(Messages.WantToRunAtScale)}\n`);
            stream?.button({
                title: vscode.l10n.t(Messages.RunInAzure),
                command : VSCodeCommand.OPEN_CHAT,
                arguments : [
                    `@${ChatParticipant.CHART_PARTICIPANT_ID} /${ChatParticipant.RUN_LOAD_TEST_IN_AZURE}`
                ]
            });

        } else {
            stream.markdown(vscode.l10n.t(ErrorMessages.REQUIRED_INPUT_FILE_MARKDOWN));
        }
        
        return false;
    }


    async proceedWithoutCopilot () {
        let generateLoadTestService  = new GenerateLoadTestService();
        await generateLoadTestService.proceedLoadTestGenerationWithoutCopilot(this._selectedUserInput)
    }

    
}