import * as dotenv from 'dotenv';
import * as vscode from 'vscode';
import { AzureSessionProviderHelper } from './AzureLogin/azureSessionProvider';
import { AzureDataSessionProviderHelper } from './AzureLogin/dataSessionProvider';
import { registerMTSChatParticipant } from './ChatParticipant';
import { createLoadTestWithCopilot as createLoadTest } from './Commands/createloadtest';
import { runLoadTestInAzure } from './Commands/runloadtestinazure';
import { runLoadTestLocally } from './Commands/runloadtestlocally';
import { viewLoadTestRuns } from './Commands/viewtestruns';
import { openWalkthrough } from './Commands/walkthrough';
import { registerChatTools } from './LanguageModelTools';
import { Logger } from './logger';
import { TestingTelemetryReport } from './telemetryReporter';

dotenv.config();

let logger = new Logger("Main");

export async function activate(context: vscode.ExtensionContext) {

    // Need to initialize the reporter before using it
    let reporter = new TestingTelemetryReport(context);

    logger.debug('Congratulations, your extension "azure-load-testing" is now active!');

    Logger.setOutputChannel();
    
    AzureSessionProviderHelper.activateAzureSessionProvider(context);
    AzureDataSessionProviderHelper.activateAzureSessionProvider(context);
    
    // registering command platte commands
    context.subscriptions.push(createLoadTest);
    context.subscriptions.push(viewLoadTestRuns);
    context.subscriptions.push(runLoadTestLocally);
    context.subscriptions.push(runLoadTestInAzure);
    context.subscriptions.push(openWalkthrough);
    context.subscriptions.push(reporter);

    // registering @testing chat extension
    registerMTSChatParticipant(context);

    registerChatTools(context);
}




