import * as vscode from 'vscode';
import { AbstractCommand } from '.';
import { Links, VSCodeCommand } from '../constants';
import { Logger } from '../logger';
import { GenerateLoadTestService } from '../Services/AzureLoadTesting/generateLoadTestService';
import { LoadTestUserInput, UserState } from '../Services/AzureLoadTesting/model';
import { ErrorMessages, Messages } from '../strings';

export class CreateLoadTestCommand extends AbstractCommand {
    
    private _service : GenerateLoadTestService;
    
    constructor() {
        super(VSCodeCommand.CREATE_LOAD_TEST);
        this.logger = new Logger("CreateLoadTest");
        this._service = new GenerateLoadTestService();
    }

    protected async execute(): Promise<void> {
        
        if(!this.isOpenWorkspaceFolder()) {
            return;
        }

        this.logger.debug("Checking if user has github account ");

        let userState = await this.githubService.getUserState();
        
        if(userState < UserState.CopilotEnabled){
            
            this.logger.debug(`User state : ${userState}`);
            
            // allow user to quick pick to sign in or sign up or proceed without copilot 
            let options = []

            if(userState == UserState.NoGitHubAccount){
                options.push({ label: vscode.l10n.t(Messages.SignInIntoGithubAccount), value : "SignIn"});
                options.push({ label: vscode.l10n.t(Messages.SignUpGitHubAccount), value : "SignUp"});
            }else if(userState == UserState.CopilotNotEnabled){
                this.logger.debug(`User state ${userState}`);
                let accountName = await this.githubService.getGitHubAccountName() || "";
                vscode.window.showWarningMessage(
                    vscode.l10n.t(ErrorMessages.NoAccessToGitHubCopilot, accountName),
                    vscode.l10n.t(ErrorMessages.SignUpForGitHubCopilot) // Button label
                )
                .then((selection) => {
                    if (selection == vscode.l10n.t(ErrorMessages.SignUpForGitHubCopilot)) {
                        vscode.env.openExternal(vscode.Uri.parse(Links.EnableCopilotInGithub));
                    }
                });
                options.push({ label: vscode.l10n.t(Messages.SignUpGitHubAccount), value : "SignUp"});
            }

            options.push({ label: vscode.l10n.t(Messages.ProceedWithoutGithubAccount), value : "WithoutCopilot"});

            let selection = await vscode.window.showQuickPick(
                options,
                {
                    placeHolder: vscode.l10n.t(Messages.FeatureRequiresGithubCopilot),
                    ignoreFocusOut : true
                }
            );

            if (selection) {
                this.logger.debug(`User selected copilot option : ${selection.value}`);
                if(selection.value == "SignIn"){
                    await this.githubService.signInToGitHubAccount();
                    // wait for few seconds to refresh the model state 
                    await new Promise(resolve => setTimeout(resolve, 1000));
                    // again initiate the command to create load test
                    this.logger.debug(`Proceeding load test generation after github sign in, opening new chat`)
                    
                    try{
                        await vscode.commands.executeCommand(VSCodeCommand.NEW_CHAT);
                        this.logger.debug(`Opened a new chat window after github sign in`);
                    }catch(e){
                        this.logger.debug(`Error occurred while opening new chat window ${e}`);
                    }
                    this.azureLoadTestService.generateLoadTestWithChatParticipant();
                }else if(selection.value == "SignUp"){
                    const uri = vscode.Uri.parse(Links.GithubCopilotSignUp);
                    vscode.env.openExternal(uri);
                }else{
                    let userInput : LoadTestUserInput | null = await this._service.selectLoadTestInputType(false);
                    this._service.proceedLoadTestGenerationWithoutCopilot(userInput);
                    
                }
            }else{
                this.logger.error(ErrorMessages.UnableToProceed)
                return;
            }
        }else{
            this.logger.debug("User has a GitHub account");
            this.azureLoadTestService.generateLoadTestWithChatParticipant();
        }

        
    }
}

export const createLoadTestWithCopilot = vscode.commands.registerCommand(
    VSCodeCommand.CREATE_LOAD_TEST,
    async () => {
        const command = new CreateLoadTestCommand();
        await command.run();
    }
);