import { RestAPI } from '../Services/AzureLoadTesting/api';
import * as vscode from 'vscode';
import { Logger } from '../logger';
import { Messages } from '../strings';

export class SelectAzureLoadTestResource implements vscode.LanguageModelTool<any> {
    private logger: Logger;

    constructor() {
        this.logger = new Logger('SelectAzureLoadTestResource');
    }

    async invoke(
        options: vscode.LanguageModelToolInvocationOptions<any>,
        _token: vscode.CancellationToken
    ) {
        this.logger.debug(`SelectAzureLoadTestResource.invoke called`);
        let apiClient = new RestAPI();
        let resource = await apiClient.selectAzureResourceDetails();
        if (resource) {
            this.logger.debug(`Resource selected: ${resource.resourceId}`);
            return new vscode.LanguageModelToolResult([
                new vscode.LanguageModelTextPart(`${resource.resourceId}`)
            ]);
        }
        this.logger.debug('No Azure Load Testing resource ID found');
        return new vscode.LanguageModelToolResult([
            new vscode.LanguageModelTextPart(Messages.NoAzureLoadTestingResourceIdFound)
        ]);
    }

    async prepareInvocation(
        options: vscode.LanguageModelToolInvocationPrepareOptions<any>,
        _token: vscode.CancellationToken
    ) {
        this.logger.debug(`SelectAzureLoadTestResource.prepareInvocation called`);
        const confirmationMessages = {
            title: Messages.SelectAzureLoadTestingResourceTitle,
            message: new vscode.MarkdownString(Messages.SelectAzureLoadTestingResourceMessage),
        };
        return {
            invocationMessage: Messages.SelectingAzureLoadTestingResource,
            confirmationMessages,
        };
    }
}