import * as vscode from 'vscode';
import * as path from 'path';
import { ChatCommandHandler } from '../../handler';
import { ErrorMessages, Messages } from '../../../strings';
import { VSCodeCommand } from '../../../constants';
import { ALTContext } from '../Context';

export class RunLoadTestLocallyHandler extends ChatCommandHandler {
    
    async handle(request: vscode.ChatRequest, context: vscode.ChatContext, stream: vscode.ChatResponseStream, token: vscode.CancellationToken){
        
        if (!this.isWorkspaceOpen(stream)) {
            return false;
        }
        
        let fileToRun: string | undefined = ALTContext.getLoadTestScript();

        // Check if there is an active text editor
        if(!fileToRun){
            // Ask the user to pick a file
            fileToRun = await this._fileService.selectLoadTestScript();

            if (!fileToRun || fileToRun === "") {
                return false;
            }
        }

        ALTContext.setLatestLoadTestScriptPath(fileToRun!);

        stream.filetree([{
            name : path.basename(path.dirname(fileToRun)),
            children : [
                {
                    name : path.basename(fileToRun),
                    children : [],
                }
            ],
        }], vscode.workspace.workspaceFolders![0].uri)
        
        stream.markdown(`${vscode.l10n.t(Messages.RunningTheLoadTestScriptLocally)} **${path.basename(fileToRun!)}** \n\n`);
        stream.markdown(`${vscode.l10n.t(Messages.CheckTerminalWindow)}\n\n`);
        vscode.commands.executeCommand(VSCodeCommand.RUN_LOAD_TEST_LOCALLY, fileToRun);
        return true;
    }
    
}
