import * as fs from "fs";
import * as yaml from "js-yaml";
import * as path from "path";
import * as vscode from "vscode";
import { LoadTestYAMLConfig } from "../../../Services/AzureLoadTesting/model";
import { YAMLParser } from "../../../Services/AzureLoadTesting/yaml";
import { ChatParticipant, VSCodeCommand } from "../../../constants";
import { ErrorMessages, Messages } from "../../../strings";
import { ChatCommandHandler, ICommandHandlerOptions } from "../../handler";
import { ALTContext } from "../Context";


export interface IValidationHandlerOptions extends ICommandHandlerOptions {
    runInAzure?: boolean;
}

export class ValidationHandler extends ChatCommandHandler {
    
    async handle(request: vscode.ChatRequest, context: vscode.ChatContext, stream: vscode.ChatResponseStream, token: vscode.CancellationToken){
            
        if (!this.isWorkspaceOpen(stream)) {
            return false;
        }

        let fileToGenerate: string | undefined = ALTContext.getLoadTestConfig(false);

        if(!fileToGenerate){
            fileToGenerate = await this._fileService.selectLoadTestConfigFile();

            if (!fileToGenerate || fileToGenerate === "") {
                return false;
            }
        }
        
        let copilotModel = request.model.family;
        
        if(!fileToGenerate.endsWith("yaml") && !fileToGenerate.endsWith("yml")){
            stream.markdown(vscode.l10n.t(ErrorMessages.SELECT_A_CONFIGURATION_FILE));
            return false;
        }

        const document = await vscode.workspace.openTextDocument(fileToGenerate);
        await vscode.window.showTextDocument(document);

        ALTContext.setLatestLoadTestConfigPath(fileToGenerate);

        let yamlService = new YAMLParser();
        let file = fs.readFileSync(fileToGenerate, "utf-8");

        // check if yaml is a valid YAML file
        try {
            yaml.load(file);

            // TODO : can check more for a valid load test yaml file
        } catch (e) {
            stream.markdown(vscode.l10n.t(ErrorMessages.NOT_A_VALID_YAML));
            return false;
        }

        stream.markdown(`${vscode.l10n.t(Messages.Using)} **${path.basename(fileToGenerate)}**...\n\n`);

        let yamlConfig = yaml.load(file) as LoadTestYAMLConfig;

        let validationResult = await yamlService.validateYAMLConfig(yamlConfig.testPlan, path.dirname(path.resolve(fileToGenerate)), yamlConfig, copilotModel);

        if (!validationResult) {
            return false;
        }

        let { missingVariables, missingFiles } = validationResult;

        let isValidYAMLConfig = await yamlService.isValidYAMLConfig({missingFiles, missingVariables});

        let missingSecrets = false;

        if(missingVariables && missingVariables.length > 0){
            missingSecrets = true;
            stream.markdown(`${vscode.l10n.t(Messages.ConfigurationIsReady)}\n\n`);

            stream.markdown(`${vscode.l10n.t(Messages.RequiredEnvironmentVariables)}:\n`);
            
            missingVariables.forEach((variable: string) => {
                stream.markdown("- "+variable+"\n");
            });
            stream.markdown('\n');
        }

        if(missingFiles && missingFiles.length > 0){
            stream.markdown(`${vscode.l10n.t(Messages.RequiredAdditionalFiles)}.\n\n`);
            
            missingFiles.forEach((file: string) => {
                stream.markdown("- " + file+"\n");
            });
            
            stream.markdown('\n');
        }

        let options = this._options as IValidationHandlerOptions;

        this._logger.debug(`ValidationHandler: ${fileToGenerate} - isValid ${isValidYAMLConfig}`);

        if(isValidYAMLConfig && options && options.runInAzure){

            // hide followups
            this.setShowFollowups(false);

            stream.markdown(vscode.l10n.t(Messages.RunninInALTNow));
            
            let resp = await yamlService.parseYAML(fileToGenerate);

            if(resp != null){
                // execute function in a new thread 
                (async () => {
                    try {
                        await this._altService.startLoadTest(resp.loadTestConfig!, resp.options!);
                    } catch (error) {
                        this._logger.error(`Failed to start load test: ${error}`);
                    }
                })();
                return true;
            }else{
                vscode.window.showErrorMessage(vscode.l10n.t(ErrorMessages.INVALTD_YAML_FILE));
                return false;
            }
        }else{
            if(missingSecrets){
                stream.markdown(`\n\n${vscode.l10n.t(Messages.StoreSecretsInAKV)}\n\n`);
                stream.markdown(`## ${vscode.l10n.t(Messages.ChooseAnOption)}:\n\n`);
                stream.markdown(`### ${vscode.l10n.t(Messages.SetupEnvFile)}`)

                stream.button({
                    title: vscode.l10n.t(Messages.SelectAEnvFile),
                    command : VSCodeCommand.OPEN_CHAT,
                    arguments : [
                        `@${ChatParticipant.CHART_PARTICIPANT_ID} /${ChatParticipant.SETUP_ENV_FILE}`
                    ]
                });

                stream.markdown(`### `+ vscode.l10n.t(Messages.ConfigureSecretsInAKV))
                stream.button({
                    title: vscode.l10n.t(Messages.ConfigureSecretsInAKVSteps),
                    command : VSCodeCommand.OPEN_CHAT,
                    arguments : [
                        `@${ChatParticipant.CHART_PARTICIPANT_ID} /${ChatParticipant.SETUP_SECRET_IN_AKV}`
                    ]
                });

                stream.markdown(`### ${vscode.l10n.t(Messages.ProccedWithTest)}`)
                stream.button({
                    title: vscode.l10n.t(Messages.RunInAzureNow),
                    command : VSCodeCommand.OPEN_CHAT,
                    arguments : [
                        `@${ChatParticipant.CHART_PARTICIPANT_ID} ${ChatParticipant.StartLoadTestRunPrompt}`
                    ]
                });
            }else{

                if(options && !options.runInAzure && isValidYAMLConfig){
                    stream.markdown(`Configuration is ready to run the load test.\n\n`);
                }
            }

            return isValidYAMLConfig;
        }
    }
}
