import * as fs from 'fs';
import * as path from 'path';
import * as vscode from 'vscode';
import { AzureLoadTesting, Copilot } from '../constants';
import { Logger } from '../logger';
import { GenerateLoadTestService } from '../Services/AzureLoadTesting/generateLoadTestService';
import { LoadTestInputType, LoadTestUserInput, TestType } from '../Services/AzureLoadTesting/model';
import { TestScriptHelper } from '../Services/AzureLoadTesting/testScript';
import { URLEndpointLoadTestInputHandler } from '../Services/LoadTestUserInput/url';
import { ErrorMessages, Messages } from '../strings';
import { formatString } from '../util';
import { ICreateLoadTestToolOptions } from './models';
import { EditorUtil } from '../Utils/editorUtil';
import { updateEnvFile, updateRequirementsFile } from '../Utils/fileUtil';

export class CreateLoadTestTool implements vscode.LanguageModelTool<ICreateLoadTestToolOptions> {
    private _generateLoadTestService: GenerateLoadTestService;
    private logger: Logger;

    constructor() {
        this._generateLoadTestService = new GenerateLoadTestService();
        this.logger = new Logger('CreateLoadTestTool');
    }

    async invoke(
        options: vscode.LanguageModelToolInvocationOptions<ICreateLoadTestToolOptions>,
        _token: vscode.CancellationToken
    ) {
        this.logger.debug('CreateLoadTestTool.invoke called');
        const params = options.input;
        const endpoint_url = params.endpoint_url;
        const input_file_path = params.input_file_path;
        const input_file_type = params.input_file_type;

        const [model] = await vscode.lm.selectChatModels({
            vendor: 'copilot',
            family: Copilot.DefaultModel
        });

        let userInput: LoadTestUserInput | null = null;
        let testType : TestType | undefined = undefined;
        let userGivenTestType = params.testType;
        let testDuration = params.test_duration_seconds ? parseInt(params.test_duration_seconds) : AzureLoadTesting.DefaultDuration;
        let virtualUserCount = params.virtual_user_count ? params.virtual_user_count : AzureLoadTesting.DefaultVUs;
        if(!userGivenTestType){
            
            // ask user for test type if not provided
            this.logger.debug('Prompting user for test type');
            let testTypeSelection = await vscode.window.showQuickPick(
                [
                    { label: vscode.l10n.t(Messages.Locust), value: TestType.Locust },
                    { label: vscode.l10n.t(Messages.JMeter), value: TestType.JMeter}
                ],
                {
                    placeHolder: vscode.l10n.t(Messages.SelectLoadTestType),
                    ignoreFocusOut : true
                }
            );

            if(testTypeSelection){
                testType = testTypeSelection.value;
            }else{
                this.logger.debug(`User did not select test type, defaulting to Locust`);
                testType = TestType.Locust;
            }
        }else{
            this.logger.debug(`Using test type from params: ${params.testType}`);
            if(userGivenTestType.toLowerCase() == "locust"){
                testType = TestType.Locust;
            }else if(userGivenTestType.toLowerCase() == "jmeter"){
                testType = TestType.JMeter;
            }else{
                this.logger.debug(`Invalid test type provided: ${userGivenTestType}, defaulting to Locust`);
                testType = TestType.Locust;
            }
        }

        if (endpoint_url) {
            this.logger.debug(`Using endpoint_url: ${endpoint_url}`);
            let urlTestHandler = new URLEndpointLoadTestInputHandler(testType);
            let artifacts = await urlTestHandler.getArtifacts(endpoint_url);
            userInput = {
                type: LoadTestInputType.URLEndpoint,
                artifacts: artifacts,
                testType: params.testType!,
                virtualUsers: virtualUserCount,
                testDurationSeconds: testDuration,
            }
        } else if (input_file_path) {
            this.logger.debug(`Using input_file_path: ${input_file_path}`);
            let resolvedInputFilePath = path.resolve(vscode.workspace.workspaceFolders![0].uri.fsPath, input_file_path);
            if (input_file_type != null) {
                userInput = {
                    type: input_file_type,
                    artifacts: {
                        inputFilePath: resolvedInputFilePath,
                        inputFileContent: fs.readFileSync(resolvedInputFilePath, 'utf-8'),
                    },
                    testType: params.testType!,
                    virtualUsers: virtualUserCount,
                    testDurationSeconds: testDuration
                }
            } else {
                let fileExtension = path.extname(resolvedInputFilePath);
                if (fileExtension === '.http') {
                    userInput = {
                        type: LoadTestInputType.HTTP,
                        artifacts: {
                            inputFilePath: resolvedInputFilePath,
                            inputFileContent: fs.readFileSync(resolvedInputFilePath, 'utf-8'),
                        },
                        testType: params.testType!,
                        virtualUsers: virtualUserCount,
                        testDurationSeconds: testDuration
                    }
                } else {
                    this.logger.debug('Prompting user for input type');
                    userInput = await this._generateLoadTestService.selectLoadTestInputType();
                }
            }
        } else {
            this.logger.debug('Prompting user for input type');
            userInput = await this._generateLoadTestService.selectLoadTestInputType();
        }

        if (userInput && userInput.artifacts) {
            this.logger.debug(`User input artifacts found`);

            let scriptFilePath : string | null = null;
            let envContent = userInput.artifacts.requiredEnvs ? Object.entries(userInput.artifacts.requiredEnvs).map(([key, value]) => `${key}=${value}`).join('\n') : "";
            let packages = userInput.artifacts.requirements || [];
            let additionalFiles = [];


            if((userInput.type == LoadTestInputType.URLEndpoint ||  userInput.type != LoadTestInputType.SampleHTTPFile ) && userInput.artifacts!.scriptContent){
                // For URL Endpoint and Sample HTTP File, we don't generate a script through llm, but we need to stream it
                let scriptContent = userInput.artifacts.scriptContent || "";
                

                let content = scriptContent.trim().split('\n').map(line => line+"\n");
                scriptFilePath = await EditorUtil.streamContentToEditorWithOverlay(content, userInput.testType);

                if (!scriptFilePath) {
                    this.logger.debug('Unable to generate load test script');
                    return new vscode.LanguageModelToolResult([new vscode.LanguageModelTextPart(vscode.l10n.t(ErrorMessages.UnableToGenerateLoadTestScript))]);
                }
                
                let envs = userInput.artifacts.requiredEnvs;
                packages = userInput.artifacts.requirements || [];
                envContent =envs ? Object.entries(envs || {}).map(([key, value]) => `${key}=${value}`).join('\n') : "";

                updateEnvFile(envs || {}, vscode.Uri.joinPath(vscode.workspace.workspaceFolders![0].uri, '.env').fsPath);

                if(userInput.testType == TestType.Locust){
                    updateRequirementsFile(packages, vscode.Uri.joinPath(vscode.workspace.workspaceFolders![0].uri, 'requirements.txt').fsPath);
                }

            }else{
                let resp = await new TestScriptHelper().createScript(userInput, model);
                scriptFilePath = resp.script;
                envContent = resp.envContent;
                packages = resp.packages;
                additionalFiles = resp.additionalFiles || [];
            }

            
            if (scriptFilePath) {
                this.logger.debug(`Script generated: ${scriptFilePath}`);
                let response = `###Load test script ${path.basename(scriptFilePath)} generated. for the given inputs.\n\n Load Test script path : ${scriptFilePath}\n\n## ${vscode.l10n.t(Messages.AdditionalSteps)}\n\n`;
                if (envContent != "" ){
                    response += `\n\n###The .env file has been updated with the following variables:\n\u0060bash\n${envContent}\n\u0060\n Please make sure to update the .env file with the correct values.\n\n`;
                    response += `You can find the .env file in the current workspace\n`;
                }
                if (packages.length > 0 && userInput.testType == TestType.Locust) {
                    response += `\n### ${formatString(Messages.RequirementTxtFileMarkdown, packages.join('\n'))}\n`;
                    response +=`You can find the `;
                    response += 'requirements.txt'
                    response +=` in the current workspace\n`;
                }
                response += `## ${vscode.l10n.t(Messages.NextSteps)}\n\n`
                response +=`\n\n### ${vscode.l10n.t(Messages.WantToTestLocally)}\n`;
                response +=`\n\n### **OR** \n`;
                response +=`\n\n### ${vscode.l10n.t(Messages.WantToRunAtScale)}\n`
                return new vscode.LanguageModelToolResult([
                    new vscode.LanguageModelTextPart(response)
                ]);
            } else {
                this.logger.debug('Unable to generate load test script');
                return new vscode.LanguageModelToolResult([new vscode.LanguageModelTextPart(vscode.l10n.t(ErrorMessages.UnableToGenerateLoadTestScript))]);
            }
        } else {
            this.logger.debug('No user input artifacts found');
            return new vscode.LanguageModelToolResult([new vscode.LanguageModelTextPart(vscode.l10n.t(ErrorMessages.UnableToGenerateLoadTestScript))]);
        }
    }

    async prepareInvocation(
        options: vscode.LanguageModelToolInvocationPrepareOptions<ICreateLoadTestToolOptions>,
        _token: vscode.CancellationToken
    ) {
        this.logger.debug(`CreateLoadTestTool.prepareInvocation called with input: ${JSON.stringify(options.input)}`);
        const endpoint_url = options.input?.endpoint_url;
        const virtual_user_count = options.input?.virtual_user_count;
        const test_duration_seconds = options.input?.test_duration_seconds;
        const input_file_path = options.input?.input_file_path;
        // create confirmation messages based on input 
        let confirmationMessages: string = vscode.l10n.t(Messages.ConfirmContinueWithParams) + "\n\n";
        if (endpoint_url) {
            confirmationMessages += `- **${vscode.l10n.t(Messages.EndpointUrl)}**: ${endpoint_url}\n`;
        }
        if (input_file_path) {
            confirmationMessages += `- **${vscode.l10n.t(Messages.InputFilePath)}**: ${input_file_path}\n`;
        }
        if (virtual_user_count) {
            confirmationMessages += `- **${vscode.l10n.t(Messages.VirtualUserCount)}**: ${virtual_user_count}\n`;
        }
        if (test_duration_seconds) {
            confirmationMessages += `- **${vscode.l10n.t(Messages.TestDuration)}**: ${test_duration_seconds} ${vscode.l10n.t(Messages.Seconds)}\n`;
        }
        return {
            invocationMessage: 'Creating load test script',
            confirmationMessages : {
                title: vscode.l10n.t(Messages.CreateLoadTestScript),
                message: new vscode.MarkdownString(confirmationMessages),
            }
        };
    }
}