import * as path from 'path';
import { VSCodeCommand } from '../constants';
import * as vscode from 'vscode';
import { AbstractCommand } from '.';
import { Logger } from '../logger';
import { ErrorMessages } from '../strings';
import { runJMeterScript, runLocustScript, validateLoadTestScript } from '../util';
import { FileServiceHelper } from '../Services/AzureLoadTesting/fileService';
import { ErrorUtil } from '../Utils/errorUtil';


export class RunLoadTestLocally extends AbstractCommand {
    
    constructor() {
        super(VSCodeCommand.RUN_LOAD_TEST_LOCALLY);
        this.logger = new Logger("RunLoadTestLocally");
    }

    protected async execute(fileToRun?: string): Promise<void> {

        if(!this.isOpenWorkspaceFolder()) {
            return;
        }

        if (!fileToRun || !fileToRun.endsWith('.py')) {

            const activeEditor = vscode.window.activeTextEditor;
            
            if (activeEditor) {
                fileToRun = activeEditor.document.fileName;

                const isValidScript = validateLoadTestScript(fileToRun);
                
                if (!isValidScript) {
                    fileToRun = undefined;
                }
            }
            
            let fileService = new FileServiceHelper();

            if(!fileToRun){
                // Ask the user to pick a file
                const selectedFile = await fileService.selectLoadTestScript();

                if (!selectedFile || selectedFile === "") {
                    return;
                }

                fileToRun = selectedFile;
            }            
        }

        if (fileToRun) {
            let isValidScript = validateLoadTestScript(fileToRun);
    
            if(!isValidScript){
                this.logger.error(ErrorMessages.InvalidLoadTestScript);
                return;
            }
    
            // if it is a Python locust script 
            if (fileToRun.endsWith('.py')) {
                // Run the locust script
                await runLocustScript(fileToRun);
            } else {
                // if it is a JMeter load test script, we can run it using the JMeter CLI
                if( fileToRun.endsWith('.jmx')) {
                    await runJMeterScript(fileToRun);
                    return;
                }else{
                    this.logger.error(ErrorMessages.InvalidLoadTestScript);
                    return;
                }
            }
            this.logger.debug(`Running load test script locally`);
        }else{
            ErrorUtil.showRequiredLoadTestScriptError();
        }
    }   
};


export const runLoadTestLocally = vscode.commands.registerCommand(
    VSCodeCommand.RUN_LOAD_TEST_LOCALLY,
    async (fileToRun?:string) => {
        const command = new RunLoadTestLocally();
        await command.run(fileToRun);
    }
);