import { VSCodeCommand } from "../constants";
import * as vscode from 'vscode';
import { Messages } from "../strings";
import { Logger } from "../logger";

const logger = new Logger("CommandUtil");
export const openWorkspaceFolder = () => {
    
    logger.info(Messages.WorkspaceNotOpen);
    
    vscode.window.showInformationMessage(Messages.WorkspaceNotOpen, {
        modal: true,
    }, {
        title: Messages.OpenWorkspace,
        command: VSCodeCommand.OpenWorkspaceCommand,
    }).then((selection:any) => {
        if (selection?.command === VSCodeCommand.OpenWorkspaceCommand) {
            vscode.commands.executeCommand(VSCodeCommand.OpenWorkspaceCommand);
        }
    })
}