import * as vscode from "vscode";
import { Links, VSCodeCommand } from "../constants";
import { Logger } from "../logger";
import { ErrorMessages, Messages } from "../strings";

export namespace ErrorUtil {

    let logger = new Logger("ErrorUtil");

    export const showRequiredLoadTestScriptError = () =>{
        logger.debug(ErrorMessages.REQUIRED_LOAD_TEST_SCRIPT);
        vscode.window
        .showErrorMessage(
            vscode.l10n.t(ErrorMessages.REQUIRED_LOAD_TEST_SCRIPT),
            vscode.l10n.t(ErrorMessages.OpenQuickstartGuide) // Button label
        )
        .then((selection) => {
            if (selection == vscode.l10n.t(ErrorMessages.OpenQuickstartGuide)) {
                vscode.env.openExternal(vscode.Uri.parse(Links.QuickStartGuide));
            }
        });
    }

    export const showRequiredInputFileError = () => {
        logger.debug(ErrorMessages.REQUIRED_INPUT_FILE_TEXT);

        vscode.window
        .showErrorMessage(
            vscode.l10n.t(ErrorMessages.REQUIRED_INPUT_FILE_TEXT),
            vscode.l10n.t(ErrorMessages.OpenQuickstartGuide) // Button label
        )
        .then((selection) => {
            if (selection == vscode.l10n.t(ErrorMessages.OpenQuickstartGuide)) {
                vscode.env.openExternal(vscode.Uri.parse(Links.QuickStartGuide));
            }
        });
    }

    export const showNoFileSelectedError = () => {
        logger.debug(ErrorMessages.NoFileSelected);

        vscode.window
        .showErrorMessage(
            vscode.l10n.t(ErrorMessages.NoFileSelected),
            vscode.l10n.t(ErrorMessages.OpenQuickstartGuide) // Button label
        )
        .then((selection) => {
            if (selection == vscode.l10n.t(ErrorMessages.OpenQuickstartGuide)) {
                vscode.env.openExternal(vscode.Uri.parse(Links.QuickStartGuide));
            }
        });
    }

    export const showEditorCloseError = () => {
        vscode.window.showWarningMessage(
            vscode.l10n.t(Messages.EditorWindowClosed),
            vscode.l10n.t(Messages.Retry),
        ).then(async (retry) => {
            if (retry === vscode.l10n.t(Messages.Retry)) {
                logger.debug(`Retrying to generate load test Script as the editor was closed`);
                vscode.commands.executeCommand(VSCodeCommand.CREATE_LOAD_TEST)
            }
        });
    }
}
