
import { AzureLoadTestingService } from '../Services/AzureLoadTesting';
import { RestAPI } from '../Services/AzureLoadTesting/api';
import { VSCodeCommand } from '../constants';
import { extractTestRunProperties, getNextFileName } from '../util';
import { Logger } from '../logger';
import { ErrorMessages, Messages } from '../strings';
import * as vscode from 'vscode';
import { AbstractCommand } from '.';
import { Loader } from '../loader';

export class ViewLoadTestRuns extends AbstractCommand {

    private readonly _apiClient: RestAPI;

    constructor() {
        super(VSCodeCommand.VIEW_LOAD_TEST_RUNS);
        this.logger = new Logger("ViewLoadTestRuns");
        this._apiClient = new RestAPI();
    }

    protected async execute(): Promise<void> {

        if(!this.isOpenWorkspaceFolder()) {
            return;
        }

        let resourceDetails = null;

        // Select azure resource through the command palette 
        resourceDetails = await this._apiClient.selectAzureResourceDetails(undefined, false);

        if(resourceDetails == null){
            this.logger.error(ErrorMessages.NoAzureResoureSelected);
            return;
        }

        let selectedTestRun = await this.selectAzureLoadTestRun(resourceDetails.dataPlaneURI);

        if (selectedTestRun) {          
            vscode.env.openExternal(selectedTestRun.portalUrl);
            vscode.window.showInformationMessage(`Selected test run: ${selectedTestRun.label}`);
        } else  {
            this.logger.error(ErrorMessages.NoTestRunSelected);
            return;
        }

        return;
    }

    async selectAzureLoadTestRun(dataPlaneURI:string) {
        // Call ALT API to get the list of test runs and store json file in the workspace
        Loader.show(Messages.LoadingTestRuns);
        
        let testRuns = await this._apiClient.getTestRuns(dataPlaneURI);

        Loader.hide();

        if (!testRuns || testRuns.length == 0) {
            this.logger.error(ErrorMessages.NoTestRunFound);
            return;
        }
        
        let listTestRuns = extractTestRunProperties(testRuns);
        
        if (!listTestRuns || listTestRuns.length == 0) {
            this.logger.error(ErrorMessages.NoTestRunFound);
            Loader.hide();
            return;
        }

        const testIds = Array.from(new Set(listTestRuns.map((testRun: any) => testRun.testId)));
        const testDetailsList = await Promise.all(testIds.map((testId: string) => this._apiClient.getTest(dataPlaneURI, testId)));
        const testIdNameMapping = new Map(testDetailsList.map((test: any) => [test.testId, test.displayName]));

        listTestRuns = listTestRuns.map((testRun: any) => { testRun.testName = testIdNameMapping.get(testRun.testId); return testRun; });

        // Display the test runs in the quick pick window
        const testRunItems = listTestRuns.map((testRun: any) => ({
            label: testRun?.testRunName,
            description: testRun?.testName,
            portalUrl: testRun?.portalUrl,
            id:testRun?.testRunId,
        }));
        Loader.hide();
        
        const selectedTestRun = await vscode.window.showQuickPick(
            testRunItems, 
            {
                placeHolder: vscode.l10n.t(Messages.SelectTestRun),
                ignoreFocusOut: true,
            });

        return selectedTestRun;
    }
}

export const viewLoadTestRuns = vscode.commands.registerCommand(
    VSCodeCommand.VIEW_LOAD_TEST_RUNS,
    async () => {
        const command = new ViewLoadTestRuns();
        await command.run();
    }
);
