import * as fs from 'fs';
import * as path from 'path';
import { JMeterScriptFilePrefix, LocustScriptFilePrefix } from '../constants';
import { TestType } from '../Services/AzureLoadTesting/model';
import * as vscode from 'vscode';
import { Logger } from "../logger";
import { getRootPath } from '../Services/VsCodeAPI';
import { formatAiResponse, getNextFileName } from '../util';
import { ErrorUtil } from './errorUtil';
import { Messages } from '../strings';

const logger = new Logger("EditorUtil");

export namespace EditorUtil {

    export async function streamContentToEditorWithOverlay(lines: string[], loadTestType:TestType) {
        
        return await vscode.window.withProgress({
            location: vscode.ProgressLocation.Notification,
            title: vscode.l10n.t(Messages.GeneratingTheLoadTestScript),
            cancellable: false,
        }, async (progress, token) => {

            let rootPath = getRootPath();
            let filePrefix = LocustScriptFilePrefix;
            let fileExtension  = 'py';

            if (loadTestType == TestType.JMeter){
                filePrefix = JMeterScriptFilePrefix
                fileExtension = 'jmx';
            } 
            const generatedScript = getNextFileName(rootPath, filePrefix, fileExtension);
            fs.writeFileSync(generatedScript, '', 'utf8');

            let documentUri = vscode.Uri.file(generatedScript);
            const document = await vscode.workspace.openTextDocument(documentUri);
            const editor = await vscode.window.showTextDocument(document, { preview: false });

            // Create a decoration type for overlay
            const overlayDecoration = vscode.window.createTextEditorDecorationType({
                isWholeLine: true,
                after: {
                    contentText: 'Generating...',
                    color: '#ffffff',
                    backgroundColor: 'rgba(156, 151, 151, 0.7)',
                    margin: '0 0 0 20px',
                    fontWeight: 'bold'
                }
            });

            // Apply the overlay decoration to the first line
            editor.setDecorations(overlayDecoration, [
                { range: new vscode.Range(0, 0, 0, 0) }
            ]);

            let scriptContent = "";
            for (let i = 0; i < lines.length; i++) {
                scriptContent += lines[i]
                try {
                    const edit = new vscode.WorkspaceEdit();
                    edit.replace(
                        document.uri,
                        new vscode.Range(0, 0, document.lineCount, 0),
                        scriptContent
                    );
                    await vscode.workspace.applyEdit(edit);
                } catch (e) {
                    logger.debug(`Error while editing editor: ${e}`);
                    ErrorUtil.showEditorCloseError();
                    overlayDecoration.dispose();
                    return null;
                }
            }

            await editor.document.save();

            // Remove the overlay decoration after generation is complete
            overlayDecoration.dispose();

            // Re-open the file with the default scheme to allow editing
            const writableUri = vscode.Uri.file(generatedScript);
            const writableDocument = await vscode.workspace.openTextDocument(writableUri);
            let writeEditor = await vscode.window.showTextDocument(writableDocument);
            logger.debug(`Reopened ${path.basename(generatedScript)} in writable mode.`);

            logger.debug(`Generated load test Script: ${path.basename(generatedScript)} for type ${loadTestType}`);

            if(loadTestType == TestType.JMeter) {
                scriptContent = formatAiResponse(scriptContent, '```xml', '```');
            } else {
                scriptContent = formatAiResponse(scriptContent, '```python', '```');
            }
            
            await writeEditor.edit(editBuilder => {
                editBuilder.replace(new vscode.Range(0, 0, document.lineCount, 0), scriptContent);
            });

            await writeEditor.document.save();

            logger.debug(`Saved load test Script: ${path.basename(generatedScript)} for type ${loadTestType}`);

            return generatedScript;

        });
    }
}