import * as vscode from 'vscode';
import { ErrorMessages, Messages } from './strings';
import { TelemeryLogger } from './telemetryLogger';
import { LogLevel } from './constants';
import { AsyncLocalStorageUtil } from './Utils/localStorageUtil';

export class Logger {
    className = '';
    static vscodeOutputChannel: any;
    static logLevelsToOutputChannel: Set<string> = new Set([LogLevel.Info, LogLevel.Error]); // Default log levels

    constructor(className: string = '') {
        this.className = "[" + className + "]";
    }

    static setOutputChannel() {
        if (Logger.vscodeOutputChannel !== undefined) {
            return;
        }

        try {
            Logger.vscodeOutputChannel = vscode.window.createOutputChannel(vscode.l10n.t(Messages.AzureLoadTesting));
            Logger.vscodeOutputChannel.show();
        } catch (e) {
            console.log(vscode.l10n.t(ErrorMessages.ErrorCreatingOutputChannel));
        }
    }

    static configureLogLevels(logLevels: string[]) {
        Logger.logLevelsToOutputChannel = new Set(logLevels);
    }

    getMessage(message: string): string {
        const timestamp = new Date().toISOString();
        return `[${timestamp}]${this.className} ${message}`;
    }

    info(message: string): void {
        this.log(`[${LogLevel.Info}]${this.getMessage(message)}`);
    }

    warning(message: string): void {
        this.log(`[${LogLevel.Warning}]${this.getMessage(message)}`);
    }

    error(message: string, notifyError: boolean = true): void {
        this.log(`[${LogLevel.Error}]${this.getMessage(message)}`);
        this.handleError(message, notifyError);
    }

    debug(message: string): void { // Changed from arrow function to regular method
        this.log(`[${LogLevel.Debug}]${this.getMessage(message)}`);
    }

    log(message: string) {
        const logLevel = message.match(/^\[([A-Z]+)\]/)?.[1];
        // Send only configured log levels to VS Code output channel
        if (Logger.vscodeOutputChannel && logLevel && Logger.logLevelsToOutputChannel.has(logLevel)) {
            // Remove all bracketed sections from the message before sending it to the output channel
            let formmatedMessage = message.replace(/\[[^\]]*\]/g, '');
            
            try{

                const correlationId = AsyncLocalStorageUtil.getCorrelationId();
                const messageWithCorrelationId = correlationId ? `[${correlationId}]${formmatedMessage}` : formmatedMessage;
                Logger.vscodeOutputChannel.appendLine(vscode.l10n.t(messageWithCorrelationId));
            } catch (e) {
                Logger.vscodeOutputChannel.appendLine(vscode.l10n.t(formmatedMessage));
            }
        }

        // Send all logs to telemetry
        TelemeryLogger.logUsage('log', { message: message });
    }

    private handleError(message: string, notifyError: boolean = true) {
        if (notifyError) {
            vscode.window.showErrorMessage(vscode.l10n.t(message));
        }
    }
}