    getDefaultEnvs(endpoint:string){
        let domain = endpoint.split('/')[2];

        return {
            "HOST" : domain,
            "VIRTUAL_USERS": AzureLoadTesting.DefaultVUs.toString(),
            "DURATION": AzureLoadTesting.DefaultDuration.toString(),
        }
    }

    getDomainFromUrl(url: string): string {
        try {
            // add schme if not present
            if(!url.startsWith("http://") && !url.startsWith("https://")){
                url = "http://" + url;
            }
            const parsedUrl = new URL(url);
            return parsedUrl.hostname; // Returns the domain (e.g., "example.com")
        } catch (error) {
            console.error("Invalid URL:", error);
            return "";
        }
    }


