import * as fs from 'fs';
import * as vscode from 'vscode';
import { AbstractCommand } from '.';
import { ChatParticipant, VSCodeCommand } from '../constants';
import { executeWithCorrelation } from '../executeAysnc';
import { Logger } from '../logger';
import { RestAPI } from '../Services/AzureLoadTesting/api';
import { FileServiceHelper } from '../Services/AzureLoadTesting/fileService';
import { LoadTestConfigurationOptions, LoadTestYAMLConfig, UserState } from '../Services/AzureLoadTesting/model';
import { YAMLParser } from '../Services/AzureLoadTesting/yaml';
import { ErrorMessages } from '../strings';
import { AsyncLocalStorageUtil } from '../Utils/localStorageUtil';


export class RunLoadTestInAzure extends AbstractCommand {

    constructor() {
        super(VSCodeCommand.RUN_LOAD_TEST_IN_AZURE);
        this.logger = new Logger("RunLoadTestInAzure");
    }

    protected async execute(yamlConfig?:string): Promise<void> {
        
        if(!this.isOpenWorkspaceFolder()) {
            return;
        }
    
        let apiClient = new RestAPI();
        let loadTestConfig : LoadTestYAMLConfig | null = null;
        let yamlParser = new YAMLParser();
        let fileService = new FileServiceHelper();
    
        const yamlConfigExists = yamlConfig && fs.existsSync(yamlConfig);
        let options : LoadTestConfigurationOptions | null = null;

        if(!yamlConfig || !yamlConfigExists){
            // Expect SelectOrCreateLoadTestConfigFile to return an object or null
            const configResult = await yamlParser.SelectOrCreateLoadTestConfigFile();
            if(!configResult || !configResult.options || !configResult.loadTestConfig){
                return;
            }
            options = configResult.options;
            loadTestConfig = configResult.loadTestConfig;
            yamlConfig = options!.yamlConfigFileName;
        }else{
            let resp = await yamlParser.parseYAML(yamlConfig);
            if(!resp){
                this.logger.error(`Failed to parse YAML file: ${yamlConfig}`);
                vscode.window.showErrorMessage(ErrorMessages.NOT_A_VALID_YAML);
                return;
            }
            options = resp.options
            loadTestConfig = resp.loadTestConfig;
        }   

        if(!yamlConfig){
            return;
        }
        
        let userState = await this.githubService.getUserState();

        if(userState < UserState.CopilotEnabled){
            this.logger.debug(`User state ${userState}, running load test in azure directly`);
            (async () => {
                try {
                    await this.azureLoadTestService.startLoadTest(loadTestConfig!, options!);
                } catch (error) {
                    this.logger.error(`Failed to start load test: ${error}`);
                }
            })();
        }else{
            await executeWithCorrelation(VSCodeCommand.OPEN_CHAT_SIDEBAR, AsyncLocalStorageUtil.getCorrelationId());
        
            const document = await vscode.workspace.openTextDocument(yamlConfig);
            
            await vscode.window.showTextDocument(document);
            
            await executeWithCorrelation(VSCodeCommand.OPEN_CHAT, AsyncLocalStorageUtil.getCorrelationId(), `@${ChatParticipant.CHART_PARTICIPANT_ID} ${ChatParticipant.ValidateLoadTestConfigPrompt}`);
        }
    }
}

export const runLoadTestInAzure = vscode.commands.registerCommand(
    VSCodeCommand.RUN_LOAD_TEST_IN_AZURE,
    async () => {
        const command = new RunLoadTestInAzure();
        await command.run();
    }
);