import path from 'path';
import { LoadTestConfigurationOptions, LoadTestYAMLConfig } from '../Services/AzureLoadTesting/model';
import * as vscode from 'vscode';
import { AzureLoadTestingService } from '../Services/AzureLoadTesting';
import { RestAPI } from '../Services/AzureLoadTesting/api';
import { YAMLParser } from '../Services/AzureLoadTesting/yaml';
import { AzureLoadTesting, Copilot } from '../constants';
import { IRunALoadTestScriptAzureOptions as IRunLoadTestInAzureOptions } from './models';
import { Logger } from '../logger';
import { ErrorMessages, Messages } from '../strings';
import { getMaskedString } from '../util';

export class RunLoadTestInAzure implements vscode.LanguageModelTool<IRunLoadTestInAzureOptions> {
    
    private logger: Logger;
    private readonly _apiClient : RestAPI;
    private readonly _yamlParser : YAMLParser;
    private readonly _azureLoadTestService : AzureLoadTestingService;

    constructor() {
        this.logger = new Logger('RunLoadTestInAzure');
        this._apiClient = new RestAPI();
        this._yamlParser = new YAMLParser();
        this._azureLoadTestService = new AzureLoadTestingService();

    }
    async invoke(
        options: vscode.LanguageModelToolInvocationOptions<IRunLoadTestInAzureOptions>,
        _token: vscode.CancellationToken
    ) {
        this.logger.debug(`RunLoadTestInAzure.invoke called`);
        const params = options.input;
        if (params.azure_load_testing_resourceId) {
            this.logger.debug(`Using azure_load_testing_resourceId: ${params.azure_load_testing_resourceId}`);
        }
        if (params.configuration_file_path) {
            this.logger.debug(`Using configuration_file_path: ${getMaskedString(params.configuration_file_path)}`);
        }
        if (params.script_file_path) {
            this.logger.debug(`Using script_file_path: ${getMaskedString(params.script_file_path)}`);
        }
        let loadTestConfig : LoadTestYAMLConfig | null = null;
        let configurationOptions : LoadTestConfigurationOptions | null = null;
        let loadTestConfigurationFilePath : string | undefined = undefined;
        if(params.azure_load_testing_resourceId ) {
            if(!params.azure_load_testing_resourceId.startsWith('/subscriptions/')){
                this.logger.debug('Invalid Azure Load Testing resource ID');
                return new vscode.LanguageModelToolResult([new vscode.LanguageModelTextPart(ErrorMessages.InvalidAzureLoadTestingResourceId)]);
            }
        }else{
            this.logger.debug('Azure Load Test Resource ID is not provided');
            return new vscode.LanguageModelToolResult([new vscode.LanguageModelTextPart(ErrorMessages.AzureLoadTestResourceIdNotProvided)]);
        }
        let resourceDetails = await this._apiClient.getAzureResourceDetails(params.azure_load_testing_resourceId);
        if (!resourceDetails || !resourceDetails.id ) {
            this.logger.debug('Resource details not found or invalid');
            return new vscode.LanguageModelToolResult([new vscode.LanguageModelTextPart(ErrorMessages.InvalidAzureLoadTestingResourceId)]);
        }

        if(params.configuration_file_path){
            loadTestConfigurationFilePath = path.resolve(vscode.workspace.workspaceFolders![0].uri.fsPath, params.configuration_file_path);
            let resp = await this._yamlParser.parseYAML(loadTestConfigurationFilePath);
            if(!resp || !resp.loadTestConfig){
                this.logger.debug('Failed to create load test configuration');
                return new vscode.LanguageModelToolResult([new vscode.LanguageModelTextPart(ErrorMessages.FailedToCreateLoadTestConfig)]);
            }else{
                loadTestConfig = resp.loadTestConfig;
                configurationOptions = resp.options;
            }
        }else if(params.script_file_path){
            let loadTestScriptFilePath = path.resolve(vscode.workspace.workspaceFolders![0].uri.fsPath, params.script_file_path);
            let config = await this._yamlParser.createYAMLConfig(loadTestScriptFilePath, {
                resourceId: params.azure_load_testing_resourceId,
                resourceLocation: resourceDetails.location,
                copilotModel: Copilot.DefaultModel,
                virtual_users : params.virtual_user_count ?? AzureLoadTesting.DefaultVUs,
                test_duration_seconds : params.test_duration_seconds ?? AzureLoadTesting.DefaultDuration,
                dataPlaneURI: `https://${resourceDetails.properties.dataPlaneURI}`,
                multiRegion:false
            });
            if(!config) {
                this.logger.debug('Failed to create load test configuration');
                return new vscode.LanguageModelToolResult([new vscode.LanguageModelTextPart(ErrorMessages.FailedToCreateLoadTestConfig)]);
            }else{
                loadTestConfig = config.loadTestYAMLConfig!;
                configurationOptions = {
                    resourceId : resourceDetails.id,
                    resourceLocation : resourceDetails.location,
                    dataPlaneURI : `https://${resourceDetails.properties.dataPlaneURI}`,
                    yamlConfigFileName : config.filePath
                }
            }
        }else{
            this.logger.debug('Prompting user to select or create load test config file');
            let resp = await this._yamlParser.SelectOrCreateLoadTestConfigFile({
                resourceId: params.azure_load_testing_resourceId,
                resourceLocation: resourceDetails.location,
                copilotModel: Copilot.DefaultModel,
                virtual_users : params.virtual_user_count ?? AzureLoadTesting.DefaultVUs,
                test_duration_seconds : params.test_duration_seconds ?? AzureLoadTesting.DefaultDuration,
                dataPlaneURI: `https://${resourceDetails.properties.dataPlaneURI}`,
            });
            if(!resp){
                this.logger.debug('Load test configuration file is not provided');
                return new vscode.LanguageModelToolResult([new vscode.LanguageModelTextPart(ErrorMessages.LoadTestConfigFileNotProvided)]);
            }else{
                loadTestConfig = resp.loadTestConfig;
                configurationOptions = resp.options;
            }
        }

        if(!loadTestConfig) {
            this.logger.debug('Failed to create load test configuration');
            return new vscode.LanguageModelToolResult([new vscode.LanguageModelTextPart(ErrorMessages.FailedToCreateLoadTestConfig)]);
        }
        if (!configurationOptions) {
            this.logger.debug('configurationOptions is null, cannot start load test');
            return new vscode.LanguageModelToolResult([new vscode.LanguageModelTextPart(ErrorMessages.FailedToResolveConfigOptions)]);
        }
        // Ensure correct parameter type for startLoadTest
        let testRun = await this._azureLoadTestService.startLoadTest(loadTestConfig, configurationOptions);
        this.logger.debug(`Test run started: ${JSON.stringify(testRun)}`);
        if(!testRun || !testRun.testRunId) {
            this.logger.debug('Failed to start load test');
            return new vscode.LanguageModelToolResult([new vscode.LanguageModelTextPart(ErrorMessages.FailedToStartLoadTest)]);
        }

        // Use the already available configurationOptions
        let subscriptionId = configurationOptions.resourceId.split('/')[2];
        let script = configurationOptions.yamlConfigFileName;
        return new vscode.LanguageModelToolResult([
            new vscode.LanguageModelTextPart(
                `${Messages.RunningLoadTestScriptInAzure}\n\n` +
                `- **${Messages.AzureLoadTestingResourceId}**: ${configurationOptions.resourceId}\n` +
                `- **${Messages.AzureSubscriptionId}**: ${subscriptionId}\n` +
                `- **${Messages.LoadTestScriptFilePath}**: ${script}\n\n` +
                `- **${Messages.TestRunId}**: ${testRun.testRunId}\n` +
                `- **${Messages.AzureLoadTestConfigFilePath}**: ${loadTestConfigurationFilePath}\n\n` +
                `${Messages.LoadTestRunCompletionNote.replace('{portalUrl}', testRun.portalUrl)}` +
                `${Messages.ReuseAzureLoadTestConfigFile.replace('{configFile}', loadTestConfigurationFilePath!)}` +
                `${Messages.RunLoadTestInAzureCommand}` +
                `${Messages.GetLoadTestRunInsightsCommand}` +
                `${Messages.SelectLoadTestRunCommand}` +
                `${Messages.SelectLoadTestResourceCommand}`
            )
        ]);
    }

    async prepareInvocation(
        options: vscode.LanguageModelToolInvocationPrepareOptions<IRunLoadTestInAzureOptions>,
        _token: vscode.CancellationToken
    ) {
        let resourceName = options.input.azure_load_testing_resourceId?.split('/').pop() || '';
        let configuration_file_path = options.input.configuration_file_path;
        let script_file_path = options.input.script_file_path;

        let configurationFileName = configuration_file_path ? path.basename(configuration_file_path) : '';
        let scriptFileName = script_file_path ? path.basename(script_file_path) : '';


        let confirmationMessage = Messages.ContinueToRunLoadTest;
        if(resourceName) {
            confirmationMessage += `\n\n**${Messages.SelectedResourceName}**: ${resourceName}`;
        }
        if(configuration_file_path) {
            confirmationMessage += `\n\n**${Messages.UsingConfigurationFileName}**: ${configurationFileName}`;
        }else if(script_file_path) {
            confirmationMessage += `\n\n**${Messages.UsingScriptFileName}**': ${scriptFileName}`;
        }
        this.logger.debug(`RunLoadTestInAzure.prepareInvocation`);
        const confirmationMessages = {
            title: Messages.RunLoadTestInAzureTitle,
            message: new vscode.MarkdownString(confirmationMessage),
        };
        return {
            invocationMessage: Messages.RunningLoadTestInAzure,
            confirmationMessages,
        };
    }
}