interface CacheEntry {
    data: any;
    expiration: number;
}

export const globalCache: { [key: string]: CacheEntry } = {};

export function setGlobalCache(key: string, value: CacheEntry): void {
    globalCache[key] = value;
}

export function getGlobalCache(key: string): any {
    const now = Date.now();
    const cacheEntry = globalCache[key];

    if (cacheEntry && cacheEntry.expiration > now) {
        return cacheEntry.data;
    } else {
        // Remove expired entry
        delete globalCache[key];
        return null;
    }
}