import { Logger } from "../../logger";
import { FileServiceHelper } from "../../Services/AzureLoadTesting/fileService";
import { LoadTestInputArtifacts, LoadTestInputType, TestType } from "../../Services/AzureLoadTesting/model";


export abstract class LoadTestUserInputHandler {
    
    protected inputType: LoadTestInputType | undefined;

    protected testType: TestType | undefined;

    protected logger: Logger = new Logger('LoadTestUserInputHandler');

    protected fileServiceHelper: FileServiceHelper = new FileServiceHelper(); // Assuming this is defined somewhere in your code

    abstract selectArtifact<T extends LoadTestInputArtifacts>() : Promise<T | null>;

    constructor(inputType: LoadTestInputType, testType: TestType) {
        this.inputType = inputType;
        this.testType = testType;
    }
}