import { ErrorMessages, Messages } from '../strings';
import * as vscode from 'vscode';
import { TelemeryLogger } from '../telemetryLogger';
import { ALTContext } from './AzureLoadTesting/Context';
import { FileServiceHelper } from '../Services/AzureLoadTesting/fileService';
import { Logger } from '../logger';
import { AzureLoadTestingService } from '../Services/AzureLoadTesting';
import { Links, VSCodeCommand } from '../constants';

export interface ICommandHandlerOptions{

}

export abstract class ChatCommandHandler {
    
    protected _command;

    protected _telemetryLogger: vscode.TelemetryLogger = TelemeryLogger;

    protected _logger : Logger;

    protected _chatParticipant?: vscode.ChatParticipant = undefined;

    protected _fileService;

    protected _options  : ICommandHandlerOptions;

    private _showFollowups = true;

    protected _altService : AzureLoadTestingService;

    constructor(command:string, logger:Logger, options: ICommandHandlerOptions = {}) {
        this._command = command;
        this._fileService = new FileServiceHelper();
        this._options = options;
        this._logger = logger;
        this._altService = new AzureLoadTestingService();
    }

    abstract handle(request: vscode.ChatRequest, context: vscode.ChatContext, stream: vscode.ChatResponseStream, token: vscode.CancellationToken) : Promise<boolean>;

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    handleError(err: any, stream: vscode.ChatResponseStream): void {
        // making the chat request might fail because
        // - model does not exist
        // - user consent not given
        // - quote limits exceeded
        this._telemetryLogger.logError("copilotError", {
            command: this._command,
            error: err.message,
            code: err.code,
            cause: err.cause,
        });

        this._logger.debug(`copilotError : ${err.message} code: ${err.code} cause: ${err.cause}  stack ${err.stack} for command ${this._command}`);

        if (err instanceof vscode.LanguageModelError) {
            if(err.code == "NoPermissions"){
                stream.markdown(vscode.l10n.t(ErrorMessages.NoPermissions));
            }else if (err.cause instanceof Error && err.cause.message.includes('off_topic')) {
                stream.markdown(vscode.l10n.t(ErrorMessages.UnableToExplained));
            }
        } else {

            // re-throw other errors so they show up in the UI
            throw err;
        }
    }

    logUsages(): void {
        this._telemetryLogger.logUsage('chatRequest', { command : this._command });
    }

    setchatParticipant(participant: vscode.ChatParticipant){
        this._chatParticipant = participant;
    }

    getchatParticipant(){
        return this._chatParticipant;
    }

    setShowFollowups(showFollowups: boolean){
        this._showFollowups = showFollowups;
    }

    getShowFollowups(){
        return this._showFollowups;
    }

    openWorkspace(stream: vscode.ChatResponseStream) {
        this._logger.debug(Messages.WorkspaceNotOpen);
        stream.markdown(vscode.l10n.t(Messages.WorkspaceNotOpen));
        stream.button({
            'title': vscode.l10n.t(Messages.OpenWorkspace),
            'command' : VSCodeCommand.OpenWorkspaceCommand
        });
    }

    isWorkspaceOpen(stream: vscode.ChatResponseStream) {
        let workspace = vscode.workspace.workspaceFolders?.[0];
        if (!workspace) {
            this.openWorkspace(stream);
            return false;
        }
        return true;
    }
}
