import * as dotenv from 'dotenv';
import * as fs from 'fs'; // Import the fs module
import * as yaml from 'js-yaml';
import * as path from 'path';
import * as vscode from 'vscode';
import { AzureLoadTesting, Copilot, excludeFoldersForSelectingConfig, loadTestConfigSelectionPattern } from '../../constants';
import { Logger } from '../../logger';
import { ErrorMessages, Messages } from '../../strings';
import { formatString, generateTestDisplayName, getMaskedString, getNextFileName, getTestKind, getTestType, isValidTestScript } from '../../util';
import { getRootPath } from '../VsCodeAPI';
import { RestAPI } from './api';
import { FileServiceHelper } from './fileService';
import { AIInsightsService } from './insight';
import { LoadTestConfigInput, EnvAndSecrets, LoadTestConfigurationOptions, LoadTestYAMLConfig, ReferenceIdentityKind, ReferenceIdentityType, TestType, YAMLConfigInfo } from './model';
import { TestScriptHelper } from './testScript';

export class YAMLParser {

    private _logger = new Logger("YAMLParser");

    private _apiClient : RestAPI;
    private _testScriptHelper : TestScriptHelper;
    private _insightService: AIInsightsService;
    private _fileService : FileServiceHelper;

    constructor() {
        this._apiClient = new RestAPI();
        this._testScriptHelper = new TestScriptHelper();
        this._insightService = new AIInsightsService();
        this._fileService = new FileServiceHelper();
    }

    async parseYAML(yamlConfig:string): Promise<{
        loadTestConfig : LoadTestYAMLConfig | null,
        options: LoadTestConfigurationOptions
    } | null> {
        const yamlConfigFile = path.resolve(yamlConfig);
        const content = fs.readFileSync(yamlConfigFile, 'utf8');
        const data  = yaml.load(content) as LoadTestYAMLConfig;

        // Check for required fields
        if (!data || !data.testPlan || !data.resourceId) {
            this._logger.error('Required configuration test script or resourceId not found in YAML configuration.');
            return null;
        }

        let testScript = path.resolve(path.dirname(yamlConfig), data.testPlan);

        if (!testScript || !isValidTestScript(testScript)) {
            this._logger.error(formatString(ErrorMessages.TestScriptNotFoundInConfiguration, testScript));
            return null;
        }

        let resourceId = data.resourceId;
        
        let options : LoadTestConfigurationOptions = {
            resourceId : data.resourceId!,
            yamlConfigFileName : yamlConfig,
        };

        if(resourceId != null && resourceId !== "") {
            this._logger.info(`Fetching resource details for resource ${resourceId.split("/")[8]}`);
            let resourceDetails = await this._apiClient.getAzureResourceDetails(resourceId);
            if(resourceDetails === null) {
                return null;
            }
            options.dataPlaneURI = "https://" + resourceDetails.properties.dataPlaneURI;
            options.resourceLocation = resourceDetails.location;
            options.resourceId = resourceId;
        }else{
            this._logger.error(ErrorMessages.ResourceIdNotFound);
            return null;
        }
        return {
            options : options,
            loadTestConfig : data
        };
    }
    
    async createYAMLConfig(testScript:string, input:LoadTestConfigInput|null): Promise<YAMLConfigInfo | null> {
        
        if (!testScript || !isValidTestScript(testScript)) {
            this._logger.error(ErrorMessages.LoadTestScriptNotFound);
            return null;
        }

        this._logger.debug(`Creating YAML config`);

        let displayName = generateTestDisplayName();
        let description =  `${getTestType(testScript)} load test`;
        
        let engineInstances = 1;

        let regionalLoadTestConfig : {
            region: string;
            engineInstances: number;
        }[] | undefined = undefined;

        let regions : string[] | null = [];

        if(input && input.multiRegion && input.resourceLocation && input.resourceId) {
            this._logger.debug(`User selected multi region load test`);
            regions = await this.selectMultiRegions(input.resourceLocation!, input.resourceId!.split("/")[2]);
            
            if(!regions || regions.length === 0) {
                return null;
            }

            engineInstances = regions.length;
            
            if(regions.length > 1) {
            
                regionalLoadTestConfig = regions.map((region) => {
                    return {
                        region: region,
                        engineInstances: 1,
                    };
                });
            }
        }
        

        this._logger.debug(`Multiple regions selected: ${regions?.join(", ")}`);

        let environmentVariables : 
            { name: string; value: any; }[]
         = [];
        

        let testType = getTestType(testScript);
        this._logger.debug(`Test type is ${testType}`);
        if( testType === TestType.Locust) {
            
            // append locust specific environment variables locust users, run time and spawn rate

            let userCount = input?.virtual_users || AzureLoadTesting.DefaultVUs;
            let runTime = input?.test_duration_seconds || AzureLoadTesting.DefaultDuration;
            
            const totalRunTime = runTime;
            const maxUsers = userCount;
            const rampUpTime = totalRunTime * 0.75; // 75% of the total run time
            const spawnRate = Math.ceil(maxUsers / rampUpTime);

            environmentVariables.push(
                { name: "LOCUST_USERS", value: userCount},
                { name: "LOCUST_SPAWN_RATE", value: spawnRate },
                { name: "LOCUST_RUN_TIME", value: runTime }
            );            
        }

        let requiredVariables :  EnvAndSecrets = await this._testScriptHelper.getRequiredEnvAndSecretVariables(testScript, input?.copilotModel ?? Copilot.DefaultModel, testType);
        
        const loadTestConfig : LoadTestYAMLConfig= {
            version: 'v0.1',
            displayName,
            description,
            testPlan: vscode.workspace.asRelativePath(testScript),
            testType: getTestKind(testScript),
            engineInstances,
            env: environmentVariables,
            resourceId: input?.resourceId,
            regionalLoadTestConfig:regionalLoadTestConfig
        };

        if(requiredVariables.secrets.length > 0){
            loadTestConfig.secrets = requiredVariables.secrets.map((variable: string) => {
                return { name: variable, value: '', type: "SECRET_VALUE" };
            });
        }

        if(requiredVariables.envVariables.length > 0){
            // append env variables to environmentVariables
            let existingEnvVariables = environmentVariables.map((env) => env.name);
            requiredVariables.envVariables.forEach(variable => {
                if(!existingEnvVariables.includes(variable.name)){
                    environmentVariables.push({
                        name: variable.name,
                        value: variable.value || "", // use empty string if value is not provided
                    });
                }
            });
            
            loadTestConfig.env = environmentVariables
        }

        environmentVariables.forEach(variable => {
            if(variable.name == "VIRTUAL_USERS" && !variable.value){
                if(input && input.virtual_users){
                    variable.value = input.virtual_users;
                }else{
                    variable.value = AzureLoadTesting.DefaultVUs;
                }
            }

            if(variable.name == "DURATION" && !variable.value){
                if(input && input.test_duration_seconds){
                    variable.value = input.test_duration_seconds;
                }else{
                    variable.value = AzureLoadTesting.DefaultDuration;
                }
            }

            if(variable.name == "ENABLE_LOGGING" && !variable.value){
                variable.value = "true"; // default to true
            }
        });

        loadTestConfig.env = environmentVariables;

        let additionalFiles = await this._testScriptHelper.findAdditionalFiles(testScript, input?.copilotModel ?? Copilot.DefaultModel);

        // remove .env file from additional files
        additionalFiles = additionalFiles.filter(file => file !== ".env");

        let zipFiles = additionalFiles.filter(file => file.includes(".zip"));
        let propertiesFiles = additionalFiles.filter(file => file.includes(".properties"));
        let remainingFiles = additionalFiles.filter(file => !zipFiles.includes(file) && !propertiesFiles.includes(file));

        let rootPath = getRootPath();
        
        // add requirements.txt file if exists for locust test type
        if(rootPath && getTestType(testScript) === TestType.Locust) {
            let requirementsFile = path.join(rootPath, "requirements.txt");

            if(fs.existsSync(requirementsFile)) {
                remainingFiles.push("requirements.txt");
            }
        }

        if(remainingFiles.length > 0){
            loadTestConfig.configurationFiles = remainingFiles;
        }

        if(zipFiles.length > 0){
            loadTestConfig.zipArtifacts = zipFiles;
        }

        if(propertiesFiles.length == 1){
            loadTestConfig.properties = {
                userPropertyFile: propertiesFiles[0]
            };
        }

        try {
            let resp = await this._insightService.enableServerSideMonitoring(input?.resourceId!, loadTestConfig);
            if(!resp){
                this._logger.debug(`Did not enable AI Insights`);
            }else{
                let { identity, appComponents } = resp;
                this._logger.debug(`User has enabled server side monitoring`);
                if (identity) {
                    loadTestConfig.referenceIdentities = [{
                        type: ReferenceIdentityType.SystemAssigned,
                        kind: ReferenceIdentityKind.Metrics,
                    }];
                }else{
                    this._logger.debug(`No identity found for AI Insights`);
                }
                if (appComponents && appComponents.length > 0) {
                    this._logger.debug(`App components found for AI Insights`);
                    loadTestConfig.appComponents = appComponents;
                }
            }
        } catch (e) {
            this._logger.error('Failed to enable AI Insights: ' + (e as Error).message);
        }

        const yamlString = yaml.dump(loadTestConfig);
        const yamlConfigFile = getNextFileName(rootPath || "", "loadtest.config", 'yaml')
        fs.writeFileSync(yamlConfigFile, yamlString); 
        
        this._logger.debug(`YAML config created at ${yamlConfigFile}`);

        return {
            loadTestYAMLConfig: loadTestConfig,
            filePath: yamlConfigFile,
        };
    }

    async validateYAMLConfig(testScript:string, directoryPath: string, yamlConfig: LoadTestYAMLConfig, copilotModel:string)  {

        testScript = path.resolve(directoryPath, testScript);
        
        if (!testScript || !isValidTestScript(testScript)) {
            this._logger.error(ErrorMessages.LoadTestScriptNotFound);
            return null;
        }

        let requiredVariables = await this._testScriptHelper.getRequiredEnvAndSecretVariables(testScript, copilotModel, getTestType(testScript));
        
        let missingVariables : string[] = [];
        let missingFiles : string[]  = [];
        
        let rootPath = getRootPath();

        // adding missing secrets to the yaml config
        if(yamlConfig.secrets){
            let secrets = yamlConfig.secrets.map((secret) => secret.name);

            secrets.forEach(secret => {
                if(!requiredVariables.secrets.includes(secret)){
                    requiredVariables.secrets.push(secret);
                }
            });

            // adding missing secrets to the yaml config
            requiredVariables.secrets.forEach(variable => {
                if(!secrets.includes(variable)){
                    yamlConfig.secrets!.push({
                        name: variable,
                        value: '',
                        type: 'SECRET_VALUE'
                    })
                }
            });
        }

        // adding missing env variables to the yaml config
        if(yamlConfig.env){
            let envVariables = yamlConfig.env.map((env) => env.name);

            envVariables.forEach(env => {
                if(!requiredVariables.envVariables.some(variable => variable.name === env)){
                    requiredVariables.envVariables.push({ name: env, value: "" });
                }
            });

            // adding missing env variables to the yaml config
            requiredVariables.envVariables.forEach(variable => {
                if(!envVariables.includes(variable.name)){
                    yamlConfig.env!.push({
                        name: variable.name,
                        value: variable.value || "",
                    });
                }
            });
        }

        // check if all required variables are present in the .env file
        const envFilePath = path.join(rootPath, '.env');
        const envConfig = dotenv.config({ path: envFilePath });

        let requiredVariableNames = requiredVariables.envVariables.filter(variable => variable.value == "").map(variable => variable.name);
        
        requiredVariableNames = requiredVariableNames.concat(requiredVariables.secrets);


        if(envConfig.parsed){
            
            // check if all required variables are present in the .env file
            for(let variable of requiredVariableNames){
                if(!envConfig.parsed[variable]){
                    missingVariables.push(variable);
                }
                
                // if yaml config already has the env value then remove it from missing variables
                if(yamlConfig.env){
                    let env = yamlConfig.env.find(env => env.name === variable);
                    if(env && env.value !== ""){
                        missingVariables = missingVariables.filter(v => v !== variable);
                    }
                }
            }
        }else{
            this._logger.debug(`.env file not found at ${envFilePath}`);
            missingVariables = requiredVariableNames;
        }

        let additionalFiles = await this._testScriptHelper.findAdditionalFiles(testScript, copilotModel);

        // File path can be relative to the script file or absolute path 
        // If absolute path then check if the file exists
        // If relative path then check if the file exists in the same directory as the script

        missingFiles = additionalFiles.filter(file => !fs.existsSync(file) && !fs.existsSync(path.join(path.dirname(testScript), file)));

        return {
            missingVariables : missingVariables,
            missingFiles : missingFiles
        }
    }

    async isValidYAMLConfig(resp : {'missingVariables' : string[], 'missingFiles' : string[]}) : Promise<boolean> {
        
        if(resp.missingVariables.length > 0 || resp.missingFiles.length > 0){
            return false;
        }

        return true;
    }

    async selectMultiRegions(location: string, subscriptionId: string): Promise<string[] | null> {
        
        let supportedRegions = this._apiClient.getMultiRegionSupportedRegions();
        
        let pickedRegions = Object.keys(supportedRegions).filter((key) => key === location);
        if (location === 'eastus' && !pickedRegions.includes('westus2')) {
            pickedRegions.push('westus2');
        } else if (location === 'westus2' && !pickedRegions.includes('eastus')) {
            pickedRegions.push('eastus');
        }

        let nonPickedRegions = Object.keys(supportedRegions).filter((key) => !pickedRegions.includes(key));

        let reorderedRegions = pickedRegions.concat(nonPickedRegions);
        const allRegions = reorderedRegions.map((key) => ({
            label: supportedRegions[key],
            description: key,
            picked: pickedRegions.includes(key)
        }));
    
        const maxSelections = AzureLoadTesting.MAX_SUPPORTED_MULTI_REGIONS;
    
        while (true) {
            let selectedRegions = await vscode.window.showQuickPick(allRegions, {
                placeHolder: vscode.l10n.t(Messages.SelectRegion),
                ignoreFocusOut: true,
                canPickMany: true,
                onDidSelectItem: (item:any) => {
                    if (item.description === location) {
                        item.picked = true; // Ensure the pre-selected region remains selected
                    }
                }
            });
        
            if (!selectedRegions || selectedRegions.length === 0) {
                this._logger.info("No regions selected. Continue with resource location.");
                selectedRegions = [
                    {
                        label: supportedRegions[location],
                        description: location,
                        picked: true
                    }
                ]
            }
        
            let regions = selectedRegions.map(region => region.description);

            if (!regions.includes(location)) {
                this._logger.error(`"${location}" cannot be unchecked as it is the default resource region. Please select it.`);
                continue; // Restart the selection process
            }
    
            // Enforce the selection limit
            if (regions.length > maxSelections) {
                this._logger.error(formatString(ErrorMessages.MaxRegionSelection, maxSelections));
                return null;
            }
        
            return regions;
        }
    }

    public async SelectOrCreateLoadTestConfigFile(input?:LoadTestConfigInput|null): Promise<any> {
    
        let loadTestConfig : LoadTestYAMLConfig | null = null;
        let options : LoadTestConfigurationOptions | null = null;
        const configFiles = await vscode.workspace.findFiles(loadTestConfigSelectionPattern, excludeFoldersForSelectingConfig); 

        let quickPickItems : any[] = [];

        if(configFiles && configFiles.length > 0) {
            quickPickItems = configFiles.map(file => ({
                label: path.basename(file.fsPath),
                description: path.resolve(file.fsPath),
                iconPath: new vscode.ThemeIcon('file')
            }));
        }
        
        const selectedConfig = await vscode.window.showQuickPick([
            ...quickPickItems,
            { label: vscode.l10n.t(Messages.CreateConfigurationFile), description: "", iconPath: new vscode.ThemeIcon('new-file') },
            { label: vscode.l10n.t(Messages.Browse), description: "", iconPath: new vscode.ThemeIcon('folder') }
        ], {
            placeHolder: vscode.l10n.t(Messages.SelectConfigurationFile),
            ignoreFocusOut: true,
        });

        let yamlConfig = selectedConfig?.description;
            
        if(selectedConfig?.label == vscode.l10n.t(Messages.CreateConfigurationFile)){

            let selectedScript = await this._fileService.selectLoadTestScript();

            if (!selectedScript || selectedScript === "") {
                return;
            }

            this._logger.debug(`User selected script : ${getMaskedString(selectedScript)}`);

            let resourceDetails = null;
            if(input && input.dataPlaneURI && input.resourceId) {
                resourceDetails = {
                    dataPlaneURI: input.dataPlaneURI,
                    resourceId: input.resourceId,
                    location: input.resourceLocation,
                };
            }else{
                resourceDetails = await this._apiClient.selectAzureResourceDetails(input?.resourceId!);
            }
            
            if(resourceDetails == null){
                this._logger.debug("No resource details found to run in azure");
                return;
            }

            this._logger.debug(`User selected resource : ${resourceDetails?.dataPlaneURI}`);

            options  = {
                resourceId : resourceDetails?.resourceId,
            };
            
            await vscode.window.withProgress({
                location: vscode.ProgressLocation.Notification,
                title: vscode.l10n.t(Messages.CreatingALoadTestConfigurationFile),
                cancellable: false
            }, async (progress) => {

                let multiRegion = true; 
                if(input && input.multiRegion != null) {
                    multiRegion = input.multiRegion;
                }
                let config = await this.createYAMLConfig(selectedScript, {
                    ...input, 
                    resourceId: resourceDetails?.resourceId,
                    resourceLocation: resourceDetails?.location,
                    multiRegion: multiRegion,
                    copilotModel: input?.copilotModel ?? Copilot.DefaultModel,
                });
    
                if(config == null){
                    this._logger.debug(ErrorMessages.FailedToCreateConfigurationFile);
                    progress.report({ increment: 100 });
                    vscode.window.showErrorMessage(vscode.l10n.t(ErrorMessages.FailedToCreateConfigurationFile));
                    return null;
                }
                
                loadTestConfig = config.loadTestYAMLConfig;
                options!.dataPlaneURI = resourceDetails?.dataPlaneURI;
                options!.resourceId = resourceDetails?.resourceId;
                options!.yamlConfigFileName = config.filePath;
                yamlConfig = path.join(config.filePath!);

                progress.report({ increment: 100 });

                vscode.window.showInformationMessage(vscode.l10n.t(`${vscode.l10n.t(Messages.CreatedConfigurationFile)}`, {0 : `${path.basename(yamlConfig)}`}));
            });
            
        }else if (selectedConfig?.label === vscode.l10n.t(Messages.Browse)) {
                yamlConfig = await this._fileService.browseLoadTestConfigFile();
                if(!yamlConfig){
                    this._logger.error(ErrorMessages.SELECT_A_CONFIGURATION_FILE);
                    return;
                }
                
                this._logger.debug(`User selected configuration file : ${getMaskedString(yamlConfig)}`);
        
                let resp = await this.parseYAML(yamlConfig);
                        
                if(resp == null){
                    this._logger.debug(`Failed to parse yaml config`);
                    return;
                }else{
                    loadTestConfig = resp.loadTestConfig;
                    options = resp.options;
                }
        }else{
            // if file selected then parse the yaml file
            if (yamlConfig && fs.existsSync(yamlConfig)) {
                this._logger.debug(`User selected configuration file : ${getMaskedString(yamlConfig)}`);
                let resp = await this.parseYAML(yamlConfig);
                
                if(resp == null){
                    this._logger.debug(`Failed to parse yaml config`);
                    return;
                }else{
                    loadTestConfig = resp.loadTestConfig;
                    options = resp.options;
                }
            }else{
                this._logger.error(ErrorMessages.SELECT_A_CONFIGURATION_FILE);
                return;
            }
        }
        return {
            loadTestConfig, options
        };        
    }
}