import * as vscode from 'vscode';
import { Copilot } from '../../constants';
import { Logger } from '../../logger';
import { ErrorMessages } from '../../strings';
import { FindAdditionalFilesSystemPrompt, FindAdditionalFilesUserPrompt, FindEnvsAndSecretsSystemPrompt, FindEnvsAndSecretsUserPrompt } from './prompt';
import { TestType } from '../AzureLoadTesting/model';

export class CopilotService {

    private _logger = new Logger("CopilotService");

    constructor() {
    }

    public async executeCopilotPrompt(messages: any, copilotModel:string, retry = 3): Promise<any> {

        if (retry == 0) {
            this._logger.error(ErrorMessages.CopilotRetryLimitExcceeded, false);
            throw new Error(ErrorMessages.CopilotRetryLimitExcceeded);
        }

        const models = await vscode.lm.selectChatModels({
            vendor: 'copilot',
            family:copilotModel ? copilotModel : Copilot.DefaultModel,
        });

        if(models == undefined || models == null || models.length == 0){
            this._logger.debug(`Copilot model not found.`);
            return null;
        }

        let model = models[0];

        const system_prompt = messages[0].content;
        const user_prompt = messages[1].content;

        const x_messages = [
            vscode.LanguageModelChatMessage
                .User(system_prompt),
            vscode.LanguageModelChatMessage.User(user_prompt),
        ];
        let tokenUsages = 0;

        try {
            tokenUsages = (await model.countTokens(x_messages[0])) + (await model.countTokens(x_messages[1]));
        } catch (err) {
            this._logger.debug(`Error occured while counting tokens: ${err}`);
        }

        let chatResponse: any;

        let response = "";
        this._logger.debug(`The copilot model used is: ${model.id}, token usages: ${tokenUsages}, maxInputTokens: ${model.maxInputTokens}`);

        try {
            chatResponse = await model.sendRequest(
                x_messages,
                {},
                new vscode.CancellationTokenSource().token
            );

            for await (const fragment of chatResponse.text) {
                response += fragment;
            }

            return {
                'data': response,
                'token_usages': tokenUsages
            };
        } catch (err: any) {
            if (err.message && err.message.indexOf("rate limit exceeded") > -1) {
                this._logger.debug('Error occured while getting response from copilot: Error: rate limit exceeded retrying...');
            } else {
                this._logger.debug(`Error occured while getting response from copilot: ${err}`);
            }

            if (err instanceof vscode.LanguageModelError) {
                if(err.code == "NoPermissions"){
                    this._logger.debug(`Error occurred while executing copilot prompt: ${ErrorMessages.NoPermissions}`);
                }else if (err.cause instanceof Error && err.cause.message.includes('off_topic')) {
                    this._logger.error(ErrorMessages.UnableToExplained);
                }
                return null;
            }
            if (err.message && err.message.indexOf("rate limit exceeded") > -1) {
                await new Promise(resolve => setTimeout(resolve, 5000));
            } else {
                await new Promise(resolve => setTimeout(resolve, 2000));
            }
            return this.executeCopilotPrompt(messages, copilotModel, retry - 1);
        }
    }

    public async findEnvAndSecretsFromScript(script: string, copilotModel:string, loadTestType:TestType): Promise<{
        data: string;
        token_usages: number;
    } | null> {

        const messages = [
            {
                content: FindEnvsAndSecretsSystemPrompt
            },
            {
                content: FindEnvsAndSecretsUserPrompt(script, loadTestType),
            },
        ];

        return await this.executeCopilotPrompt(messages, copilotModel);
    }

    async findIfScriptNeedsAnyFiles(script: string, copilotModel:string): Promise<any> {

        // TODO : ask llm to find out local referanced python files in the script, CSV file 

        const messages = [
            {
                content: FindAdditionalFilesSystemPrompt,
            },
            {
                content: FindAdditionalFilesUserPrompt(script),
            },
        ];

        return await this.executeCopilotPrompt(messages, copilotModel);
    }

}