import * as path from 'path';
import * as vscode from 'vscode';
import { excludeFoldersForSelectingConfig, excludeFoldersForSelectingScript, loadTestConfigSelectionPattern, loadTestScriptSelectionPattern, VSCodeCommand } from '../../constants';
import { Logger } from "../../logger";
import { ErrorMessages, Messages } from '../../strings';
import { getNextFileName } from '../../util';
import * as fs from 'fs';
import { ErrorUtil } from '../../Utils/errorUtil';
import { updateEnvFile, updateRequirementsFile } from '../../Utils/fileUtil';


export class FileServiceHelper {

    private _logger : Logger;
    
    constructor() {
        this._logger = new Logger("FileServiceHelper");
    }

    public async selectLoadTestConfigFile(): Promise<string> {
        let loadTestConfigFile: string | undefined;
        const configFiles = await vscode.workspace.findFiles(loadTestConfigSelectionPattern, excludeFoldersForSelectingConfig);
            
        const quickPickItems = configFiles.map(file => ({
            label: path.basename(file.fsPath),
            description: path.resolve(file.fsPath)
        }));
    
        const selectedConfig = await vscode.window.showQuickPick([
            ...quickPickItems,
            { label: vscode.l10n.t(Messages.Browse), description: "" }
        ], {
            placeHolder: vscode.l10n.t(Messages.SelectConfigurationFile),
            ignoreFocusOut: true,
        });
        
        loadTestConfigFile = selectedConfig?.description;
    
        if (selectedConfig?.label === vscode.l10n.t(Messages.Browse)) {
            loadTestConfigFile = await this.browseLoadTestConfigFile();
        } 
    
        if(!loadTestConfigFile || loadTestConfigFile === ''){
            this._logger.error(ErrorMessages.SELECT_A_CONFIGURATION_FILE);
            return '';
        }
        return loadTestConfigFile;
    }


    public async browseLoadTestConfigFile(): Promise<string> {
        let label = Messages.LoadTestScript;
        let filters : {[key:string] :  any } = {}
        let filePath = '';
        filters[label] = ['yaml'];
        
        const fileUri = await vscode.window.showOpenDialog({
            canSelectMany: false,
            filters: filters,
        });

        if (fileUri && fileUri.length > 0) {
            filePath = fileUri[0].fsPath;
        }
        return filePath;
    }

    public async selectLoadTestScript(): Promise<string | undefined> {
        const specFiles = await vscode.workspace.findFiles(loadTestScriptSelectionPattern, excludeFoldersForSelectingScript, 10);

        const quickPickItems = specFiles.map(file => ({
            label: path.basename(file.fsPath),
            description: path.resolve(file.fsPath),
            iconPath: new vscode.ThemeIcon('file')
        }))
        .sort((a, b) => a.description.localeCompare(b.description));

        if(quickPickItems.length === 0) {
            quickPickItems.push({
                label: vscode.l10n.t(Messages.GenerateLoadTestScript),
                description: '',
                iconPath: new vscode.ThemeIcon('new-file')
            });
        }

        quickPickItems.push({
            label: vscode.l10n.t(Messages.PetStoreSample),
            description: '',
            iconPath: new vscode.ThemeIcon('file'),
        });

        // add browse option
        quickPickItems.push({
            label: vscode.l10n.t(Messages.Browse),
            description: '',
            iconPath: new vscode.ThemeIcon('folder'),
        });

        const selectedSpec = await vscode.window.showQuickPick(quickPickItems, {
            placeHolder: vscode.l10n.t(Messages.SelectALoadTestFile),
            ignoreFocusOut: true,
        });
        
        if(!selectedSpec) {
            ErrorUtil.showRequiredLoadTestScriptError();
            return;
        }
        
        if(selectedSpec?.label === vscode.l10n.t(Messages.GenerateLoadTestScript)) {
            this._logger.debug(`User selected generating new script`);
            vscode.commands.executeCommand(VSCodeCommand.CREATE_LOAD_TEST);
            return;
        }else if(selectedSpec?.label === vscode.l10n.t(Messages.PetStoreSample)) {
            let sampleScript = this.getPetStoreSampleLocustScript();
            let fileName = getNextFileName(vscode.workspace.workspaceFolders![0].uri.fsPath, 'petstore-locust', 'py');
            fs.writeFileSync(fileName, sampleScript);
            let envs = this.getPetStoreEnvs();
            updateEnvFile(envs, path.join(vscode.workspace.workspaceFolders![0].uri.fsPath, '.env'));
            let requirements = this.getPetStoreRequirements();
            let requirementsFileName = path.join(vscode.workspace.workspaceFolders![0].uri.fsPath, 'requirements.txt');
            updateRequirementsFile(requirements , requirementsFileName);
            vscode.window.showInformationMessage(vscode.l10n.t(Messages.ExportedPetStoreLocustScript, {0 : path.basename(fileName)}));
            return fileName;
        }else if(selectedSpec?.label === vscode.l10n.t(Messages.Browse)) {
            const fileUri = await this.browseFile(['py']);
            if (fileUri && fileUri.length > 0) {
                return fileUri;
            }else{
                ErrorUtil.showRequiredLoadTestScriptError();
                return;
            }
        }

        if(!selectedSpec) {
            ErrorUtil.showRequiredLoadTestScriptError();
            return;
        }

        return selectedSpec?.description || '';
    }

    public async browseFile(types:string[]): Promise<string> {
        let label = Messages.LoadInputFile;
        let filters : {[key:string] :  any } = {}
        let filePath = '';
        filters[label] = types;
        
        const fileUri = await vscode.window.showOpenDialog({
            canSelectMany: false,
            filters: filters,
        });

        if (fileUri && fileUri.length > 0) {
            filePath = fileUri[0].fsPath;
        }
        return filePath;
    }

    private getPetStoreEnvs() {
        return {
            "BASE_URL" : "https://petstore3.swagger.io/api/v3",
            "API_KEY" : "12345",
            "ENABLE_LOGGING" : "True"
        };
    }

    private getPetStoreRequirements(): string[] {
        return [
            "requests",
            "locust",
            "python-dotenv"
        ];
    }

    private getPetStoreSampleLocustScript(): string {
        return `import os
import uuid
import logging
from locust import HttpUser, task, between
from dotenv import load_dotenv

# Load environment variables from .env file
load_dotenv()

class ApiUser(HttpUser):
    wait_time = between(1, 3)
    host = os.getenv("BASE_URL", "https://petstore3.swagger.io/api/v3")
    timeout_duration = 90
    ENABLE_LOGGING = os.getenv('ENABLE_LOGGING', 'True') == 'True'
    api_key = os.getenv("API_KEY", "12345")
    pet_id = None  # To store the dynamically generated pet ID

    def on_start(self):
        """Executed when a user starts running the test."""
        logging.info("Starting test scenario...")

    @task
    def run_scenario(self):
        """Run the sequence of operations."""
        self.create_pet()
        self.get_pet()
        self.update_pet()
        self.delete_pet()

    def create_pet(self):
        """Create a new pet."""
        self.pet_id = str(uuid.uuid4().int % 1000000)  # Generate a unique pet ID
        url = f"{self.host}/pet"
        headers = {
            "Content-Type": "application/json",
            "Accept": "application/json",
            "api_key": self.api_key
        }
        payload = {
            "id": int(self.pet_id),
            "name": "Fluffy",
            "category": {"id": 1, "name": "Dogs"},
            "photoUrls": ["https://example.com/photo.jpg"],
            "tags": [{"id": 1, "name": "cute"}],
            "status": "available"
        }

        with self.client.post(
            url,
            headers=headers,
            json=payload,
            name="Create Pet",
            catch_response=True,
            timeout=self.timeout_duration
        ) as response:
            if response.status_code in [200, 201]:
                response.success()
                logging.info(f"Pet created successfully with ID: {self.pet_id}")
            else:
                response.failure(f"Failed to create pet: {response.status_code}, {response.text}")
                if self.ENABLE_LOGGING:
                    logging.error(f"Request URL: {url}, Headers: {headers}, Payload: {payload}")

    def get_pet(self):
        """Retrieve the newly created pet."""
        url = f"{self.host}/pet/{self.pet_id}"
        headers = {
            "Accept": "application/json",
            "api_key": self.api_key
        }

        with self.client.get(
            url,
            headers=headers,
            name="Get Pet",
            catch_response=True,
            timeout=self.timeout_duration
        ) as response:
            if response.status_code == 200:
                response.success()
                logging.info(f"Pet retrieved successfully: {response.text}")
            else:
                response.failure(f"Failed to retrieve pet: {response.status_code}, {response.text}")
                if self.ENABLE_LOGGING:
                    logging.error(f"Request URL: {url}, Headers: {headers}")

    def update_pet(self):
        """Update the pet."""
        url = f"{self.host}/pet"
        headers = {
            "Content-Type": "application/json",
            "Accept": "application/json",
            "api_key": self.api_key
        }
        payload = {
            "id": int(self.pet_id),
            "name": "UpdatedFluffy",
            "category": {"id": 1, "name": "Dogs"},
            "photoUrls": ["https://example.com/newphoto.jpg"],
            "tags": [{"id": 1, "name": "cute"}],
            "status": "sold"
        }

        with self.client.put(
            url,
            headers=headers,
            json=payload,
            name="Update Pet",
            catch_response=True,
            timeout=self.timeout_duration
        ) as response:
            if response.status_code in [200, 201]:
                response.success()
                logging.info(f"Pet updated successfully: {response.text}")
            else:
                response.failure(f"Failed to update pet: {response.status_code}, {response.text}")
                if self.ENABLE_LOGGING:
                    logging.error(f"Request URL: {url}, Headers: {headers}, Payload: {payload}")

    def delete_pet(self):
        """Delete the pet."""
        url = f"{self.host}/pet/{self.pet_id}"
        headers = {
            "Accept": "application/json",
            "api_key": self.api_key
        }

        with self.client.delete(
            url,
            headers=headers,
            name="Delete Pet",
            catch_response=True,
            timeout=self.timeout_duration
        ) as response:
            if response.status_code in [200, 204]:
                response.success()
                logging.info(f"Pet deleted successfully with ID: {self.pet_id}")
            else:
                response.failure(f"Failed to delete pet: {response.status_code}, {response.text}")
                if self.ENABLE_LOGGING:
                    logging.error(f"Request URL: {url}, Headers: {headers}")

    def on_stop(self):
        """Clean up resources if necessary."""
        logging.info("Test scenario completed.")`;
    }

    
}