import { randomUUID } from 'crypto';
import * as dotenv from 'dotenv';
import * as fs from 'fs'; // Import the fs module
import * as yaml from 'js-yaml';
import * as path from 'path';
import * as vscode from 'vscode';
import { AzureLoadTesting, ChatParticipant, VSCodeCommand } from '../../constants';
import { executeWithCorrelation } from '../../executeAysnc';
import { Logger } from '../../logger';
import { ErrorMessages, Messages } from '../../strings';
import { formatErrorMessage, formatStatusEnum, formatString, generateTestRunDisplayName, getTestKind, getTestType, isValidTestScript } from '../../util';
import { AsyncLocalStorageUtil } from '../../Utils/localStorageUtil';
import { getRootPath } from '../VsCodeAPI';
import { RestAPI } from './api';
import { AppComponent, LoadTestConfigurationOptions, LoadTestYAMLConfig, ReferenceIdentityKind, Test, TestKind, TestType } from './model';


export class AzureLoadTestingService {

    private _logger : Logger
    private _apiClient : RestAPI;

    constructor() {
        this._logger = new Logger("AzureLoadTestingService");
        this._apiClient = new RestAPI();
    }
    
    public generateLoadTestWithChatParticipant = async() => {

        this._logger.debug('Generating load test with chat participant');

        await executeWithCorrelation(VSCodeCommand.OPEN_CHAT_SIDEBAR, AsyncLocalStorageUtil.getCorrelationId());

        await executeWithCorrelation(VSCodeCommand.OPEN_CHAT, AsyncLocalStorageUtil.getCorrelationId(), `@${ChatParticipant.CHART_PARTICIPANT_ID} /${ChatParticipant.GENERATE_LOAD_TEST_COMMAND}`);
    }

    public async startLoadTest(loadTestConfig:LoadTestYAMLConfig, options:LoadTestConfigurationOptions): Promise<any> {
        
        let correlationId = AsyncLocalStorageUtil.getCorrelationId();

        let testPlan = loadTestConfig.testPlan;
        let dataPlaneURI = options.dataPlaneURI;

        this._logger.debug(`Starting load test for data plane URI : ${dataPlaneURI?.split(".")[0]}`);

        let rootPath = getRootPath();

        if(!testPlan){
            this._logger.error(ErrorMessages.NoTestScriptFound);
            return null;
        }

        let environmentVariables : {[key:string]:any} = loadTestConfig.env || {}; 
        let secrets : {[key:string]:any} = {};

        if(getTestType(testPlan) == TestType.Locust){
            // Calculate LOCUST_SPAWN_RATE based on LOCUST_USERS and LOCUST_RUN_TIME
            if (!environmentVariables["LOCUST_SPAWN_RATE"] || parseInt(environmentVariables["LOCUST_SPAWN_RATE"]) < 1) {
                const totalRunTime = parseInt(environmentVariables["LOCUST_RUN_TIME"]);
                const maxUsers = parseInt(environmentVariables["LOCUST_USERS"]);
                const rampUpTime = totalRunTime * 0.75; // 75% of the total run time
                const spawnRate = Math.ceil(maxUsers / rampUpTime);
                environmentVariables["LOCUST_SPAWN_RATE"] = spawnRate.toString();
            }
        }

        // add .env variables to secrets 
        if(rootPath !== null){
            // read .env file and get the values
            const envFilePath = path.join(rootPath, '.env');
            const envConfig = dotenv.config({ path: envFilePath });
            if(envConfig.parsed){
                for (const [key, value] of Object.entries(envConfig.parsed)) {
                    secrets[key] = {
                        value: value,
                        type: 'SECRET_VALUE',
                        name: key
                    }
                }
            }
        }
        
        const token = await RestAPI.getDataPlaneAccessToken();

        let TEST_ID = loadTestConfig.testId;

        let message = vscode.l10n.t(Messages.CreatingLoadTest);

        let isCreated = false;
        if(TEST_ID === null || TEST_ID === undefined || TEST_ID === "") {
            TEST_ID = randomUUID();
            loadTestConfig.testId = TEST_ID;
            isCreated = true;
        }else{
            message = vscode.l10n.t(Messages.UpdatingLoadTest);
        }

        this._logger.info(message);
        
        let testRun = null;

        Logger.vscodeOutputChannel.show();
        this._logger.info(`Creating load test for test plan : ${testPlan}`);
        
        await vscode.window.withProgress({
            location: vscode.ProgressLocation.Window,
            title: message,
            cancellable: false
        }, async (progress) => {
    
            this._logger.debug(`Creating load test with id : ${TEST_ID}`);
            
            let resp = await fetch(`${dataPlaneURI}/tests/${TEST_ID}?api-version=${AzureLoadTesting.DataPlaneAPIVersion}`, {
                headers : {
                    'Content-Type': AzureLoadTesting.ContentTypeJsonMergePatch,
                    'Authorization': `Bearer ${token}`,
                    'User-Agent': AzureLoadTesting.UserAgent,
                    'x-ms-client-request-id': correlationId,
                },
                method: "PATCH",
                body: JSON.stringify({
                    ...this.getTestFromLoadTestYAMLConfig(loadTestConfig, testPlan!),
                    "testId": TEST_ID
                }),
            });

            if (!resp.ok) {
                this._logger.error(`${ErrorMessages.FailedToCreateTest} : ${await formatErrorMessage(resp)}`);
                progress.report({ increment : 100});
                return;
            }else{
                this._logger.debug(`Load test ${isCreated ? 'created' : 'updated'} successfully with id : ${TEST_ID}`);
            }
            
            loadTestConfig.testId = TEST_ID;

            fs.writeFileSync(options.yamlConfigFileName!, yaml.dump(loadTestConfig));

            // Add app components if present in YAML config
            if (loadTestConfig.appComponents && loadTestConfig.appComponents.length > 0) {
                this._logger.debug(`Adding app components for test ${TEST_ID}`);
                await this.addAppComponents(TEST_ID, dataPlaneURI!, loadTestConfig.appComponents);
            }

            progress.report({ message: vscode.l10n.t(Messages.UploadingTestScriptAndArtifacts) });

            this._logger.debug(`Uploading test script for test id : ${TEST_ID}`);

            // upload test script 
            let fileUploadResp = await this.uploadArtifacts(path.dirname(path.resolve(options.yamlConfigFileName!)), loadTestConfig, dataPlaneURI, TEST_ID, progress);

            if(!fileUploadResp){
                progress.report({ increment : 100});
                return;
            }else{
                this._logger.debug(`Test script uploaded successfully for test id : ${TEST_ID}`);
            }

            let requiredSecrets = loadTestConfig.secrets != null ? loadTestConfig.secrets.map(s => s.name) : [];
        
            // remove secrets which are not needed 
            for (let key in secrets) {
                if (!requiredSecrets.includes(key)) {
                    delete secrets[key];
                }
            }

            // run load test 
            this._logger.info(vscode.l10n.t(Messages.RunningLoadTest));
            
            progress.report({message : vscode.l10n.t(Messages.RunningLoadTest)})

            let testRunId = randomUUID();
            
            this._logger.debug(`Starting test run with id : ${testRunId} for test id : ${TEST_ID}`);
            
            resp = await fetch(`${dataPlaneURI}/test-runs/${testRunId}?api-version=${AzureLoadTesting.DataPlaneAPIVersion}`, {
                headers : {
                    'Content-Type': AzureLoadTesting.ContentTypeJsonMergePatch,
                    'Authorization': `Bearer ${token}`,
                    'User-Agent': AzureLoadTesting.UserAgent,
                    'x-ms-client-request-id': correlationId,
                },
                method: "PATCH",
                body: JSON.stringify({
                    "testId":TEST_ID,
                    "secrets": secrets,
                    "displayName": generateTestRunDisplayName(),
                }),
            });

            if (!resp.ok) {
                this._logger.error(`${ErrorMessages.FailedToRunTest} : ${await formatErrorMessage(resp)}`);
                progress.report({ increment : 100});
                return;
            }else{
                this._logger.debug(`Test run started successfully with id : ${testRunId} for test id : ${TEST_ID}`);
            }

            testRun = await resp.json();
            
            if(testRun){
                let portalUrl = testRun.portalUrl;
                
                progress.report({ increment : 100});

                // Show information message with a button link
                vscode.window.showInformationMessage(
                    vscode.l10n.t(Messages.LoadTestRunStartedSuccessfully),
                    vscode.l10n.t(Messages.OpenInAzurePortal)
                ).then(async (result) => {
                    if (result === vscode.l10n.t(Messages.OpenInAzurePortal)) {
                        // Open the URL in the default web browser
                        vscode.env.openExternal(portalUrl);
                    }  
                });
                
                if(options.pollTestRun){
                    // async poll test run status
                    (() => {
                        this.pollTestRunStatus(testRunId, dataPlaneURI!, token);
                    })();
                }

            }
        });

        return testRun;
    }

    async addAppComponents(testId: string, dataPlaneURI: string, appComponents?: AppComponent[]) {
        let correlationId = AsyncLocalStorageUtil.getCorrelationId();
        
        if (!appComponents || appComponents.length === 0) {
            this._logger.debug(`No app components to add for test ${testId}`);
            return null;
        }

        const token = await RestAPI.getDataPlaneAccessToken();

        // create map for App components with resource Id as key 

        let appComponentMap : {[key:string] : AppComponent}= {};

        for (let appComponent of appComponents) {
            if(appComponent.resourceId){
                appComponentMap[appComponent.resourceId] = appComponent;
            }
        }

        let resp = await fetch(`${dataPlaneURI}/tests/${testId}/app-components?api-version=${AzureLoadTesting.DataPlaneAPIVersion}`, {
            headers : {
                'Content-Type': AzureLoadTesting.ContentTypeJsonMergePatch,
                'Authorization': `Bearer ${token}`,
                'User-Agent': AzureLoadTesting.UserAgent,
                'x-ms-client-request-id': correlationId,
            },
            method: "PATCH",
            body: JSON.stringify({
                "components" : appComponentMap,
                "testId" : testId
            }),
        });

        if (!resp.ok) {
            let error = await resp.json();
            this._logger.debug(formatString(ErrorMessages.FailedToConfigureAppComponents, await formatErrorMessage(resp)));
            return null;
        }

        let data = await resp.json();
        return data;
    }


    async reRunLoadTest(dataPlaneURI: string, test:Test) {
        let correlationId = AsyncLocalStorageUtil.getCorrelationId();

        let testRunId = randomUUID();

        const token = await RestAPI.getDataPlaneAccessToken();

        let resp = await fetch(`${dataPlaneURI}/test-runs/${testRunId}?api-version=${AzureLoadTesting.DataPlaneAPIVersion}`, {
            headers : {
                'Content-Type': AzureLoadTesting.ContentTypeJsonMergePatch,
                'Authorization': `Bearer ${token}`,
                'User-Agent': AzureLoadTesting.UserAgent,
                'x-ms-client-request-id': correlationId,
            },
            method: "PATCH",
            body: JSON.stringify(test),
        });

        if (!resp.ok) {
            this._logger.error(`${ErrorMessages.FailedToRunTest} : ${await formatErrorMessage(resp)}`);
            return null;
        }

        return resp.json();
    }

    private async uploadArtifacts(directoryPath: string, yamlConfig:LoadTestYAMLConfig, dataPlaneURI: string | undefined, TEST_ID: string, progress?: vscode.Progress<{ message?: string; increment?: number; }>) {
        
        let correlationId = AsyncLocalStorageUtil.getCorrelationId();

        let testScript = path.resolve(directoryPath, yamlConfig.testPlan);

        if (!testScript || !isValidTestScript(testScript)) {
            this._logger.error(ErrorMessages.LoadTestScriptNotFound);
            return null;
        }

        // read script content as string 
        let scriptContent = fs.readFileSync(testScript, 'utf8');


        const token = await RestAPI.getDataPlaneAccessToken();

        this._logger.info(Messages.UploadingAdditionalFiles);

        let rootPath = getRootPath();

        if(rootPath && getTestType(testScript) === TestType.Locust) {
            // upload requirements.txt file if exists
            let requirementsFile = path.join(rootPath, "requirements.txt");
            if(fs.existsSync(requirementsFile)) {

                let content = fs.readFileSync(requirementsFile);

                this._logger.info(Messages.UploadingRequirementsFile);
                progress?.report({ message: vscode.l10n.t(Messages.UploadingRequirementsFile) });

                let resp = await fetch(`${dataPlaneURI}/tests/${TEST_ID}/files/requirements.txt?fileType=ADDITIONAL_ARTIFACTS&api-version=${AzureLoadTesting.DataPlaneAPIVersion}`, {
                    headers: {
                        contentType: AzureLoadTesting.ContentTypeApplicationOctetStream,
                        Authorization: `Bearer ${token}`,
                        'User-Agent': AzureLoadTesting.UserAgent,
                        'x-ms-client-request-id': correlationId,
                    },
                    method: "PUT",
                    body: content
                });

                if (!resp.ok) {
                    this._logger.error(`${vscode.l10n.t(ErrorMessages.FailedToUploadRequirementsFile)} : ${await formatErrorMessage(resp)}`);
                    return null;
                }
            }
        }

        let additionalFiles = yamlConfig.configurationFiles || [];

        // remove .env & requirements.txt file from additional files
        additionalFiles = additionalFiles.filter((file:string) => file !== ".env" && file !== "requirements.txt");

        // upload additional files
        if(rootPath){
            for (let file of additionalFiles) {
    
                let absoluteFilePath = file;

                // check if path is absolute path
                if(fs.existsSync(file)){
                    absoluteFilePath = file;
                }else if(fs.existsSync(path.join(path.dirname(testScript), file))){
                    absoluteFilePath = path.join(path.dirname(testScript), file);
                }else{
                    this._logger.debug(`File not found : ${file} for testId : ${TEST_ID}`);
                    continue;
                }

                let fileType = "ADDITIONAL_ARTIFACTS";
    
                if(file.includes(".zip")){
                    fileType = "ZIPPED_ARTIFACTS";
                }
    
                if(file.includes(".properties")){
                    fileType = "USER_PROPERTIES";
                }
    
                let content = fs.readFileSync(absoluteFilePath);
    
                let resp = await fetch(`${dataPlaneURI}/tests/${TEST_ID}/files/${path.basename(absoluteFilePath)}?fileType=${fileType}&api-version=${AzureLoadTesting.DataPlaneAPIVersion}`, {
                    headers: {
                        contentType: AzureLoadTesting.ContentTypeApplicationOctetStream,
                        Authorization: `Bearer ${token}`,
                        'User-Agent': AzureLoadTesting.UserAgent,
                        'x-ms-client-request-id': correlationId,
                    },
                    method: "PUT",
                    body: content
                });
    
                if (!resp.ok) {
                    this._logger.error(`${ErrorMessages.FailedToUploadFile} ${file}, error  : ${await formatErrorMessage(resp)}`);
                    return;
                }
            }
        }
        

        // upload test script

        this._logger.info(Messages.UploadingTestScript);
        progress?.report({ message: vscode.l10n.t(Messages.UploadingTestScript) });

        let testScriptName = path.basename(testScript!);
        let fileType = "TEST_SCRIPT";

        let resp = await fetch(`${dataPlaneURI}/tests/${TEST_ID}/files/${testScriptName}?fileType=${fileType}&api-version=${AzureLoadTesting.DataPlaneAPIVersion}`, {
            headers: {
                contentType: AzureLoadTesting.ContentTypeApplicationOctetStream,
                Authorization: `Bearer ${token}`,
                'User-Agent': AzureLoadTesting.UserAgent,
                'x-ms-client-request-id': correlationId,
            },
            method: "PUT",
            body: Buffer.from(scriptContent, 'utf-8')
        });

        if (!resp.ok) {
            this._logger.error(`${ErrorMessages.FailedToUploadTestScript} : ${await formatErrorMessage(resp)}`);
            return null;
        }

        // check file upload status for max 2 minutes 
        let i = 0;
        let fileUploadStatus = false;

        this._logger.info(Messages.ValidatingTestScript);
        progress?.report({ message: vscode.l10n.t(Messages.ValidatingTestScript) });
        while (i < 24) {
            resp = await fetch(`${dataPlaneURI}/tests/${TEST_ID}/files/${testScriptName}?api-version=${AzureLoadTesting.DataPlaneAPIVersion}`, {
                headers: {
                    Authorization: `Bearer ${token}`,
                    'User-Agent': AzureLoadTesting.UserAgent,
                    'x-ms-client-request-id': correlationId,
                },
                method: "GET"
            });

            if (resp.ok) {
                let data = await resp.json();
                this._logger.debug(`Test script validation status: ${formatStatusEnum(data.validationStatus)}`);
                if( data.validationStatus === "VALIDATION_FAILURE") {
                    this._logger.error(`${ErrorMessages.FailedToUploadTestScript} : ${data.validationFailureDetails}`);
                    return null;
                }
                if (data.validationStatus === "VALIDATION_SUCCESS") {
                    fileUploadStatus = true;
                    break;
                }
            }
            i++;
            await new Promise(resolve => setTimeout(resolve, 5000));
        }

        if (!fileUploadStatus) {
            this._logger.error(`${ErrorMessages.FailedToUploadTestScript} : ${await formatErrorMessage(resp)}`);
            return null;
        }

        return resp;
    }

    async pollTestRunStatus(testRunId: string, dataPlaneURI: string, token:string): Promise<any> {
        // poll test run status and show the result for 5 minutes

        let correlationId = AsyncLocalStorageUtil.getCorrelationId();
        
        this._logger.info(`Polling test run status for test run id : ${testRunId}`);
        let count = 0;
        let maxCount = 60; // 5 minutes
        let testRunFinished = false;
        let portalUrl = "";
        while(true && count < maxCount) {
            count++;
            let resp = await fetch(`${dataPlaneURI}/test-runs/${testRunId}?api-version=${AzureLoadTesting.DataPlaneAPIVersion}`, {
                headers : {
                    Authorization: `Bearer ${token}`,
                    'User-Agent': AzureLoadTesting.UserAgent,
                    'x-ms-client-request-id': correlationId,
                },
                method: "GET"
            });

            if (!resp.ok) {
                this._logger.debug(formatString(ErrorMessages.FailedToGetTestRunStatus, testRunId, resp.statusText));
                return;
            }

            let data = await resp.json();

            if(AzureLoadTesting.LoadTestTerminalStates.indexOf(data.status) > -1) {
                if(data.errorDetails && data.errorDetails.length > 0) {
                    this._logger.error(`Test run failed : ${data.errorDetails[0].message}`);
                }else if(data.status === "DONE"){
                    this._logger.info(`Test run completed successfully.`);
                }else {
                    this._logger.info(`Test run finished with status: ${formatStatusEnum(data.status)}`);
                }
                testRunFinished = true;
                portalUrl = data.portalUrl;
                break;
            }else{
                this._logger.info(`Test run status: ${formatStatusEnum(data.status)}`);
            }

            await new Promise(resolve => setTimeout(resolve, 5000));
        }

        if(!testRunFinished){
            this._logger.info(formatString(Messages.TestRunProgressUpdate, portalUrl ?? ""));
        }
    }

    getTestFromLoadTestYAMLConfig(loadTestConfig: LoadTestYAMLConfig, testScript:string): Test | null {
        let TEST_NAME = "";
        let displayName = "";
        let engineInstances = 1;
        let regionalLoadTestConfig = null;
        let description = `${getTestType(testScript)} load test`;
        let virtualUsers = AzureLoadTesting.DefaultVUs;
        let duration = AzureLoadTesting.DefaultDuration;

        let TEST_ID = loadTestConfig.testId;

        TEST_NAME = path.basename(path.dirname(path.dirname(testScript!)));
        displayName = loadTestConfig.displayName || `${TEST_NAME}_LoadTest`;
        description = loadTestConfig.description || description;

        if (loadTestConfig.regionalLoadTestConfig != null) {
            regionalLoadTestConfig = loadTestConfig.regionalLoadTestConfig;
        }
        
        let environmentVariables : {[key : string] : string} = {};

        const envs = loadTestConfig.env || [];
        
        for (const envVar of envs) {
            environmentVariables[envVar.name] = envVar.value;

            // checking if env variables has locust user and duration handled with try catch
            if (envVar.name === "LOCUST_USERS") {
                try {
                    virtualUsers = parseInt(envVar.value);
                } catch (e) {
                    this._logger.error(`Invalid value for LOCUST_USERS: ${envVar.value}`);
                }
            }
            if (envVar.name === "LOCUST_RUN_TIME") {
                try {
                    duration = parseInt(envVar.value);
                } catch (e) {
                    this._logger.error(`Invalid value for LOCUST_RUN_TIME: ${envVar.value}`);
                }
            }
        }

        engineInstances = loadTestConfig.engineInstances || regionalLoadTestConfig?.length || engineInstances;

        let test: Test = {
            displayName : displayName,
            description : description,
            loadTestConfiguration : {
                engineInstances : engineInstances,
                splitAllCSVs : false,
                regionalLoadTestConfig : regionalLoadTestConfig,
            },
            environmentVariables : environmentVariables,
            kind : getTestKind(testScript),
            testId : TEST_ID,
        };

        if (loadTestConfig.referenceIdentities && loadTestConfig.referenceIdentities.length > 0) {
            loadTestConfig.referenceIdentities.forEach((identity) => {
                if (identity.kind === ReferenceIdentityKind.Metrics){
                    test.metricsReferenceIdentityId = identity.value;
                    test.metricsReferenceIdentityType = identity.type;
                }else if (identity.kind === ReferenceIdentityKind.KeyVault) {
                    test.keyvaultReferenceIdentityId = identity.value;
                    test.keyvaultReferenceIdentityType = identity.type;
                }else if (identity.kind === ReferenceIdentityKind.Engine) {
                    if( !test.engineBuiltinIdentityIds) {
                        test.engineBuiltinIdentityIds = [];
                    }
                    test.engineBuiltinIdentityIds.push(identity.value!);
                    test.engineBuiltinIdentityType = identity.type;
                }
            });
        }
        return test;
    }
}