import * as fs from 'fs';

export function validateInputFile(fileToGenerate: string | undefined) {
    if (!fileToGenerate || (fileToGenerate && !fileToGenerate.endsWith('.json') && !fileToGenerate.endsWith('.http'))) {
        return false;
    }

    if(!fs.existsSync(fileToGenerate)){
        return false;
    }
    return true;
}