import { v4 as uuidv4 } from 'uuid';
import * as vscode from 'vscode';
import { Links, VSCodeCommand } from './constants';
import { Logger } from './logger';
import { UserState } from './Services/AzureLoadTesting/model';
import { GitHubService } from './Services/GitHub';
import { ErrorMessages } from './strings';
import { AsyncLocalStorageUtil } from './Utils/localStorageUtil';

const logger  = new Logger("ExecuteAsync");

const githubService = new GitHubService();

export async function executeWithCorrelation<T>(command: string, correlationId: string |  undefined, ...args: any[]): Promise<T> {

    if (!correlationId) {
        correlationId = uuidv4();
    }

    /**
     * Check if we are initiating github copilot chat and no github account loggedin
     */
    if(command == VSCodeCommand.OPEN_CHAT){
        

        let userState = await githubService.getUserState();

        if(userState == UserState.NoGitHubAccount){
            logger.debug("No github account found");
            
            vscode.window.showWarningMessage(
                vscode.l10n.t(ErrorMessages.GithubAccountNotLoggedIn),
                vscode.l10n.t(ErrorMessages.OpenQuickstartGuide) // Button label
            )
            .then((selection) => {
                if (selection == vscode.l10n.t(ErrorMessages.OpenQuickstartGuide)) {
                    vscode.env.openExternal(vscode.Uri.parse(Links.QuickStartGuide));
                }
            });
            return new Promise<T>((resolve, reject) => {});
        }else if(userState == UserState.CopilotNotEnabled){
            let accountName = await githubService.getGitHubAccountName() || "";
            logger.debug(`User state ${userState}, copilot not enabled`);
            vscode.window.showWarningMessage(
                vscode.l10n.t(ErrorMessages.NoAccessToGitHubCopilot, accountName),
                vscode.l10n.t(ErrorMessages.SignUpForGitHubCopilot) // Button label
            )
            .then((selection) => {
                if (selection == vscode.l10n.t(ErrorMessages.SignUpForGitHubCopilot)) {
                    vscode.env.openExternal(vscode.Uri.parse(Links.EnableCopilotInGithub));
                }
            });
            return new Promise((resolve) => {});
        }
    }

    // Wrap the thenable in a new Promise that re‑establishes the corresponding async context.
    return new Promise<T>((resolve, reject) => {
        AsyncLocalStorageUtil.getLocalContext().run({ correlationId }, () => {
            vscode.commands.executeCommand<T>(command, ...args).then(resolve, reject);
        });
    });
}