import * as fs from 'fs';
import * as vscode from 'vscode';
import { validateLoadTestScript } from '../../../util';
/**
 * In memory context to maintain the latest load test configuration files and other setting 
 * TODO : // need to add more settings and handler for workspace level configurations 
 */
export class ALTContext {
        
    private static _latestLoadScriptPath: string = '';

    private static _latestLoadTestConfigPath : string = '';

    private static _latestAzureLoadTestRunId : string = '';

    private static _latestAzureLoadTestResourceId : string = '';

    private static _latestLoadTestInputFilePath : string = '';

    private static _latestContext? : vscode.ExtensionContext;

    static getLoadTestScript(readFromCache=true){
        
        // check if there is a active python file in editor

        const activeEditor = vscode.window.activeTextEditor;
        let fileToGenerate: string | undefined; 
        
        if (activeEditor) {
            fileToGenerate = activeEditor.document.fileName;
        } 
        
        if(validateLoadTestScript(fileToGenerate)){
            return fileToGenerate;
        }

        if(this._latestLoadScriptPath && fs.existsSync(this._latestLoadScriptPath) && readFromCache){
            return this._latestLoadScriptPath;
        }
    }

    static getLoadTestInputFile(readFromCache:boolean=true){
        
        // check if there is a active python file in editor
        const activeEditor = vscode.window.activeTextEditor;
        let fileToGenerate: string | undefined;
        
        if (activeEditor) {
            fileToGenerate = activeEditor.document.fileName;
        } 
        
        if(fileToGenerate && (fileToGenerate.endsWith('.json') || fileToGenerate.endsWith('.http'))){
            return fileToGenerate;
        }

        if(this._latestLoadTestInputFilePath && fs.existsSync(this._latestLoadTestInputFilePath) && readFromCache){
            return this._latestLoadTestInputFilePath;
        }
    }

    static getLoadTestConfig(readFromCache:boolean=true){
        const activeEditor = vscode.window.activeTextEditor;
                    
        let fileToGenerate: string | undefined;
        
        if (activeEditor) {
            fileToGenerate = activeEditor.document.fileName;
        } 

        if(fileToGenerate && (fileToGenerate.endsWith('.yaml') || fileToGenerate.endsWith('.yml'))){
            return fileToGenerate;
        }

        if(this._latestLoadTestConfigPath && fs.existsSync(this._latestLoadTestConfigPath) && readFromCache){
            return this._latestLoadTestConfigPath;
        }
    }


    static setLatestLoadTestScriptPath(loadTestScriptPath: string){
        this._latestLoadScriptPath = loadTestScriptPath;
    }

    static setLatestLoadTestConfigPath(loadTestConfigPath: string){
        this._latestLoadTestConfigPath = loadTestConfigPath;
    }

    static setLatestAzureLoadTestRunId(azureLoadTestRunId: string){
        this._latestAzureLoadTestRunId = azureLoadTestRunId;
    }

    static setLatestAzureLoadTestResourceId(azureLoadTestResourceId: string){
        this._latestAzureLoadTestResourceId = azureLoadTestResourceId;
    }

    static setLatestContext(context: vscode.ExtensionContext){
        this._latestContext = context;
    }

    static setLatestLoadTestInputFilePath(loadTestInputFilePath: string){
        this._latestLoadTestInputFilePath = loadTestInputFilePath;
    }

}