import * as vscode from 'vscode';
import TelemetryReporter from '@vscode/extension-telemetry';
import { ErrorMessages } from './strings';

// telemetry reporter
export class TestingTelemetryReport implements vscode.Disposable {
    private static reporter: TelemetryReporter;

    constructor(context: vscode.ExtensionContext) {
        const { aiKey } = context.extension.packageJSON as { aiKey: string };
        TestingTelemetryReport.reporter = new TelemetryReporter(aiKey);
    }

    public static getInstance(): TelemetryReporter {
        if(!this.reporter) {
            throw new Error(vscode.l10n.t(ErrorMessages.TelemetryReporterNotInitialized));
        }

        return this.reporter;
    }

    public dispose(): void {
        TestingTelemetryReport.reporter.dispose();
    }
}
