import { ChatCommandHandler } from "../../handler";
import * as vscode from 'vscode';
import * as yaml from 'js-yaml';
import * as fs from 'fs';
import * as path from 'path';
import { LoadTestYAMLConfig } from "../../../Services/AzureLoadTesting/model";
import { GenerateAEnvFileUserPrompt, GeneratingLoadTestScriptSystemPrompt } from "../Prompts";
import { ALTContext } from "../Context";

export class SetupEnvFileHandler extends ChatCommandHandler {
    
    async handle(request: vscode.ChatRequest, context: vscode.ChatContext, stream: vscode.ChatResponseStream, token: vscode.CancellationToken){
        
        if (!this.isWorkspaceOpen(stream)) {
            return false;
        }

        let loadTestConfigFile: string | undefined = ALTContext.getLoadTestConfig();
        let configFileName = '';

        if(!loadTestConfigFile){
            loadTestConfigFile = await this._fileService.selectLoadTestConfigFile();

            if (!loadTestConfigFile || loadTestConfigFile === "") {
                return false;
            }
        }

        configFileName = path.basename(loadTestConfigFile);
        let yamlConfig = yaml.load(fs.readFileSync(loadTestConfigFile, 'utf8')) as LoadTestYAMLConfig;
        let secrets = yamlConfig.secrets?.map(secret => secret.name) ?? [];

        let scriptPath = path.resolve(path.dirname(loadTestConfigFile), yamlConfig.testPlan?? '');
        let scriptContent = fs.readFileSync(scriptPath, 'utf8');

        let inputFilePath = ALTContext.getLoadTestInputFile();
        let inputFileContent = '';
        if (inputFilePath) {
            inputFileContent = fs.readFileSync(inputFilePath, 'utf8');
        }

        const document = await vscode.workspace.openTextDocument(loadTestConfigFile);
        await vscode.window.showTextDocument(document);

        const envMessages = [
            vscode.LanguageModelChatMessage.Assistant(GeneratingLoadTestScriptSystemPrompt),
            vscode.LanguageModelChatMessage.User(GenerateAEnvFileUserPrompt(secrets, JSON.stringify(yamlConfig), scriptContent, inputFileContent))
        ];
        const envChatResponse = await request.model.sendRequest(envMessages, {}, token);
        
        for await (const fragment of envChatResponse.text) {
            stream.markdown(fragment);
        }    

        return true;
    }
}

