import { Messages } from "../../strings";
import * as vscode from "vscode";
import { Logger } from "../../logger";
import { CopilotService } from "../Copilot";
import { TestScriptHelper } from "./testScript";
import { RestAPI } from "./api";
import { formatErrorMessage } from "../../util";
import { AzureLoadTesting, MetricsReaderRoleId } from "../../constants";
import { randomUUID } from "crypto";
import { AppComponent } from "./model";

export class AIInsightsService {
    private _logger = new Logger("AIInsightsService");
    private _copilotService: CopilotService;
    private _testScriptHelper: TestScriptHelper;
    private _apiClient: RestAPI = new RestAPI();

    constructor() {
        this._copilotService = new CopilotService();
        this._testScriptHelper = new TestScriptHelper();
    }

    /**
     * Prompts user to enable AI Insights,
     * Enable system assigned identity and ensures it has metrics reader access.
     * Updates the test object in the YAML config accordingly.
     * @param resourceId The Azure Load Testing resourceId (for role assignment)
     * @param testObj The test object to update (mutated in place)
     * @returns The selected managed identity object or null if not enabled
     */
    async enableServerSideMonitoring(resourceId: string, testObj: any): Promise<any | null> {
        // 1. Ask user if they want to enable AI Insights
        const enable = await vscode.window.showQuickPick([
            { label: Messages.EnableServerSideMonitoringYes, value: true },
            { label: Messages.EnableServerSideMonitoringNo, value: false }
        ], {
            placeHolder: Messages.EnableServerSideMonitoring,
            ignoreFocusOut: true
        });

        if (!enable || !enable.value) {
            return null;
        }

        let appComponents : AppComponent[] = [];
        let selectedResourceGroup = "";
        // 2. Ask for server side selectResourcesByResourceGroup
        try {
            const subscriptionId = resourceId.split("/")[2];
            const data = await this._apiClient.selectResourcesByResourceGroup(subscriptionId);
            if (data) {
                let {resourceGroupName, resources} = data;
                if(resources && Object.keys(resources).length > 0){
                    appComponents = Object.values(resources).map((r: any) => ({
                        resourceId: r.id,
                        resourceName: r.name,
                        resourceType: r.type,
                        resourceGroup: r.resourceGroup,
                        subscriptionId: subscriptionId,
                        ...(r.kind ? { kind: r.kind } : {}),
                    }));
                }
                selectedResourceGroup = resourceGroupName;
            }
        } catch (e) {
            this._logger.error("Failed to select app components: " + (e as Error).message);
        }

        // 3. Check if system-assigned identity is already enabled and has Metrics Reader role
        let identity : {
            principalId: string;
            resourceId: string;
        } | null = null;

        let existingSystemIdentity = null;
        try {
            const session = await RestAPI.getSession();
            const getResp = await fetch(
                `https://management.azure.com${resourceId}?api-version=${AzureLoadTesting.ControlPlaneApiVersion}`,
                {
                    headers: {
                        'Authorization': `Bearer ${session?.accessToken}`,
                        'Content-Type': 'application/json',
                    }
                }
            );
            if (getResp.ok) {
                const resourceData = await getResp.json();
                const sysIdentityEnabled = resourceData.identity && resourceData.identity.type && resourceData.identity.type.toLowerCase().includes('systemassigned');
                const principalId = resourceData.identity?.principalId;
                if (sysIdentityEnabled && principalId) {
                    existingSystemIdentity = principalId;
                    this._logger.debug(`System-assigned identity already enabled: ${principalId}`);
                    // Check if Metrics Reader role is already assigned at resource group level
                    let subscriptionId = resourceId.split('/')[2];
                    const resourceGroup = resourceId.split('/')[4];
                    const roleAssignmentsUrl = `https://management.azure.com/subscriptions/${subscriptionId}/resourceGroups/${resourceGroup}/providers/Microsoft.Authorization/roleAssignments?api-version=2022-04-01&$filter=assignedTo('${principalId}')`;
                    const roleResp = await fetch(roleAssignmentsUrl, {
                        headers: {
                            'Authorization': `Bearer ${session?.accessToken}`
                        }
                    });
                    if (roleResp.ok) {
                        const roleData = await roleResp.json();

                        // resource group scope
                        const metricsReaderRoleId = `/subscriptions/${resourceId.split('/')[2]}/resourceGroups/${selectedResourceGroup}/providers/Microsoft.Authorization/roleDefinitions/${MetricsReaderRoleId}`;
                        // parent subscription scope
                        const subscriptionMetricsReaderRoleId = `/subscriptions/${resourceId.split('/')[2]}/providers/Microsoft.Authorization/roleDefinitions/${MetricsReaderRoleId}`;
                        const hasMetricsReader = (roleData.value || []).some((r: any) => r.properties?.roleDefinitionId?.toLowerCase() === metricsReaderRoleId.toLowerCase());
                        const hasSubscriptionMetricsReader = (roleData.value || []).some((r: any) => r.properties?.roleDefinitionId?.toLowerCase() === subscriptionMetricsReaderRoleId.toLowerCase());
                        if (hasMetricsReader || hasSubscriptionMetricsReader) {
                            this._logger.debug(`System-assigned identity already has Metrics Reader role: ${principalId}`);
                            identity = { principalId, resourceId };
                        }
                    }else{
                        this._logger.debug(`Failed to fetch role assignments for system identity. ${await formatErrorMessage(roleResp)}`);
                    }
                }
            }
        } catch (e) {
            this._logger.debug('Failed to check existing system identity and roles: ' + (e as Error).message);
        }

        // 4. If not already assigned, assign system identity and role
        if (!identity) {
            identity = await this.assignSystemIdentityAndRole(resourceId, existingSystemIdentity, selectedResourceGroup);
        }

        return {identity, appComponents};
    }

    // ARM implementation: Assigns system-assigned identity and role, returns identity object
    private async assignSystemIdentityAndRole(resourceId: string, systemIdentity:string, resourceGroup:string): Promise<any> {
        return await vscode.window.withProgress({
            location: vscode.ProgressLocation.Window,
            title: Messages.AssigningSystemIdentity,
            cancellable: false
        }, async (progress) => {
            
            const session = await RestAPI.getSession();
            let identityCreated = false;
            if(!systemIdentity){
                this._logger.debug('System-assigned identity not enabled, enabling now...');

                // 1. Fetch current resource to get existing identities
                let resourceData;
                try {
                    const getResp = await fetch(
                        `https://management.azure.com${resourceId}?api-version=${AzureLoadTesting.ControlPlaneApiVersion}`,
                        {
                            headers: {
                                'Authorization': `Bearer ${session?.accessToken}`,
                            }
                        }
                    );
                    if (!getResp.ok) {
                        this._logger.error(`Failed to fetch resource for system identity update, error ${await formatErrorMessage(getResp)}`);
                        return null;
                    }
                    resourceData = await getResp.json();
                } catch (e) {
                    this._logger.error((e as Error).message);
                    return null;
                }
                // 2. Prepare PATCH body with both system and any existing user-assigned identities
                let patchIdentity: any = { type: 'systemassigned' };
                const existingUserAssigned = resourceData.identity?.userAssignedIdentities;
                if (existingUserAssigned && Object.keys(existingUserAssigned).length > 0) {
                    patchIdentity.type = 'systemassigned,userassigned';
                    patchIdentity.userAssignedIdentities = existingUserAssigned;
                }
                // 3. PATCH to enable system-assigned identity (and preserve user-assigned)
                let patchResp;
                try {
                    patchResp = await fetch(
                        `https://management.azure.com${resourceId}?api-version=${AzureLoadTesting.ControlPlaneApiVersion}`,
                        {
                            method: 'PATCH',
                            headers: {
                                'Authorization': `Bearer ${session?.accessToken}`,
                                'Content-Type': 'application/json',
                            },
                            body: JSON.stringify({ identity: patchIdentity })
                        }
                    );
                    identityCreated = true;
                } catch (e) {
                    this._logger.error('Failed to send PATCH request for system identity. ' + (e as Error).message);
                    return null;
                }
                // 4. Handle long-running operation (202 Accepted)
                let finalResourceData = null;
                if (patchResp.status === 202) {
                    const asyncUrl = patchResp.headers.get('Azure-AsyncOperation') || patchResp.headers.get('Location');
                    if (asyncUrl) {
                        let status = '';
                        for (let i = 0; i < 30; i++) { // up to ~150s
                            progress.report({ message: `Waiting for identity assignment... (${i * 5}s)` });
                            await new Promise(res => setTimeout(res, 5000));
                            const pollResp = await fetch(asyncUrl, {
                                headers: {
                                    'Authorization': `Bearer ${session?.accessToken}`,
                                }
                            });
                            if (!pollResp.ok) break;
                            const pollData = await pollResp.json();
                            status = pollData.status || pollData.provisioningState;
                            if (status && (status.toLowerCase() === 'succeeded' || status.toLowerCase() === 'success')) {
                                break;
                            }
                            if (status && (status.toLowerCase() === 'failed' || status.toLowerCase() === 'canceled')) {
                                this._logger.error(`Enabling system-assigned identity failed: ${JSON.stringify(pollData)}`);
                                return null;
                            }
                        }
                        // After success, fetch the updated resource
                        const finalResp = await fetch(
                            `https://management.azure.com${resourceId}?api-version=${AzureLoadTesting.ControlPlaneApiVersion}`,
                            {
                                headers: {
                                    'Authorization': `Bearer ${session?.accessToken}`,
                                }
                            }
                        );
                        if (!finalResp.ok) {
                            this._logger.error(`Failed to fetch updated resource after identity assignment. ${await formatErrorMessage(finalResp)}`);
                            return null;
                        }
                        finalResourceData = await finalResp.json();
                    } else {
                        this._logger.error('PATCH returned 202 but no polling URL found in headers.');
                        return null;
                    }
                } else if (patchResp.ok) {
                    finalResourceData = await patchResp.json();
                } else {
                    this._logger.error(`Failed to enable system-assigned managed identity. ${await formatErrorMessage(patchResp)}`);
                    return null;
                }
                systemIdentity = finalResourceData.identity?.principalId;
            }
            
            // 5. Assign Metrics Reader and Contributor roles
            if(systemIdentity){
                (async(identityCreated:boolean) => {
                    if(identityCreated){
                        // delay for 10 more seconds to ensure the identity is fully provisioned and replicated 
                        this._logger.debug('Waiting for 10 seconds to ensure identity is fully provisioned...');
                        await new Promise(res => setTimeout(res, 10000));
                    }
                    this._logger.debug(`Assigning Metrics Reader role to system identity ${systemIdentity} at resource group level...`);
                    let assigned = await this.assignRoleToIdentity(resourceId, systemIdentity, resourceGroup);
                    if (!assigned) {
                        this._logger.error(`Failed to assign metrics reader role to system-assigned identity: ${systemIdentity}`);
                        return null;
                    }
                })(identityCreated);
                return { systemIdentity, resourceId };
            }
            return null;
        });
    }

    // ARM implementation: Fetches all user-assigned managed identities in the resource group
    private async getUserAssignedManagedIdentities(resourceId: string): Promise<any[]> {
        // Extract subscription and resource group from resourceId
        const parts = resourceId.split('/');
        const subscriptionId = parts[2];
        const resourceGroup = parts[4];
        const session = await RestAPI.getSession();
        const url = `https://management.azure.com/subscriptions/${subscriptionId}/resourceGroups/${resourceGroup}/providers/Microsoft.ManagedIdentity/userAssignedIdentities?api-version=2023-01-31`;
        const resp = await fetch(url, {
            headers: {
                'Authorization': `Bearer ${session?.accessToken}`,
                'Content-Type': 'application/json',
            }
        });
        if (!resp.ok) {
            this._logger.error(`Failed to fetch user-assigned managed identities. ${await formatErrorMessage(resp)}`);
            return [];
        }
        
        const data = await resp.json();
        
        return (data.value || []).map((id: any) => ({
            name: id.name,
            clientId: id.properties.clientId,
            principalId: id.properties.principalId,
            resourceId: id.id
        }));
    }

    // ARM implementation: Assigns Metrics Reader and Contributor roles to the selected identity at the resource group level
    private async assignRoleToIdentity(resourceId: string, principalId: string, resourceGroup: string): Promise<boolean> {
        const session = await RestAPI.getSession();
        // Extract subscriptionId from resourceId
        const parts = resourceId.split('/');
        const subscriptionId = parts[2];
        // Metrics Reader built-in role definitionId
        const roleDefinitionId = `/subscriptions/${subscriptionId}/resourceGroups/${resourceGroup}/providers/Microsoft.Authorization/roleDefinitions/${MetricsReaderRoleId}`;
        // Assign at resource group scope
        const url = `https://management.azure.com/subscriptions/${subscriptionId}/resourceGroups/${resourceGroup}/providers/Microsoft.Authorization/roleAssignments/`;
        const maxRetries = 10;
        const retryDelayMs = 10000; // 10 seconds
        let attempt = 0;
        while (attempt < maxRetries) {
            const assignmentName = randomUUID();
            const fullUrl = `${url}${assignmentName}?api-version=2022-04-01`;
            const body = {
                properties: {
                    roleDefinitionId,
                    principalId: principalId,
                    principalType: "ServicePrincipal"
                }
            };
            const resp = await fetch(fullUrl, {
                method: 'PUT',
                headers: {
                    'Authorization': `Bearer ${session?.accessToken}`,
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify(body)
            });
            if (!resp.ok) {
                let error = await resp.json();
                this._logger.debug(`Failed to assign role: ${roleDefinitionId} to identity ${principalId} at resource group level. Response: ${JSON.stringify(error)}`);
                if (error && error.error && error.error.code) {
                    if (error.error.code === "RoleAssignmentExists") {
                        this._logger.debug(`Role assignment already exists for identity ${principalId} at resource group level.`);
                        return true;
                    } else if (error.error.code === "PrincipalNotFound") {
                        this._logger.warning(`Principal not found. Retrying in ${retryDelayMs / 1000} seconds... (attempt ${attempt + 1}/${maxRetries})`);
                        await new Promise(res => setTimeout(res, retryDelayMs));
                        attempt++;
                        continue;
                    }
                }
                this._logger.error(`Failed to assign role: ${roleDefinitionId} to identity ${principalId} at resource group level. ${await formatErrorMessage(resp)}`);
                return false;
            } else {
                this._logger.debug(`Successfully assigned role: ${roleDefinitionId} to identity ${principalId} at resource group level.`);
                return true;
            }
        }
        this._logger.error(`Failed to assign role after ${maxRetries} attempts due to PrincipalNotFound.`);
        return false;
    }
}