    createResourceGroup = async (subscriptionId: string, resourceGroupName: string, location: string): Promise<any> => {
        let session = await RestAPI.getSession();

        let response = await fetch(`${AzureLoadTesting.ARMEndpoint}/subscriptions/${subscriptionId}/resourcegroups/${resourceGroupName}?api-version=${AzureLoadTesting.ControlPlaneApiVersion}`, {
            headers: {
                'Authorization': `Bearer ${session!.accessToken}`,
                'Content-Type': AzureLoadTesting.ContentTypeApplicationJson,
                'User-Agent': AzureLoadTesting.UserAgent,
                'x-ms-client-request-id': AsyncLocalStorageUtil.getCorrelationId(),
            },
            body: JSON.stringify({
                location: location,
            }),
            method: 'PUT'
        });

        if (!response.ok) {
            if (response.status === 409) {
                RestAPI._logger.error(formatString(ErrorMessages.ResourceGroupAlreadyExists, resourceGroupName));
            }else{
                RestAPI._logger.error(formatString(ErrorMessages.FailedToCreateResourceGroup, response.statusText));
            }
            return null;
        }

        const data = await response.json();
        return data;
    }

