import * as vscode from 'vscode';
import { TestingTelemetryReport } from './telemetryReporter';
import { ExtensionName, ExtensionPublisher } from './constants';
import { AsyncLocalStorageUtil } from './Utils/localStorageUtil';


// TODO need to check more things on log formatting 
export const TelemeryLogger : vscode.TelemetryLogger = vscode.env.createTelemetryLogger({
    sendEventData(eventName, data:any) {
        
        // remove extension name from then event name as it is already added by the reporter
        if (eventName.startsWith(`${ExtensionPublisher}.${ExtensionName}/`)) {
            eventName = eventName.replace(`${ExtensionPublisher}.${ExtensionName}/`, "");
        }

        data.correlationId = AsyncLocalStorageUtil.getCorrelationId();

        TestingTelemetryReport.getInstance().sendTelemetryEvent(eventName, data);
    },
    sendErrorData(error, data:any) {

        data.correlationId = AsyncLocalStorageUtil.getCorrelationId();

        TestingTelemetryReport.getInstance().sendTelemetryErrorEvent("Error", data);
    }
});