import * as vscode from 'vscode';
import { Messages } from './strings';

export class Loader {
    private static quickPick: vscode.QuickPick<vscode.QuickPickItem> | null = null;

    public static show(message?: string) {
        if (!this.quickPick) {
            this.quickPick = vscode.window.createQuickPick();
            this.quickPick.placeholder = vscode.l10n.t((message ? `${message}` : Messages.Loading));
            this.quickPick.ignoreFocusOut = true;
            this.quickPick.show();
        }
    }

    public static hide() {
        if (this.quickPick) {
            this.quickPick.hide();
            this.quickPick.dispose();
            this.quickPick = null;
        }
    }
}