import { LoadTestInputArtifacts, LoadTestInputType, PostmanInputArtifacts, TestType } from "../../Services/AzureLoadTesting/model";
import { LoadTestUserInputHandler } from ".";
import * as vscode from 'vscode';
import { excludeFolders } from "../../constants";
import path from "path";
import { ErrorMessages, Messages } from "../../strings";
import { Logger } from "../../logger";
import { checkIfJSONIsAPostmanCollection, getMaskedString } from "../../util";
import fs from "fs";
import { ErrorUtil } from "../../Utils/errorUtil";

export class PostmanLoadTestInputHandler extends LoadTestUserInputHandler {
    
    constructor(testType: TestType) {
        super(LoadTestInputType.Postman, testType);
        this.logger = new Logger('PostmanLoadTestInputHandler');
    }

    async selectArtifact<T extends LoadTestInputArtifacts>(): Promise<T | null> {
        
       let selectedInputFile: string | null | undefined;
       
        const postmanCollections = await vscode.workspace.findFiles(`{**/*.json}`, excludeFolders, 10);
                 
        const quickPickItems = postmanCollections.map(file => ({
            label: path.basename(file.fsPath),
            description: path.resolve(file.fsPath),
            iconPath: new vscode.ThemeIcon("file"),
        }));
        
        this.logger.debug(`Found ${quickPickItems.length} files while searching for Postman files`);
        
        const selectedFile = await vscode.window.showQuickPick(
            [
                ...quickPickItems, 
                { label: vscode.l10n.t(Messages.Browse), description: "", iconPath: new vscode.ThemeIcon("folder") }
            ],
            { 
                placeHolder: vscode.l10n.t(Messages.SelectPostmanCollection), 
                ignoreFocusOut: true,
            }
        );
       
        if(selectedFile == undefined){
            ErrorUtil.showNoFileSelectedError();
            return null;
        }

        if (selectedFile?.label === vscode.l10n.t(Messages.Browse)) {
            selectedInputFile = await this.fileServiceHelper.browseFile(['json']);
        } 
        else {
            selectedInputFile = selectedFile?.description;
        }
    
        if (!selectedInputFile) {
            ErrorUtil.showRequiredInputFileError();
            return null;
        }
        
        let artifacts: PostmanInputArtifacts = {
            inputFilePath: selectedInputFile,
            inputFileContent : fs.readFileSync(selectedInputFile, 'utf-8'),
            selectedRequests : []
        }

        let isValidPostman = checkIfJSONIsAPostmanCollection(selectedInputFile);
        
        if(isValidPostman){

            this.logger.debug('Selected input file is a valid postman collection');
            const postmanContent = fs.readFileSync(selectedInputFile, 'utf-8');
            const postmanCollection = JSON.parse(postmanContent);
        
            // Extract folder names and root level request from postman request and show it in quick pick list

            let folders = postmanCollection.item;
            let folderNames : string[]= [];

            folders.forEach((folder:any) => {
                // if folder has items, then add (folder) with name 
                
                if(folder.item && folder.item.length > 0){
                    folder.item.forEach((item:any) => {
                        folderNames.push(folder.name + " - " + item.name);
                    });
                }else{
                    folderNames.push(folder.name);
                }
            });

            if(folderNames.length > 1){

                let selectedRequests = await vscode.window.showQuickPick(folderNames, {
                    placeHolder: vscode.l10n.t(Messages.SelectAPIRequestToGenerateLoadTest),
                    canPickMany : true,
                    ignoreFocusOut: true,
                });
                
                if(selectedRequests && selectedRequests.length > 10){
                    this.logger.error(ErrorMessages.MaxTenRequestCanBeSelected);
                    return null;
                }

                if(!selectedRequests || selectedRequests.length == 0){
                    this.logger.info(vscode.l10n.t(Messages.GeneratingLoadTestForALLAPIs))
                    selectedRequests = folderNames;
                }

                artifacts.selectedRequests = selectedRequests;

                if(artifacts.selectedRequests.length > 0){
                    artifacts.inputFileContent = this.filterPostmanCollection(artifacts.inputFileContent, selectedRequests);
                }
            }

            this.logger.debug(`No of Selected requests : ${artifacts.selectedRequests?.length}`);
        }
        else{
            this.logger.debug(`Invalid postman collection schema found in ${getMaskedString(path.basename(selectedInputFile))}`);
        }
        
        return artifacts as unknown as T;
    }

    filterPostmanCollection = (postmanCollection: any, selectedRequests: string[]) => {
        let filteredCollection = JSON.parse(postmanCollection);

        let folders = filteredCollection.item;

        let newCollection : {[key:string] : any} = {};

        folders.forEach((folder:any) => {
                        
            if(folder.item && folder.item.length > 0){
                folder.item.forEach((item:any) => {
                    if(selectedRequests.includes(folder.name + " - " + item.name)){
                        if(newCollection.item == undefined){
                            newCollection.item = [];
                        }
                        newCollection.item.push(item);
                    }
                });
            }else{
                if(selectedRequests.includes(folder.name)){
                    if(newCollection.item == undefined){
                        newCollection.item = [];
                    }
                    newCollection.item.push(folder);
                }                
            }
        });

        filteredCollection.item = newCollection.item;
        return JSON.stringify(filteredCollection);
    }
}