import * as vscode from 'vscode';
import { AbstractCommand } from '.';
import { ExtensionName, ExtensionPublisher, VSCodeCommand, OpenWalkThroughId } from '../constants';
import { executeWithCorrelation } from '../executeAysnc';
import { AsyncLocalStorageUtil } from '../Utils/localStorageUtil';


class OpenWalkThrough extends AbstractCommand {

    constructor() {
        super(VSCodeCommand.OPEN_WALKTHROUGH);
    }

    protected async execute(): Promise<void> {

        executeWithCorrelation(VSCodeCommand.WORKBENCH_OPEN_WALKTHROUGH, AsyncLocalStorageUtil.getCorrelationId(), `${ExtensionPublisher}.${ExtensionName}#${OpenWalkThroughId}`, false);
    }
};

export const openWalkthrough = vscode.commands.registerCommand(
    VSCodeCommand.OPEN_WALKTHROUGH,
    async () => {
        await new OpenWalkThrough().run();
    }
);