import * as fs from 'fs';
import * as path from 'path';
import * as vscode from 'vscode';
import { GenerateRequirementsUserPrompt, GeneratingEnvUserPrompt, GeneratingLoadTestScriptSystemPrompt, LoadTestGenerationSystemPrompt, LoadTestScriptGenerationPrompt } from "../../ChatParticipant/AzureLoadTesting/Prompts";
import { Logger } from "../../logger";
import { Messages } from "../../strings";
import { formatAiResponse, getMaskedString } from "../../util";
import { EditorUtil } from '../../Utils/editorUtil';
import { updateEnvFile, updateRequirementsFile } from '../../Utils/fileUtil';
import { CopilotService } from "../Copilot";
import { EnvAndSecrets, LoadTestUserInput, TestType } from './model';


export class TestScriptHelper {

    private logger = new Logger("TestScriptHelper");

    private _copilotService : CopilotService;

    constructor() {
        this._copilotService = new CopilotService();
    }

    async getRequiredEnvAndSecretVariables(testScript:string, copilotModel:string, loadTestType:TestType) {

        let requiredEnvAndSecrets : EnvAndSecrets = {
            envVariables: [],
            secrets: []
        };

        let resp = await this._copilotService.findEnvAndSecretsFromScript(fs.readFileSync(testScript, 'utf8'), copilotModel, loadTestType);

        if(resp){
            let data = resp.data;
            let string = formatAiResponse(data, '```json', '```');
            let variables : EnvAndSecrets | null = JSON.parse(string);
            if(variables){
                // Filter out empty env variables and secrets
                variables.envVariables = variables.envVariables.filter((env:any) => env.name !== "");
                variables.secrets = variables.secrets.filter((secret:string) => secret.trim() !== "");

                // if something is came as secrtes and env both then remove from env 
                variables.envVariables = variables.envVariables.filter((env:any) => !variables.secrets.includes(env.name));
                
                requiredEnvAndSecrets = variables;
            }
            
        }

        return requiredEnvAndSecrets;
    }

    async findAdditionalFiles(testScript:string, copilotModel:string) {
        let scriptContent = fs.readFileSync(testScript, 'utf8');
        this.logger.debug(`Finding additional files for script: ${getMaskedString(testScript)}`);
        
        let resp = await this._copilotService.findIfScriptNeedsAnyFiles(scriptContent, copilotModel);

        if(resp){
            let data = resp.data;

            let files  = formatAiResponse(data, '```files', '```');

            if(files != ""){
                try{
                    let fileArray : string[] = JSON.parse(files);
                    let additionalFiles = fileArray.map((line:string) => line.trim());
                    
                    // remove the file name if it is the same as the script name
                    let basename = path.basename(testScript);
                    
                    if(additionalFiles.includes(basename)){
                        additionalFiles = additionalFiles.filter(file => file != "" && file != basename);
                    }

                    // Remove empty strings
                    additionalFiles = additionalFiles.filter(file => file !== "");

                    return additionalFiles;
                }catch(e) {
                    this.logger.debug(`Error while parsing additional files: ${e}`);
                }

            }
        }

        return [];
    }

    async createScript(userInput: LoadTestUserInput, model:vscode.LanguageModelChat) : Promise<any> {

        let inputFileContent = userInput.artifacts!.inputFileContent;

        let system_prompt = LoadTestGenerationSystemPrompt;
        let user_prompt = LoadTestScriptGenerationPrompt(inputFileContent, userInput);

        const messages = [
            vscode.LanguageModelChatMessage.Assistant(system_prompt),
            vscode.LanguageModelChatMessage.User(user_prompt)
        ];
        
        this.logger.debug(`promt messages: ${JSON.stringify(messages)}`);
        
        let tokenUsages = await model.countTokens(messages[0]) + await model.countTokens(messages[1]);

        this.logger.debug(`The copilot model used is: ${model.id}, token usages: ${tokenUsages}, maxInputTokens: ${model.maxInputTokens}`);

        const chatResponse = await model.sendRequest(messages, {});

        let scriptContent = '';

        this.logger.debug(`Generating load test script for test type: ${userInput.testType}`);
        
        let contents = [];

        for await (const fragment of chatResponse.text) {
            scriptContent += fragment;
            contents.push(fragment);
        }

        let generatedScript = await EditorUtil.streamContentToEditorWithOverlay(contents, userInput.testType);  

        if(!generatedScript) {
            this.logger.debug(`Error while generating load test Script`);
            return null;
        }
        
        // check with copilot for env variable in script and stream the results 
        let fileContent = fs.readFileSync(generatedScript, 'utf8');

        const envMessages = [
            vscode.LanguageModelChatMessage.Assistant(GeneratingLoadTestScriptSystemPrompt),
            vscode.LanguageModelChatMessage.User(GeneratingEnvUserPrompt(fileContent, userInput.artifacts!.inputFileContent, userInput.testType))
        ];
        const envChatResponse = await model.sendRequest(envMessages, {}, new vscode.CancellationTokenSource().token);
        
        let envContent = '';
        
        for await (const fragment of envChatResponse.text) {
            envContent += fragment
        }

        const envFilePath = vscode.Uri.joinPath(vscode.workspace.workspaceFolders![0].uri, '.env').fsPath;
        envContent = formatAiResponse(envContent, '```bash', '```');

        // Parse new entries from envContent
        let newEntries : Record<string,string> = {};
        if(envContent != "" && envContent.split('\n').length > 0){
            envContent.split('\n').forEach(line => {
                if (!line.trim() || line.trim().startsWith('#')) return;
                const [key, ...rest] = line.split('=');
                if(key && rest){
                    newEntries[key.trim()] = rest.join('=').trim();
                }
            });
        }

        updateEnvFile(newEntries, envFilePath);

        let requirements : string[] = [];

        if(userInput.testType == TestType.Locust){
            // For Locust, we need to generate requirements.txt
            this.logger.debug(`Generating requirements.txt for Locust test type`);
            const requirementsMessages = [
                vscode.LanguageModelChatMessage.Assistant(GeneratingLoadTestScriptSystemPrompt),
                vscode.LanguageModelChatMessage.User(GenerateRequirementsUserPrompt(fileContent))
            ];

            const requirementsChatResponse = await model.sendRequest(requirementsMessages, {}, new vscode.CancellationTokenSource().token);

            let requirementsContent = '';

            for await (const fragment of requirementsChatResponse.text) {
                requirementsContent += fragment;
            }

            requirementsContent = formatAiResponse(requirementsContent, '```json', '```');


            if(requirementsContent != ""){
                try{
                    let packages = JSON.parse(requirementsContent);
                    packages = packages.filter((pkg:string) => pkg.trim() !== '');
                    requirements = packages.map((pkg:string) => pkg.trim());
                    if(requirements.length > 0){
                        updateRequirementsFile(requirements, vscode.Uri.joinPath(vscode.workspace.workspaceFolders![0].uri, 'requirements.txt').fsPath);
                        this.logger.debug(`Saved requirements.txt`);
                    }
                }catch(e){
                    this.logger.debug(`Error while parsing requirements.txt: ${e}`);
                }
            }
        }
        
        
        return {
            script: generatedScript,
            envContent: envContent,
            packages: requirements,
            additionalFiles: []
        };
    }


}