import * as fs from 'fs';
import * as yaml from 'js-yaml';
import * as vscode from 'vscode';
import { AzureLoadTestingService } from "../../../Services/AzureLoadTesting";
import { YAMLParser } from "../../../Services/AzureLoadTesting/yaml";
import { ErrorMessages, Messages } from "../../../strings";
import { ChatCommandHandler } from "../../handler";
import { VSCodeCommand } from '../../../constants';
import { ALTContext } from '../Context';

export class RunNowChatHandler extends ChatCommandHandler {

    async handle(request: vscode.ChatRequest, context: vscode.ChatContext, stream: vscode.ChatResponseStream, token: vscode.CancellationToken){
        
        if (!this.isWorkspaceOpen(stream)) {
            return false;
        }

        let fileToGenerate: string | undefined = ALTContext.getLoadTestConfig();

        let altService = new AzureLoadTestingService();
        if(!fileToGenerate){
            fileToGenerate = await this._fileService.selectLoadTestConfigFile();
            if (!fileToGenerate || fileToGenerate === "") {
                return false;
            }
        }


        if(!fileToGenerate.endsWith("yaml") && !fileToGenerate.endsWith("yml")){
            stream.markdown(vscode.l10n.t(ErrorMessages.SELECT_A_CONFIGURATION_FILE));
            return false;
        }

        const document = await vscode.workspace.openTextDocument(fileToGenerate);
        await vscode.window.showTextDocument(document);
        
        ALTContext.setLatestLoadTestConfigPath(fileToGenerate);

        let yamlParser = new YAMLParser();

        let file = fs.readFileSync(fileToGenerate, "utf-8");

        // check if yaml is a valid YAML file
        try {
            yaml.load(file);

            // TODO : can check more for a valid load test yaml file
        } catch (e) {
            stream.markdown(vscode.l10n.t(ErrorMessages.NOT_A_VALID_YAML));
            return false;
        }

        stream.markdown(vscode.l10n.t(Messages.RunninInALTNow));

        let resp = await yamlParser.parseYAML(fileToGenerate);

        if(resp && resp.loadTestConfig != null){
            // execute function in a new thread 
            (async () => {
                try {
                    await altService.startLoadTest(resp.loadTestConfig!, resp.options);
                } catch (error) {
                    this._logger.error(`Failed to start load test: ${error}`);
                }
            })();
            return true;
        }else{
            stream.markdown(vscode.l10n.t(ErrorMessages.INVALTD_YAML_FILE));
            return false;
        }
    }
}


