import * as fs from 'fs';
import { Logger } from '../logger';

let logger = new Logger("FileUtil");


export function updateEnvFile(newEntries:Record<string,string> | undefined, envFilePath: string): boolean {

    if(!newEntries || Object.keys(newEntries).length === 0) {
        logger.debug(`No new entries to update in .env file at ${envFilePath}`);
        return false;
    }

    try {
        // Read the existing .env file if it exists
        let existingContent = '';
        if (fs.existsSync(envFilePath)) {
            existingContent = fs.readFileSync(envFilePath, 'utf8');
        }

        const updatedLines: string[] = [];
        const envs = new Set<string>();

        // Split existing content and remove leading blank lines
        const existingLines = existingContent
                                .split('\n')
                                .map(line => line.trim())
                                .filter(line => line.length > 0);

        // check if the new entry already exists
        for (const line of existingLines) {
            const [key, value] = line.split('=');
            const trimmedKey = key.trim();
            const trimmedValue = value ? value.trim() : '';
            if (newEntries[trimmedKey] !== undefined) {
                // If the key already exists, update its value
                updatedLines.push(`${trimmedKey}=${trimmedValue}`);
                envs.add(trimmedKey);
            } else {
                // If the key doesn't exist in newEntries, keep the existing line
                updatedLines.push(line);
            }
        }
        // Add new entries that don't exist in the existing content

        for (const [key, value] of Object.entries(newEntries)) {
            const trimmedKey = key.trim();
            const trimmedValue = value ? value.trim() : '';
            if (!envs.has(trimmedKey)) {
                updatedLines.push(`${trimmedKey}=${trimmedValue}`);
            }
        }

        if(updatedLines.length === 0) {
            logger.debug(`No changes made to .env file at ${envFilePath}`);
            return false;
        }
        // Write the updated content back to the .env file
        const output = updatedLines.join('\n')
        fs.writeFileSync(envFilePath, output, 'utf8');
        logger.debug(`Updated .env file at ${envFilePath}`);

        return true;
    } catch (error) {
        if (error instanceof Error) {
            logger.debug(`Failed to update .env file: ${error.message}`);
        } else {
            logger.debug('Failed to update .env file: An unknown error occurred.');
        }
        return false;
    }
}

export function updateRequirementsFile(requirements: string[] | undefined, requirementsPath: string): boolean {

    if (!requirements || requirements.length === 0) {
        logger.debug(`No new requirements to update in requirements.txt file at ${requirementsPath}`);
        return false;
    }

    try {
        // Read the existing requirements.txt if it exists
        let existingContent = '';
        if (fs.existsSync(requirementsPath)) {
            existingContent = fs.readFileSync(requirementsPath, 'utf8');
        }

        let existingLines = existingContent
            .split('\n')
            .map(line => line.trim())
            .filter(line => line.length > 0)
            .filter(line => !line.startsWith('#'));

        // get packages name 
        let existingPackages = existingLines.map(line => {
            const [packageName] = line.split(/==|>=|<=/);
            return packageName.trim();
        });

        const linesToAppend: string[] = [];

        for (const line of requirements) {
            let packageName = line.split(/==|>=|<=/)[0].trim();
            if (!existingPackages.includes(packageName)) {
                linesToAppend.push(line);
            }
        }

        if (linesToAppend.length > 0) {
            if(existingContent && existingContent.length > 0 && !existingContent.endsWith('\n') && linesToAppend.length > 0) {
                // Add a blank line before appending new packages if the file is not empty
                existingContent = existingContent.trimEnd() + '\n';
            }
            const output =  existingContent + linesToAppend.join('\n')
            fs.writeFileSync(requirementsPath, output, 'utf8');
        }

        return true;
    } catch (error) {
        if (error instanceof Error) {
            console.error(`Failed to update requirements.txt: ${error.message}`);
        } else {
            console.error('Failed to update requirements.txt: An unknown error occurred.');
        }
        return false;
    }
}
