export const checkIfJSONIsAPostmanCollection = (filePath: any): boolean => {
    let fileContent = fs.readFileSync(filePath, 'utf8');

    // check schema should have postman
    try {
        
        // check for valid json file
        let postmanCollection = JSON.parse(fileContent);

        // check if it is a postman collection
        if(postmanCollection.info.schema && postmanCollection.info.schema.indexOf('postman.com') > -1){
            return true;
        }
    } catch (e) {
        return false;
    }
    return false;
}


export const getNextFileName = (directory: string, baseName: string, extension: string): string => {
    let fileName = `${baseName}.${extension}`;
    let counter = 1;

    while (fs.existsSync(path.join(directory, fileName))) {
        fileName = `${baseName}-${counter}.${extension}`;
        counter++;
    }

    return path.join(directory, fileName);
}


export function formatAiResponse(data: string | null, prefix: string, suffix: string): string {
    if (data == null) {
        return "";
    }

    // Dynamically build the regex to find the first code block based on prefix and suffix
    const regex = new RegExp(`${prefix}(.*?)${suffix}`, 's');
    const match = data.match(regex);
    if (!match) {
        return "";
    }

    const firstBlock = match[1].trim();

    return firstBlock || "";
}

export async function runLocustScript(locustFilePath:string) {
    let terminal = vscode.window.terminals.find(t => t.name === vscode.l10n.t(Messages.LoadTestTerminalName));
    if (terminal) {
        terminal.dispose();  // Close the terminal and terminate any running process
    }

    terminal = vscode.window.createTerminal(vscode.l10n.t(Messages.LoadTestTerminalName));
    terminal.show();

    terminal.sendText(`locust -f "${locustFilePath}" -u 10 -r 2 --run-time 1m`);

    // delay for 10 seconds 
    await new Promise(resolve => setTimeout(resolve, 10000));

    const locustDashboardUrl = 'http://localhost:8089';
    await vscode.env.openExternal(vscode.Uri.parse(locustDashboardUrl));
}

export function runJMeterScript(jmeterFilePath:string) {
    let terminal = vscode.window.terminals.find(t => t.name === vscode.l10n.t(Messages.LoadTestTerminalName));
    if (terminal) {
        terminal.dispose();  // Close the terminal and terminate any running process
    }
    terminal = vscode.window.createTerminal(vscode.l10n.t(Messages.LoadTestTerminalName));

    terminal.show();
    terminal.sendText(`jmeter -n -t "${jmeterFilePath}" -l "${path.join(path.dirname(jmeterFilePath), 'results.jtl')}"`);
}


export function validateLoadTestScript(fileName?:string) {

    // fileNmae should be defined and should be a python file with jmx in the name
    if (!fileName || (!fileName.endsWith('.py') && !fileName.includes('.jmx'))) {
        return false;
    }

    if (!fs.existsSync(fileName)) {
        return false;
    }

    return true;
}

export function formatStatusEnum(status: string): string {
    return status
        .toLowerCase()
        .split('_')
        .map(word => word.charAt(0).toUpperCase() + word.slice(1))
        .join(' ');
}

export const generateTestDisplayName = (): string => {
    const now = new Date();
    const date = now.toLocaleDateString('en-US', { year: 'numeric', month: '2-digit', day: '2-digit' });
    const time = now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    return `Test - ${date} ${time}`;
}

export const generateTestRunDisplayName = (): string => {
    const now = new Date();
    const date = now.toLocaleDateString('en-US', { year: 'numeric', month: '2-digit', day: '2-digit' });
    const time = now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    return `Test Run - ${date} ${time}`;
}

export const getTestType = (testScript:string) => {
    let fileName = path.basename(testScript);

    if(fileName.includes(".py")){
        return TestType.Locust;
    }else if(fileName.includes(".jmx")){
        return TestType.JMeter;
    }
    throw new Error("Test type not found");
}

export const getTestKind = (testScript:string) => {
    let fileName = path.basename(testScript);

    if(fileName.includes(".py")){
        return TestKind.Locust 
    }else if(fileName.includes(".jmx")){
        return TestKind.JMX;
    }
    throw new Error("Test type not found");
}

export function extractTestRunProperties(dataArray: any[]): TestRunProperty[] | null {
    try {
        if (!Array.isArray(dataArray)) {
            throw new Error("Invalid JSON: Expected an array");
        }

        return dataArray.map(data => ({
            testRunName: data.displayName || "",
            testId: data.testId || "",
            portalUrl: data.portalUrl || "",
            status: data.status || "",
            testRunId: data.testRunId || "",
        }));
    } catch (error) {
        console.error("Invalid JSON: ", error);
        return null;
    }
}

export function isValidTestScript(testScript?:string){
    return testScript && fs.existsSync(testScript);
}

export function extractLoadTestLocations(data: any): string[] {
    const resourceType = data.resourceTypes.find((type: any) => type.resourceType === 'loadtests');
    return resourceType ? resourceType.locations : [];
}

export function formatString(template: string, ...args: any[]): string {
    return template.replace(/{(\d+)}/g, (match, index) => {
        return typeof args[index] !== 'undefined' ? args[index] : match;
    });
}

export function isValidDomain(domain: string): boolean {
    const domainRegex = /^(https?:\/\/)?([a-zA-Z0-9-_]{1,63}\.)+[a-zA-Z]{2,}$/;
    return domainRegex.test(domain);
}

export function getMaskedString(str: string, maskChar: string = '*', visibleChars: number = 3): string {
    if (str.length <= visibleChars) {
        // If the string is shorter than or equal to the mask all characters, return it as is
        return maskChar.repeat(str.length);
    }

    // Mask the string, keeping every 3 characters visible from the start and end 
    // and masking the rest with the specified mask character
    // For example, "123456789" becomes "123******789"
    // For example, "123456789" becomes "123******789"

    const visibleStart = str.slice(0, visibleChars);
    const visibleEnd = str.slice(-visibleChars);
    const maskedMiddle = maskChar.repeat(str.length - visibleChars * 2);
    return `${visibleStart}${maskedMiddle}${visibleEnd}`;
}

export function isTerminalState(status: string): boolean {
    const terminalStates = [
        'COMPLETED',
        'FAILED',
        'CANCELLED',
        'STOPPED',
        'DONE'
    ];

    return terminalStates.includes(status);
}

export async function formatErrorMessage(resp: any) {
    try {
        const contentType = resp.headers.get("content-type");
        if (contentType && contentType.includes("application/json")) {
            let error = await resp.json();
            if(error && error.error && error.error.message){
                return `[${error.error.code??""}]${error.error.message}`;
            } 
        }
    } catch (e) {
    }
    return resp.statusText;
}