import { v4 as uuidv4 } from 'uuid';
import * as vscode from 'vscode';
import { ChatParticipant, Links, VSCodeCommand } from '../constants';
import { Logger } from '../logger';
import { TelemeryLogger } from '../telemetryLogger';
import { AsyncLocalStorageUtil } from '../Utils/localStorageUtil';
import { ALTContext } from './AzureLoadTesting/Context';
import { ChatCommandFollowup, ChatPromptFollowup } from './AzureLoadTesting/Followups';
import { DefaultALTChatHandler } from './AzureLoadTesting/Handlers/default';
import { GenerateLoadTestHandler } from './AzureLoadTesting/Handlers/generateloadtest';
import { RunLoadTestLocallyHandler } from './AzureLoadTesting/Handlers/runloadtestlocally';
import { RunNowChatHandler } from './AzureLoadTesting/Handlers/runnow';
import { SetupSecretsInAzureKeyVaultHandler } from './AzureLoadTesting/Handlers/setupakv';
import { SetupEnvFileHandler } from './AzureLoadTesting/Handlers/setupenv';
import { ValidationHandler } from './AzureLoadTesting/Handlers/validateconfig';
import { ChatCommandHandler } from './handler';
import { IChatResult } from './model';
import { GitHubService } from '../Services/GitHub';
import { UserState } from '../Services/AzureLoadTesting/model';
import { ErrorMessages, Messages } from '../strings';
let alt: vscode.ChatParticipant;

let logger = new Logger('ChatParticipant');
let githubService = new GitHubService();

export function registerMTSChatParticipant(context: vscode.ExtensionContext) {

    // Define a Azure Load Testing chat handler.
    const althandler: vscode.ChatRequestHandler = async (request: vscode.ChatRequest, context: vscode.ChatContext, stream: vscode.ChatResponseStream, token: vscode.CancellationToken): Promise<IChatResult> => {
        
        let correlationId = AsyncLocalStorageUtil.getCorrelationId() || uuidv4();
        // Get correlation id from the previous chat results metadata 
        let chatResults = context.history;

        if(chatResults && chatResults.length > 0){
            let lastResult : vscode.ChatResponseTurn | undefined = getLastChatResponse(context)
            
            if(lastResult && lastResult.result && lastResult.result.metadata && lastResult.result.metadata.correlationId){
                correlationId = lastResult.result.metadata.correlationId;
            }
        }

        let userState = await githubService.getUserState();
        
        if(userState < UserState.CopilotEnabled){
            let accountName = await githubService.getGitHubAccountName() || "";
            logger.debug(`User state ${userState}, copilot not enabled`);
            vscode.window.showWarningMessage(
                vscode.l10n.t(ErrorMessages.NoAccessToGitHubCopilot, accountName),
                vscode.l10n.t(ErrorMessages.SignUpForGitHubCopilot) // Button label
            )
            .then((selection) => {
                if (selection == vscode.l10n.t(ErrorMessages.SignUpForGitHubCopilot)) {
                    vscode.env.openExternal(vscode.Uri.parse(Links.EnableCopilotInGithub));
                }
            });
            return { metadata: { command: request.command ?? '', correlationId : correlationId } };
        }
        
        logger.debug(`Received chat request with correlationId: ${correlationId} and command ${request.command}`);

        let handler : ChatCommandHandler;

        if (request.command === ChatParticipant.GENERATE_LOAD_TEST_COMMAND){
            handler =  new GenerateLoadTestHandler(ChatParticipant.GENERATE_LOAD_TEST_COMMAND, new Logger('GenerateLoadTestHandler'));
        }
        else if (request.command === ChatParticipant.SETUP_ENV_FILE){
            handler = new SetupEnvFileHandler(ChatParticipant.SETUP_ENV_FILE, new Logger('SetupEnvFileHandler'));
        }
        else if (request.command === ChatParticipant.SETUP_SECRET_IN_AKV){
            handler = new SetupSecretsInAzureKeyVaultHandler(ChatParticipant.SETUP_SECRET_IN_AKV, new Logger('SetupSecretsInAzureKeyVaultHandler'));
        }
        else if (request.command === ChatParticipant.VALIDATION_COMMAND) {
            handler = new ValidationHandler(ChatParticipant.VALIDATION_COMMAND, new Logger('ValidationHandler'));
        }
        else if(request.prompt == ChatParticipant.ValidateLoadTestConfigPrompt){
            handler = new ValidationHandler(ChatParticipant.VALIDATION_COMMAND, new Logger('ValidationHandler'),{
                runInAzure : true
            });
        }else if(request.command == ChatParticipant.RUN_LOAD_TEST_IN_AZURE || request.prompt == ChatParticipant.RunInAzurePrompt){
            vscode.commands.executeCommand(VSCodeCommand.RUN_LOAD_TEST_IN_AZURE, ALTContext.getLoadTestConfig());
            return { metadata: { command: request.command ?? '', correlationId : correlationId } };
        }
        else if(request.command == ChatParticipant.RUN_LOAD_TEST_LOCALLY || request.prompt == ChatParticipant.RunLoadTestLocallyPrompt){
            handler = new RunLoadTestLocallyHandler(request.command ?? '', new Logger('RunLoadTestLocallyHandler'));
        }
        else if(request.prompt == ChatParticipant.StartLoadTestRunPrompt){
            logger.debug(`Received prompt to start load test run`);
            handler = new RunNowChatHandler('RunNow', new Logger('RunNowChatHandler'));
        }
        else {
            handler = new DefaultALTChatHandler('default', new Logger('DefaultALTChatHandler'));
        }
        
        if(!handler.getchatParticipant()){
            handler.setchatParticipant(alt);
        }
        
        return executeHandlerAsync(handler, request, context, stream, token, correlationId);
    };

    
    alt = vscode.chat.createChatParticipant(`${ChatParticipant.CHART_PARTICIPANT_ID}`, althandler);

    alt.iconPath = vscode.Uri.joinPath(context.extensionUri, 'media/alt.png');

    context.subscriptions.push(alt.onDidReceiveFeedback((feedback: vscode.ChatResultFeedback) => {
        
        TelemeryLogger.logUsage('chatResultFeedback', {
            kind: feedback.kind,
            feedback : feedback
        });
    }));
}


/**
 * Executing handle in async context with given correlation id and logging the command invocation
 * @param handler 
 * @param request 
 * @param context 
 * @param stream 
 * @param token 
 * @param correlationId 
 * @returns 
 */
const executeHandlerAsync = async(handler: ChatCommandHandler, request: vscode.ChatRequest, context: vscode.ChatContext, stream: vscode.ChatResponseStream, token: vscode.CancellationToken, correlationId:string) =>   {
    // Run within the asynchronous context carrying the correlation id
    return AsyncLocalStorageUtil.getLocalContext().run({ correlationId }, async () => {
        // Log the command invocation with the correlation id
        handler.logUsages();

        try{
            let success = await handler.handle(request, context, stream, token);
            if(handler.getShowFollowups()){
                if(success && request && request.command){
                    const followups = ChatCommandFollowup[request.command];
                    alt.followupProvider = {
                        provideFollowups(_result: IChatResult, _context: vscode.ChatContext, _token: vscode.CancellationToken): vscode.ProviderResult<vscode.ChatFollowup[]> {
                            return followups;
                        }
                    }; 
                }else if(request.prompt && ChatPromptFollowup[request.prompt]){
                    const followups = ChatPromptFollowup[request.prompt];
                    alt.followupProvider = {
                        provideFollowups(_result: IChatResult, _context: vscode.ChatContext, _token: vscode.CancellationToken): vscode.ProviderResult<vscode.ChatFollowup[]> {
                            return followups;
                        }
                    }; 
                }else{
                    alt.followupProvider = {
                        provideFollowups(_result: IChatResult, _context: vscode.ChatContext, _token: vscode.CancellationToken): vscode.ProviderResult<vscode.ChatFollowup[]> {
                            return [];
                        }
                    }; 
                }
            }else{
                alt.followupProvider = {
                    provideFollowups(_result: IChatResult, _context: vscode.ChatContext, _token: vscode.CancellationToken): vscode.ProviderResult<vscode.ChatFollowup[]> {
                        return [];
                    }
                };
            }
        }catch(err){
            handler.handleError(err, stream);
        }
        return { metadata: { command: request.command ?? '', correlationId : correlationId } };
    });
}

const getLastChatResponse = (context: vscode.ChatContext): vscode.ChatResponseTurn | undefined => {
    let chatResults = context.history;
    
    let chatResponses = chatResults.filter((result) => {
        return result instanceof vscode.ChatResponseTurn;
    });

    return chatResponses.length > 0 ? chatResponses[chatResponses.length - 1] as vscode.ChatResponseTurn : undefined;
}
