import { GitHubService } from '../Services/GitHub';
import { v4 as uuidv4 } from 'uuid';
import * as vscode from 'vscode';
import { Logger } from '../logger';
import { AzureLoadTestingService } from '../Services/AzureLoadTesting';
import { TelemeryLogger } from '../telemetryLogger';
import { openWorkspaceFolder } from '../Utils/commandUtil';
import { AsyncLocalStorageUtil } from '../Utils/localStorageUtil';

/**
 * Abstract logic for adding telemetry for hitting the command palette and adding correlation to the command execution
 */
export abstract class AbstractCommand {
    protected commandId: string;
    protected logger : Logger = new Logger("AbstractCommand");
    protected azureLoadTestService : AzureLoadTestingService;
    protected githubService : GitHubService;

    constructor(commandId: string) {
        this.commandId = commandId;
        this.azureLoadTestService = new AzureLoadTestingService();
        this.githubService = new GitHubService();
    }

    public async run(...args: any[]): Promise<any> {
        const correlationId = uuidv4();
        // Run within the asynchronous context carrying the correlation id
        return AsyncLocalStorageUtil.getLocalContext().run({ correlationId }, async () => {
            // Log the command invocation with the correlation id
            TelemeryLogger.logUsage('commandPaletteExecuted', { commandId: this.commandId });

            // Call the actual command logic implemented in subclass
            return this.execute(...args);
        });
    }

    protected abstract execute(...args: any[]): Promise<any> | any;

    isOpenWorkspaceFolder(): boolean {
        const workspaceFolders = vscode.workspace.workspaceFolders?.[0];
        if (workspaceFolders) {
            return true;
        } else {
            openWorkspaceFolder();
            return false;
        }
    }
}