import { RestAPI } from '../Services/AzureLoadTesting/api';
import { isTerminalState } from '../util';
import * as vscode from 'vscode';
import { IGetAzureLoadTestRunInsightsOptions } from './models';
import { Logger } from '../logger';
import { ErrorMessages, Messages } from '../strings';

export class GetAzureLoadTestRunInsights implements vscode.LanguageModelTool<IGetAzureLoadTestRunInsightsOptions> {
    
    private readonly _apiClient : RestAPI;
    private logger: Logger;
    constructor() {
        this._apiClient = new RestAPI();
        this.logger = new Logger('GetAzureLoadTestRunInsights');
    }

    async invoke(
        options: vscode.LanguageModelToolInvocationOptions<IGetAzureLoadTestRunInsightsOptions>,
        _token: vscode.CancellationToken
    ) {
        this.logger.debug(`GetAzureLoadTestRunInsights.invoke called`);
        const params = options.input;
        const resourceId = params.azure_load_testing_resourceId;
        const testRunId = params.test_run_id;
        if(resourceId && testRunId) {
            this.logger.debug(`Fetching insights for resource and test run: resourceId=${resourceId}, testRunId=${testRunId}`);
            let loadTestResource = await this._apiClient.getAzureResourceDetails(resourceId);
            this.logger.debug(`Found resource details for resourceId ${resourceId}`);
            if(loadTestResource == null){
                this.logger.debug(`Resource not found: ${resourceId}`);
                return new vscode.LanguageModelToolResult([new vscode.LanguageModelTextPart(ErrorMessages.AzureLoadTestingResourceNotFound.replace('{resourceId}', resourceId))]);
            }
            let dataPlaneURI = loadTestResource.properties.dataPlaneURI;
            let insights = await this._apiClient.getTestRunInsights(`https://${dataPlaneURI}`, testRunId);
            if(insights == null){
                this.logger.debug(`No insights found for test run: ${testRunId}`);
                return new vscode.LanguageModelToolResult([new vscode.LanguageModelTextPart(ErrorMessages.NoInsightsFoundForTestRun.replace('{testRunId}', testRunId))]);
            }
            if(insights.status != "Succeeded"){
                this.logger.debug(`Insights not ready: ${insights.status}`);
                return new vscode.LanguageModelToolResult([new vscode.LanguageModelTextPart(ErrorMessages.LoadTestInsightsNotReady)]);
            }
            let insightsText = JSON.stringify(insights.rows, null, 2);
            return new vscode.LanguageModelToolResult([
                new vscode.LanguageModelTextPart(
                    `${Messages.LoadTestRunInsights}\n\n ${insightsText}`
                ),
            ]);
        } else {
            this.logger.debug(`Missing resourceId or testRunId: resourceId=${resourceId}, testRunId=${testRunId}`);
            return new vscode.LanguageModelToolResult([new vscode.LanguageModelTextPart(ErrorMessages.AzureLoadTestingResourceIdAndTestRunIdRequired)]);
        }
    }
    async prepareInvocation(
        options: vscode.LanguageModelToolInvocationPrepareOptions<IGetAzureLoadTestRunInsightsOptions>,
        _token: vscode.CancellationToken
    ) {
        this.logger.debug(`GetAzureLoadTestRunInsights.prepareInvocation`);
        const confirmationMessages = {
            title: Messages.GetAzureLoadTestRunInsights,
            message: new vscode.MarkdownString(Messages.ContinueToGetInsights),
        };
        return {
            invocationMessage: Messages.FetchingAzureLoadTestRunInsights,
            confirmationMessages,
        };
    }
}